-- Poems batch 368
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ffc0fb49-933b-4ccd-b7ad-1959d47d69b4','近傳已有代者補之作詩見寄因次其韻','李光','宋','宋诗','song-poetry','','[]','清時民訟簡，尺素半偷閑。',48,'全唐诗/poet.song.82000.json','["清時民訟簡，尺素半偷閑。", "岐路将迎裏，人情喜怒間。", "舄鳬隨意遠，遼鶴自知還。", "小艇春洲晚，歸尋天姥山。"]'),
('ecb2aa9f-0f17-487a-9a72-9479eb99cb8c','馬上寄補之以急歸不果追前約爲恨','李光','宋','宋诗','song-poetry','','[]','歸鞍乘月夕，度嶺訪靈真。',48,'全唐诗/poet.song.82000.json','["歸鞍乘月夕，度嶺訪靈真。", "路轉山邀馬，溪回水趁人。", "春殘花院静，家近夢歸頻。", "回首追前約，猶如未了因。"]'),
('c05d0fb2-2dca-4280-9202-27e42fcb8c6b','贈高端禮','李光','宋','宋诗','song-poetry','','[]','炎暑勞相過，清言扇爲停。',48,'全唐诗/poet.song.82000.json','["炎暑勞相過，清言扇爲停。", "新吟捨瑟作，衰耳洗竽聼。", "諸老子猶接，正音今已零。", "君家高記室，句法是儀刑。"]'),
('ce6b22f8-2621-4bad-a4dc-f2befac1f074','同永嘉諸賢奠謁右丞許公少伊','李光','宋','宋诗','song-poetry','','[]','葱鬰佳城秘，回環宅兆深。',48,'全唐诗/poet.song.82000.json','["葱鬰佳城秘，回環宅兆深。", "懸崖森翠栢，踴地布黄金。", "天下方雲擾，斯人竟陸沈。", "塵侵徐孺榻，絃斷伯牙琴。"]'),
('3fd2f09d-3c50-41ef-9f80-c5148855883b','次韻師川見贈','李光','宋','宋诗','song-poetry','','[]','鈞樞歸雅望，邪志寢姦雄。',48,'全唐诗/poet.song.82000.json','["鈞樞歸雅望，邪志寢姦雄。", "鵰鶚清秋急，豺狼當路空。", "經綸思妙手，談辯想英風。", "未厭東山卧，沈機一局中。"]'),
('c0c7ef83-ac37-484d-bdcc-ce2e2efc441e','贈陳讜二首  其一','李光','宋','宋诗','song-poetry','','[]','識字嗟逢晚，安貧未易招。',48,'全唐诗/poet.song.82000.json','["識字嗟逢晚，安貧未易招。", "儒冠走江浙，詩笥带衢饒。", "學貴參先覺，才須驗後凋。", "諸賢書稳致，定不作洪喬。"]'),
('dfad47a1-18c6-44f8-89af-5bf14d6d35c6','贈陳讜二首  其二','李光','宋','宋诗','song-poetry','','[]','人物有興廢，山川無古今。',48,'全唐诗/poet.song.82000.json','["人物有興廢，山川無古今。", "匹夫空有志，四海孰知心。", "莫覩芝蘭室，如游薝蔔林。", "同行六七子，涕淚各沾襟。"]'),
('bb2b265a-517c-4253-adf3-7d3a664ac968','次韻賀子忱喜雨','李光','宋','宋诗','song-poetry','','[]','天眷周王德，功歸傅說霖。',48,'全唐诗/poet.song.82000.json','["天眷周王德，功歸傅說霖。", "少寛邊餉急，聊慰老農心。", "雷隱滄江轉，階喧玉漏沈。", "西山多爽氣，拄笏助清吟。"]'),
('7778d250-c5d1-426b-8dc1-8d5ceba47032','子忱告别忽改塗湖外迎護母夫人殯宫惻然念之作詩送行','李光','宋','宋诗','song-poetry','','[]','異縣傷孤殯，慈顔念倚閭。',48,'全唐诗/poet.song.82000.json','["異縣傷孤殯，慈顔念倚閭。", "舊阡無觸鹿，新薦有跳魚。", "舟楫踰江水，風霜迫歲除。", "歸來一大事，莫忘剡溪居。"]'),
('53457215-4fb8-4d5a-b7c2-9a159741a05c','德起侍講侍郎以親老丐外章累數十上上雖察其誠至眷待方隆卒不許其去五月九日有旨令歸覲且使迎奉以來一時士友莫不歆豔稱歎爲人臣子能使聖主敬愛貪戀如此誠千載之遇足以顯其父母揚名後世矣上虞李某作詩送行','李光','宋','宋诗','song-poetry','','[]','别浦征帆速，歸寧漢詔温。',48,'全唐诗/poet.song.82000.json','["别浦征帆速，歸寧漢詔温。", "青雲方得路，白髪笑迎門。", "欲報慈親意，難忘聖主恩。", "朝回奉温凊，忠孝兩能存。"]'),
('6264de8b-1f09-4c08-9047-c6a930e7c969','有懷念一兄三二弟','李光','宋','宋诗','song-poetry','','[]','晚墮容江側，蠻蜑且雜居。',48,'全唐诗/poet.song.82000.json','["晚墮容江側，蠻蜑且雜居。", "懷兄頻有夢，憶弟懶觀書。", "憂國心徒切，謀身計已疏。", "歸田儻有日，握手喜何如。"]'),
('62fd5356-5435-4bee-b1d2-4fdaa40b507e','城北江岸獨行成此詩居人皆竹籬茅屋無壁可題歸而書於此','李光','宋','宋诗','song-poetry','','[]','散策江村路，柴門欲訪誰。',48,'全唐诗/poet.song.82000.json','["散策江村路，柴門欲訪誰。", "榕根盤古岸，藤菜蔓疏籬。", "未辦遊春屐，閑尋敵手棋。", "天涯隨處好，莫作楚囚悲。"]'),
('23f753be-8309-4d0f-991d-9340012f3371','予始到瓊衆謂海南自來無大寒今歲臘月連日風雨殆不異北地因成小詩記之','李光','宋','宋诗','song-poetry','','[]','海國冬常燠，陰霾忽滿山。',48,'全唐诗/poet.song.82000.json','["海國冬常燠，陰霾忽滿山。", "颼颼北風勁，凛凛凍雲頑。", "蟋蟀已無語，芭蕉猶強顔。", "江頭梅柳色，春色幾時還。"]'),
('8c3ca184-905b-4a1a-be82-3bd1cadfa91a','丙寅十月二十二日孟堅理舊篋見純老送行詩有見及語因次其韻三首  其一','李光','宋','宋诗','song-poetry','','[]','南來償宿債，一笑悟前身。',48,'全唐诗/poet.song.82000.json','["南來償宿債，一笑悟前身。", "白首癡頑老，清朝放逐臣。", "休傳江左夢，愁見海南春。", "魯叟乘桴意，他年莫問津。"]'),
('34b017f0-3e66-4099-b042-f2ca77c16822','丙寅十月二十二日孟堅理舊篋見純老送行詩有見及語因次其韻三首  其二','李光','宋','宋诗','song-poetry','','[]','衣冠雙闕遠，煙瘴百蠻深。',48,'全唐诗/poet.song.82000.json','["衣冠雙闕遠，煙瘴百蠻深。", "不記朝天路，難忘拱極心。", "任從生死病，莫問去來今。", "身似孤雲遠，閑飛不作霖。"]'),
('b6394431-6679-4604-9978-0979ecc573e0','丙寅十月二十二日孟堅理舊篋見純老送行詩有見及語因次其韻三首  其三','李光','宋','宋诗','song-poetry','','[]','竄流今六載，無復望天朝。',48,'全唐诗/poet.song.82000.json','["竄流今六載，無復望天朝。", "象魏闕云遠，寶陀山匪遙。", "音書時有繼，風義未全凋。", "只有獼猴性，年來亦漸調。"]'),
('3f1c8e56-bcf6-4e6b-9c6e-0842049d5d52','八月十六夜江邊對月','李光','宋','宋诗','song-poetry','','[]','水月交相映，江空净客衣。',48,'全唐诗/poet.song.82000.json','["水月交相映，江空净客衣。", "孤光凌象緯，倒影射窗扉。", "宿鳥依林動，流螢逐暗飛。", "興來隨杖履，難下董生帷。"]'),
('3b4650e2-36f8-435a-88a7-1f6728d94440','連日以目疾不能躬課子侄輩枕上成四十言粗明汲古之意以勉之','李光','宋','宋诗','song-poetry','','[]','文史三冬足，窺尋究始終。',48,'全唐诗/poet.song.82000.json','["文史三冬足，窺尋究始終。", "夜窗捐末事，歲計見深功。", "古井家家有，靈泉處處通。", "隨身具修綆，取給自無窮。"]'),
('f14f1978-60fa-4b7f-bdab-1d0c6f0fca9a','近買扁舟篷棹悉具戲示諸兒','李光','宋','宋诗','song-poetry','','[]','此生雲水興，今日買扁舟。',72,'全唐诗/poet.song.82000.json','["此生雲水興，今日買扁舟。", "着岸從人繫，乘風逐處浮。", "山歌和漁子，净社結江鷗。", "夜泛寒潮稳，朝尋古寺幽。", "謝安空雅量，范蠡漫多謀。", "豈若吾無事，平湖盡日留。"]'),
('2b55beab-e2cf-4550-9100-0ca15f2cfcbd','瓊士黄與善會友堂課諸生作移竹詩爲賦一首','李光','宋','宋诗','song-poetry','','[]','綠竹名清友，書齋植最宜。',72,'全唐诗/poet.song.82000.json','["綠竹名清友，書齋植最宜。", "根深知舊壤，葉密带新枝。", "寒暑時須易，冰霜操不移。", "影寒金瑣碎，聲振玉參差。", "引鳳符周運，爲龍待葛陂。", "諸生頻掃徑，琴海每相隨。"]'),
('0ae58122-406a-42a9-8eda-e9dae8dab23c','泂酌亭詩','李光','宋','宋诗','song-poetry','','[]','投老幾三黜，郊居更一遷。',216,'全唐诗/poet.song.82000.json','["投老幾三黜，郊居更一遷。", "江山相映带，風物自清妍。", "妙墨移新榜，清詩失舊鐫。", "地偏無俗轍，境勝賴前賢。", "氣浹岡巒潤，榮滋草木鮮。", "雙泉今莫辨，異味豈虚傳。", "餘潤分畦圃，支流給市廛。", "幽嵌鏘玉佩，石罅湧璣璿。", "瀝漉聞朝汲，淙琤攪夜眠。", "甘寒通沆瀣，精潔秘蜿蜒。", "奔駛觀洄洑，泓渟有折旋。", "滂沱蘇旱歲，清冷變炎天。", "鴈過空遺影，僧來忽誤禪。", "澄瀾涵璧月，暗谷響朱弦。", "夢想千巖秀，徜徉一壑専。", "使君常倒載，别乘屢加籩。", "隔竹聞茶臼，臨池泛酒船。", "塵襟如可洗，來此弄潺湲。"]'),
('f280dd6a-94f0-43eb-a1ae-251b37fa7ce6','三月三日康守燕嚴亭','李光','宋','宋诗','song-poetry','','[]','禊飲城西路，山翁岸幅巾。',72,'全唐诗/poet.song.82000.json','["禊飲城西路，山翁岸幅巾。", "習池還倒載，曲水暗通津。", "鼓吹雄南國，旌旗照暮春。", "莫嫌娼妓拙，自有主人真。", "散策花迷逕，隨車雨洗塵。", "杖藜歸興晚，猶有浣紗人。"]'),
('69a26624-9c9d-462a-ae87-4c7671800520','吾里桃花之盛不减武陵獨東院一株色白而多葉跗蕚皆碧世謂之碧桃主僧回公折以相贈置几硯間蕭然有出塵之想因賦鄙句','李光','宋','宋诗','song-poetry','','[]','不作尋常好面皮，劉郎去後弄粧遲。',64,'全唐诗/poet.song.82000.json','["不作尋常好面皮，劉郎去後弄粧遲。", "喚回濃睡春方好，洗退殘紅晚更宜。", "薝蔔有香陪冷豔，酴醿無力鬬豐肌。", "最憐月下朦朧影，定起山僧莫皺眉。"]'),
('5c6813f4-3630-4242-b028-9f23f34df77c','總持師示近詩一軸輙次最後神字韻梅花一篇','李光','宋','宋诗','song-poetry','','[]','水邊難覩似梅人，且看垂垂一樹新。',64,'全唐诗/poet.song.82000.json','["水邊難覩似梅人，且看垂垂一樹新。", "獨許玉妃陪寂寞，可須青女助精神。", "傳杯冷艷愁聞笛，入戶幽香已報春。", "抽盡空花經月雨，此心那復住根塵。"]'),
('b9bf14fe-d796-4656-be9b-faf9f7938444','重午食大麥','李光','宋','宋诗','song-poetry','','[]','春來斗米欲逾千，麥熟家家爨有煙。',64,'全唐诗/poet.song.82000.json','["春來斗米欲逾千，麥熟家家爨有煙。", "手磨旋推雲子落，脚鐺深煎蚌胎員。", "香聞並舍兒童喜，效錄奇方胃海便。", "信是書生能說食，杜陵饑客漫流涎。"]'),
('8864bccc-183b-434b-8f85-c132208385ca','得之寓静齋斆學之暇不廢吟詠甚自得也因其歸省作詩送行','李光','宋','宋诗','song-poetry','','[]','數椽茅屋絕過從，窗戶深明一逕通。',64,'全唐诗/poet.song.82000.json','["數椽茅屋絕過從，窗戶深明一逕通。", "雨過竹叢增晚翠，風翻荷沼亂殷紅。", "揩磨五字無瑕纇，鼓吹羣經有折衷。", "斆學從來自強半，應憐時輩尚談空。"]'),
('4fd7efb2-2ee5-4643-bf62-b8d14d6d2b87','贈李振祖','李光','宋','宋诗','song-poetry','','[]','兒時思致早飄然，便合高鶱在少年。',64,'全唐诗/poet.song.82000.json','["兒時思致早飄然，便合高鶱在少年。", "下第令人感二鳥，上庠寄徑應三鱣。", "義方永訣詩無恙，手澤珍藏墨尚鮮。", "識取前修顯揚事，决科之外有流傳。"]'),
('ac863bcc-73af-4e3e-8b8d-64c3b84fc5bb','向丞廳舊有小軒榜曰日哦庳隘不爽近徹墻向南植竹數竿改曰分翠與僚友邑之賢彦日遊其間且索鄙句因賦二詩呈諸友  其一','李光','宋','宋诗','song-poetry','','[]','旋植修篁一逕深，蕭然便可滌塵襟。',64,'全唐诗/poet.song.82000.json','["旋植修篁一逕深，蕭然便可滌塵襟。", "碧移湘浦千梢净，清借淇園十畝陰。", "曉檻秋聲風撼玉，空庭寒影月篩金。", "造門賴有山陰客，酒熟時來伴醉吟。"]'),
('1dc30f06-1e04-4828-844c-9b26fff997c9','向丞廳舊有小軒榜曰日哦庳隘不爽近徹墻向南植竹數竿改曰分翠與僚友邑之賢彦日遊其間且索鄙句因賦二詩呈諸友  其二','李光','宋','宋诗','song-poetry','','[]','先生活計未全貧，一徑篔簹碧玉新。',64,'全唐诗/poet.song.82000.json','["先生活計未全貧，一徑篔簹碧玉新。", "野趣近依陶令宅，幽姿深隔庾公塵。", "獨餘世外冰霜操，不逐人間草木春。", "吏隱何妨成小築，風流重見竹林人。"]'),
('65c13f37-295e-4be8-a1d0-07f210ee914b','題向丞竹軒','李光','宋','宋诗','song-poetry','','[]','琅玕新植覺深幽，頓使軒窗一夜秋。',64,'全唐诗/poet.song.82000.json','["琅玕新植覺深幽，頓使軒窗一夜秋。", "寒影静侵書幌冷，翠陰清逐桂花浮。", "蕙蘭終許依霜操，桃李從教媚冶遊。", "公子已多林下趣，更看仙吏落銀鈎。"]'),
('329a422d-64eb-494b-90e9-b7c33913dd3b','詩悼德輿通判寺丞','李光','宋','宋诗','song-poetry','','[]','扁舟訪我海邊村，笑語俄驚隔九原。',64,'全唐诗/poet.song.82000.json','["扁舟訪我海邊村，笑語俄驚隔九原。", "蕭寺新題雲有態，故鄉清譽玉無痕。", "傷心姹女能傳業，銜痛慈親尚倚門。", "紖紼情乖臨穴送，一尊聊酹若敖魂。"]'),
('9cdb1b4c-9258-4fac-ab7f-2d94811cda2b','題藏春軒','李光','宋','宋诗','song-poetry','','[]','何必金丹訪洞賓，壺中日月自長春。',64,'全唐诗/poet.song.82000.json','["何必金丹訪洞賓，壺中日月自長春。", "直疑簾幕遮藏得，未怕鶯花漏洩頻。", "摩詰神通移不去，桃園風景畫難真。", "尊罍賸把笙歌擁，沉醉何妨墊角巾。"]'),
('1455c49c-2463-4888-a77d-04b61a9ec7e0','送知府提舉出守虢略','李光','宋','宋诗','song-poetry','','[]','繡斧當年舊使星，却分符竹往専城。',64,'全唐诗/poet.song.82000.json','["繡斧當年舊使星，却分符竹往専城。", "流風遠繼三堂詠，扶路爭看五馬迎。", "不獨循良追漢吏，便應清切振家聲。", "都門祖帳人多羡，嫋嫋春風動斾旌。"]'),
('a8670147-fa81-4acc-bb0f-1351c83ad67d','次韻叔興計議端午發家書感懷之詩','李光','宋','宋诗','song-poetry','','[]','細葛香羅罷賜衣，十年風雨暗蝸廬。',64,'全唐诗/poet.song.82000.json','["細葛香羅罷賜衣，十年風雨暗蝸廬。", "浴蘭紉佩憐兒女，懸艾題符徇井閭。", "地勝斗墟饒賦詠，日長蓮幕少文書。", "欲憑尺素傳深意，千里慇懃附鴈魚。"]'),
('34397dc0-8e67-4b06-9f5d-bf1f3417d023','贈趙璚夫','李光','宋','宋诗','song-poetry','','[]','世間兒子總紛紛，屬籍吾賢最不羣。',64,'全唐诗/poet.song.82000.json','["世間兒子總紛紛，屬籍吾賢最不羣。", "天在山中須畜學，風行水上自成文。", "操存有約要真見，記問夸多只謏聞。", "我與東巖情分腆，臨分書此勉郎君。"]'),
('4ed77dc4-2617-45ef-9de1-e73fa042959b','游破山通幽軒用前人韻呈同行諸友','李光','宋','宋诗','song-poetry','','[]','小軒佳致信通幽，爽氣侵人挾九秋。',64,'全唐诗/poet.song.82000.json','["小軒佳致信通幽，爽氣侵人挾九秋。", "暇日不妨尋舊隱，清時無用借前籌。", "能詩誰復追常建，愛竹吾今似子猷。", "已有琴書隨杖履，更邀閑客伴清游。"]'),
('e870488f-e149-40cf-895f-8a4e6cc90b8b','題無俗亭','李光','宋','宋诗','song-poetry','','[]','一榻蕭然岸幅巾，寒梅爲友竹爲鄰。',64,'全唐诗/poet.song.82000.json','["一榻蕭然岸幅巾，寒梅爲友竹爲鄰。", "清譚謝傅風流勝，倒載山翁氣味真。", "獨把琴棋消永日，未須歌管送餘春。", "簿書堆案應頻掃，不學陶潛避俗塵。"]'),
('ead3f444-a1ee-481f-8f50-60e56f03f145','人日立春呈元成進道二兄二首  其一','李光','宋','宋诗','song-poetry','','[]','人日春風動琯灰，新年佳節併相催。',64,'全唐诗/poet.song.82000.json','["人日春風動琯灰，新年佳節併相催。", "金花巧向釵頭見，和氣潛隨斗柄回。", "青入池塘頻夢草，暖生官閣易尋梅。", "相從便好攜爐銚，乳面新來勝撇醅。"]'),
('0c80717a-3996-43e3-ad89-4fccc7fa0f05','人日立春呈元成進道二兄二首  其二','李光','宋','宋诗','song-poetry','','[]','新詩如律起寒灰，多謝鄒郎着意催。',64,'全唐诗/poet.song.82000.json','["新詩如律起寒灰，多謝鄒郎着意催。", "清比金莖天上落，句生春草夢中回。", "才高可但空吟雪，心鐵猶能強賦梅。", "山月欲圓人又好，羡君同潑甕頭醅。"]'),
('cd4ce458-b0ae-4fdf-b7cf-0ed54f688d5c','校文毗陵經由見寄','李光','宋','宋诗','song-poetry','','[]','牽衣兒女最相關，節物催人歲欲闌。',64,'全唐诗/poet.song.82000.json','["牽衣兒女最相關，節物催人歲欲闌。", "船落草聲驚夢斷，水涵山影照杯殘。", "堂深空羡河陽集，被冷誰憐范叔寒。", "坐想歸途花正好，杜鵑聲裏破愁顔。"]'),
('d8d2c69b-8add-4488-b0a5-d3d7c1e0b7be','度黄陂嶺','李光','宋','宋诗','song-poetry','','[]','肩輿渺渺歷崎嶇，自笑謀身老更迂。',64,'全唐诗/poet.song.82000.json','["肩輿渺渺歷崎嶇，自笑謀身老更迂。", "獻策但知憂社稷，投荒那敢顧妻孥。", "南行已度黄陂嶺，北去何愁青草湖。", "冒雨穿雲信奇絕，玆遊真豈是良圖。"]'),
('2bb77be6-765d-4639-b2d4-60f7c79b2a8d','次郊行韻','李光','宋','宋诗','song-poetry','','[]','森森巨麓蔽秋岡，薄日籠陰一味凉。',64,'全唐诗/poet.song.82000.json','["森森巨麓蔽秋岡，薄日籠陰一味凉。", "散策繞溪閑覓伴，幅巾對客坐焚香。", "午潮暗長看平岸，野竹纔添便出墻。", "巖壑自無南北異，不妨隨處得相羊。"]'),
('68ccf6c3-04e8-4f70-ba09-08203512a78e','某近復得女補之有詩次韻爲謝','李光','宋','宋诗','song-poetry','','[]','荆棘林中蛇虺驚，懸知不作鳳雛鳴。',64,'全唐诗/poet.song.82000.json','["荆棘林中蛇虺驚，懸知不作鳳雛鳴。", "維熊已誤傳佳夢，得女猶能繼頌聲。", "貧賤預求梁氏壻，才情敢擅謝娘名。", "囊中幸自全無物，更覺新來分外清。"]'),
('84f8abb4-557a-486a-96a9-abffb75eb991','和胡德暉增明軒詩','李光','宋','宋诗','song-poetry','','[]','窗間列岫鬰嵳峨，一寸遙岑已是多。',64,'全唐诗/poet.song.82000.json','["窗間列岫鬰嵳峨，一寸遙岑已是多。", "跨海空青疊寒玉，浮天濃綠豔修蛾。", "漫傳五嶽歸圖畫，坐想千巖見詠歌。", "從此閉門閑覓句，直将世事付依阿。"]'),
('62005926-d813-4c89-bf77-c22824978ec6','次韻補之續思越吟','李光','宋','宋诗','song-poetry','','[]','俗軌紛紛正背馳，鑑中白髪愧明時。',64,'全唐诗/poet.song.82000.json','["俗軌紛紛正背馳，鑑中白髪愧明時。", "致身何必營三窟，入仕聊同庇一枝。", "故里有懷松菊老，聖朝無用計謀奇。", "相從喜有忘形侣，杖屨山樊酒滿巵。"]'),
('d801e5ba-9c66-41b3-b20c-dd325da5887d','奉和補之至日書懷','李光','宋','宋诗','song-poetry','','[]','薄宦伶俜祗自傷，捧巵無復獻華堂。',64,'全唐诗/poet.song.82000.json','["薄宦伶俜祗自傷，捧巵無復獻華堂。", "暗驚老去蒼顔在，誰道陰鋪白晝長。", "天際雲煙成五色，堯階鴛鷺列千行。", "懸知凍筆孤吟罷，徙倚南窗揖翠浪。"]'),
('93c709de-4e05-49b0-9605-ee192ee63820','次韻七夕','李光','宋','宋诗','song-poetry','','[]','犢鼻長挑竹杖頭，未能免俗想清流。',64,'全唐诗/poet.song.82000.json','["犢鼻長挑竹杖頭，未能免俗想清流。", "西來誰遣青禽至，仙去還乘白鶴遊。", "天上歡娱纔瞬息，人間恩愛漫綢繆。", "穿針乞巧真兒戲，曝腹庭中更可羞。"]'),
('bbdb5747-5c6e-41fb-88ed-9081b9c507af','又德循補之寵示七夕酬唱聊發狂言以當一笑','李光','宋','宋诗','song-poetry','','[]','好事多應與願違，經年消息却如期。',64,'全唐诗/poet.song.82000.json','["好事多應與願違，經年消息却如期。", "匆匆舊約重尋處，耿耿銀河欲渡時。", "綽約肌膚雲路遠，低迷簾幕玉鈎垂。", "夜凉風露非塵世，天外彎彎墮月眉。"]'),
('c3d9d920-eb61-473c-a9d4-3d0e4c371250','補之以鍊養之說勉德循眷眷之意并見二詩若懼其不我從者以待德循可也他人能無誚乎因次韻奉寄  其一','李光','宋','宋诗','song-poetry','','[]','漫道壺中别有春，枉教衆楚笑齊人。',64,'全唐诗/poet.song.82000.json','["漫道壺中别有春，枉教衆楚笑齊人。", "本來妙說元無說，信是靈真未識真。", "佩劍攜書如可繼，殺雞炊黍不妨頻。", "相逢且說無生話，若問長生有大鈞。"]'),
('9f45346e-05a4-4703-8516-69b1adaa303b','補之以鍊養之說勉德循眷眷之意并見二詩若懼其不我從者以待德循可也他人能無誚乎因次韻奉寄  其二','李光','宋','宋诗','song-poetry','','[]','不用休糧學隱淪，眼前無事即仙人。',64,'全唐诗/poet.song.82000.json','["不用休糧學隱淪，眼前無事即仙人。", "解官終作陶元亮，晦迹聊同鄭子真。", "交友盡緣酬唱密，關山豈碍往來頻。", "流行坎止平生志，壽夭還如泥在鈞。"]'),
('57d408c2-383f-492c-b3c4-4f2fe83ee05d','客醉而亟歸不慮畏塗之可戒當爲罪首丞令不行與吏慢丞命其罪均也以爲不然則縣令先入又何逃焉因次韻戲答德循且誚深山道人眷眷炬火非胥靡登危而不慄者遂并以寄之','李光','宋','宋诗','song-poetry','','[]','肩輿歸去未全醒，倚戶何人念遠征。',64,'全唐诗/poet.song.82000.json','["肩輿歸去未全醒，倚戶何人念遠征。", "事在赦前皆可罪，過因酒後各原情。", "壺中未便乘風去，夜半何妨秘息行。", "不向險中求不死，却因何處覓長生。"]'),
('29dc3b0e-b91d-4e6f-86b9-1c7cce3e2053','次韻補之瑤堂瑞蓮','李光','宋','宋诗','song-poetry','','[]','映水雙開带晚烟，丹葩浥露鬬鮮妍。',64,'全唐诗/poet.song.82000.json','["映水雙開带晚烟，丹葩浥露鬬鮮妍。", "瑤堂地産金蓮瑞，蒿里人歸玉府仙。", "並立江臯珠珮冷，相親漢苑曉粧偏。", "舜庭敷奏無虚日，潛德并遺柱史傳。"]'),
('6867cfaf-f6ed-48ba-a053-035ea5ff31a2','和睡起飲茶','李光','宋','宋诗','song-poetry','','[]','虚堂清簟午抛簪，人静疏簾映晝閽。',64,'全唐诗/poet.song.82000.json','["虚堂清簟午抛簪，人静疏簾映晝閽。", "身過中年心已倦，病因煩暑氣常昏。", "紫煙碧月天初賜，乳竇寒泉世莫論。", "塵味暫忘惟嗜此，更無餘思到芳樽。"]'),
('28e01202-3081-407e-a56d-16d8417e1214','贈高申','李光','宋','宋诗','song-poetry','','[]','夜半匆匆離府庠，那知造物相槐忙。',64,'全唐诗/poet.song.82000.json','["夜半匆匆離府庠，那知造物相槐忙。", "直言賈禍飜成福，正論驚人竟擅場。", "庚戌掄魁卿有技，甲辰近榜士流芳。", "勉旃學問全名節，富貴儻來如探囊。"]'),
('d14cbb91-f615-476c-8302-943cdbdb25b5','送韋子駿赴中書舍人召','李光','宋','宋诗','song-poetry','','[]','桃李成蹊竹逕幽，幾年依隱玩林丘。',64,'全唐诗/poet.song.82000.json','["桃李成蹊竹逕幽，幾年依隱玩林丘。", "日邊紫詔頻催入，郭外青山故挽留。", "河右始知天子聖，淮南應寢叛臣謀。", "絲綸世掌真餘事，濟難徐觀用巨舟。"]'),
('348ab21d-26ed-4319-8047-f08ea20f5fcf','賊退雙溪樓遣興','李光','宋','宋诗','song-poetry','','[]','朝來喜見妖氛静，坐覺山川勝氣還。',64,'全唐诗/poet.song.82000.json','["朝來喜見妖氛静，坐覺山川勝氣還。", "關塞罷征車馬健，郊原得雨老龍閑。", "黄綿慣擁茅簷日，白髪羞陪玉筍班。", "好在故園兵火後，那無破屋兩三間。"]'),
('54308f01-b648-4d65-a07a-843b77c25c75','八月晦日游東山彦約有詩次韻爲謝二首  其一','李光','宋','宋诗','song-poetry','','[]','永夜全莖下九天，郊坰風物正凄然。',64,'全唐诗/poet.song.82000.json','["永夜全莖下九天，郊坰風物正凄然。", "百年寶地空蕭瑟，十里青山水接連。", "局上笑談棋易勝，坐中奇險句難聯。", "定回老演應相問，浄社何時到白蓮。"]'),
('29773a8c-b94d-47a7-b5cb-650a3e846e48','八月晦日游東山彦約有詩次韻爲謝二首  其二','李光','宋','宋诗','song-poetry','','[]','燕坐僧窗爇水沈，暫時塵務不關心。',64,'全唐诗/poet.song.82000.json','["燕坐僧窗爇水沈，暫時塵務不關心。", "殿堂突兀諸天擁，花木扶疏曲徑深。", "節近重陽堪把翫，景如圖畫費摹臨。", "秋晴急趁黄花約，短日凄風易作霖。"]'),
('62033e31-d8ef-45c9-a46c-34e4f87ea0f1','辛亥中春遂宫祠之請自漁浦轉山入離渚宿化城以歸道中成鄙句','李光','宋','宋诗','song-poetry','','[]','誰倩冰霜一掃空，旋烘和氣轉春風。',64,'全唐诗/poet.song.82000.json','["誰倩冰霜一掃空，旋烘和氣轉春風。", "野田溢水層層落，山路催花樹樹紅。", "門巷旋教開竹逕，姓名初喜掛琳宫。", "江湖乍脱風波地，莫擬扁舟伴釣翁。"]'),
('4ffe18fb-f7b3-49b7-b301-e787a7c32a29','獨宿有懷','李光','宋','宋诗','song-poetry','','[]','危亭搔首撥寒灰，夜久無人共一杯。',64,'全唐诗/poet.song.82000.json','["危亭搔首撥寒灰，夜久無人共一杯。", "濕翠沾雲溪外竹，暗香浮月壠頭梅。", "烏啼日落孤村晚，被冷燈青夜夢回。", "還許對床尋舊約，肩輿應爲我重來。"]'),
('c5c1be5a-cf39-40af-9011-d32c465edfee','次韻幕僚喜雨詩卷','李光','宋','宋诗','song-poetry','','[]','皇天欲遣雨催詩，潤澤焦枯自應期。',64,'全唐诗/poet.song.82000.json','["皇天欲遣雨催詩，潤澤焦枯自應期。", "江上半犂如有繼，田家一飽豈無時。", "漢軍乏食徴方急，商后精祈事敢遺。", "嘉穀蒿莱俱茂遂，故應沛澤稱平施。"]'),
('586bb836-c09a-45de-8fb4-994e9efdf227','題塵外堂','李光','宋','宋诗','song-poetry','','[]','故園重到豁塵襟，桃李成蹊竹塢深。',64,'全唐诗/poet.song.82000.json','["故園重到豁塵襟，桃李成蹊竹塢深。", "三徑頻來無俗客，五更喚起有鳴禽。", "溪光山影常遮眼，酒醆茶甌獨掛心。", "塵外莫言無一事，苔痕掃盡復相侵。"]'),
('5c089594-5970-4000-bd1a-d50715e2657b','歸五松有作呈陳志尹諸兄','李光','宋','宋诗','song-poetry','','[]','幾年辛苦厭兵間，多謝君恩肯放還。',64,'全唐诗/poet.song.82000.json','["幾年辛苦厭兵間，多謝君恩肯放還。", "故里蕭騷松竹在，流年荏苒鬢毛斑。", "愁多不分青春過，睡足聊欣白晝閑。", "况有弟兄同保社，年年攜酒共澆山。"]'),
('1d09c8c9-6822-4a78-a3b6-0a122fe4cf91','復用前韻簡志尹','李光','宋','宋诗','song-poetry','','[]','已謀湖上屋三間，身退聊同倦鳥還。',64,'全唐诗/poet.song.82000.json','["已謀湖上屋三間，身退聊同倦鳥還。", "老去最便青篛笠，夢回空想紫宸班。", "招邀山月當軒醉，結約江鷗作伴閑。", "賴有淵明能賦詠，悠然把酒對南山。"]'),
('22161253-fbcc-4f65-8aaa-3d63d0cb86ce','和孚先兄安貧樂道以書史自娱嘉歎成詠','李光','宋','宋诗','song-poetry','','[]','青山繞屋水侵籬，拙計何妨與世違。',64,'全唐诗/poet.song.82000.json','["青山繞屋水侵籬，拙計何妨與世違。", "窗有殘燈供夜讀，瓶無儲粟補朝饑。", "日長門巷荆枝合，歲暮風霜塞鴈歸。", "白首重來耆舊盡，餘年從此永相依。"]'),
('be078c78-310f-4958-8d9f-e8458eadc039','次韻孚先兄寵示汲古佳章','李光','宋','宋诗','song-poetry','','[]','甕牖蓬牎守素風，弟兄來往一生中。',64,'全唐诗/poet.song.82000.json','["甕牖蓬牎守素風，弟兄來往一生中。", "祇憑六籍爲修綆，豈有雙梁架綵虹。", "朝市山林非有異，衆生心佛本來同。", "誰知白首維摩老，萬事都将袖被蒙。"]'),
('759b364f-62df-420c-9243-f528d32ed806','今歲遇元夕于五松連日大雪巷陌蕭然孚先兄有詩詫燈火之盛因成四韻','李光','宋','宋诗','song-poetry','','[]','里巷蕭條戶半扃，更無冷月掛山城。',64,'全唐诗/poet.song.82000.json','["里巷蕭條戶半扃，更無冷月掛山城。", "熒熒小市唯漁火，耿耿幽窗但雪聲。", "海國此時瞻氣象，端門何日覩升平。", "會須一掃陰霾盡，盡放冰輪徹夜明。"]'),
('c5bb5bc0-5bb2-4197-b6d9-edd8bd4c3122','孚先兄以連雨形于詠歌是時適聞韓侯淮北之捷因次韻','李光','宋','宋诗','song-poetry','','[]','頽垣敗屋未須悲，淮北于今暗鐵衣。',64,'全唐诗/poet.song.82000.json','["頽垣敗屋未須悲，淮北于今暗鐵衣。", "背水漢營朝氣鋭，青岡敵騎夜聲微。", "蕭條里巷徴符急，浩渺江湖羽檄稀。", "不及戎行親矢石，獨将詩禮繼庭闈。"]'),
('5fb419bf-3b70-4526-8a45-4c9abb4c99ff','伏覩親征榜又聞韓侯過江北是皆可喜然小臣區區亦有不勝憂者輙次韻成鄙句呈子駿侍郎','李光','宋','宋诗','song-poetry','','[]','親征一紙詔書頒，頓覺中原氣象還。',64,'全唐诗/poet.song.82000.json','["親征一紙詔書頒，頓覺中原氣象還。", "漫說風沙臨瀚海，遙憐草木舊淮山。", "百年社稷傾危後，一擲乾坤勝負間。", "北望鑾輿心共折，小臣無路得追攀。"]'),
('cb1ab91d-b08a-4a33-abf8-d4b2bd98ae54','和孚先兄久雨','李光','宋','宋诗','song-poetry','','[]','未容春色到園林，寂寞鶯花困久陰。',64,'全唐诗/poet.song.82000.json','["未容春色到園林，寂寞鶯花困久陰。", "積潦壞墻低易補，曉寒侵被破難禁。", "門閑賸欲償詩債，裘敝猶堪當酒金。", "昨夜東風掃羣翳，放迴天地發生心。"]'),
('93ae192d-c7c3-48d1-a81b-084a9a30bacd','甲寅仲秋水漲獨民先兄元發弟徙居招提日有登覽棋酒之勝連日雨復大作水且洊至舉室幾于濕浸仰二公之曠達歎輜重之爲累輙成鄙句以寄并呈志尹宣教表兄洎往來諸友兄一笑','李光','宋','宋诗','song-poetry','','[]','活計從來祗旋營，急難方悟此生輕。',64,'全唐诗/poet.song.82000.json','["活計從來祗旋營，急難方悟此生輕。", "資身但有書盈腹，潤屋不将金滿籯。", "塵榻曉寒資酒力，空堦夜雨雜棋聲。", "茗甌時赴湯休約，肯念人間雨與晴。"]'),
('4da79882-3f72-4e29-8679-ec71ecf5e5ec','喜晴','李光','宋','宋诗','song-poetry','','[]','西風一夜卷層波，并落人聲喜氣多。',64,'全唐诗/poet.song.82000.json','["西風一夜卷層波，并落人聲喜氣多。", "巨浸漲天吞夢澤，空庭積水湛星河。", "光搖萬瓦疑浮動，翠颭羣山巧琢磨。", "從此江湖更清曠，肯将軒冕換漁蓑。"]'),
('01d0df44-ad04-4f86-83b5-a90e5025316c','賦長慶寺白桃花','李光','宋','宋诗','song-poetry','','[]','似與江梅欲抗衡，空庭初見數枝横。',64,'全唐诗/poet.song.82000.json','["似與江梅欲抗衡，空庭初見數枝横。", "素肌臨水瓊琚冷，落葉沾苔絮雪輕。", "玉體生來清自韻，冰魂别後夢難成。", "故應天遣娱春晚，一洗人間紫與頳。"]'),
('cbc558a3-525f-49b3-a4cc-0ab9c2789a67','三月十一日獨寓經閣民先元發商叟見過縱步長廊因至旼師房愛其潔雅攜棋瀹茗竟日而歸因成鄙句','李光','宋','宋诗','song-poetry','','[]','長廊散步尋僧話，青眼相邀得老旼。',64,'全唐诗/poet.song.82000.json','["長廊散步尋僧話，青眼相邀得老旼。", "久禮懴堂心獨苦，慣迎野客語尤真。", "當軒翠竹根根静，對手拈棋局局新。", "日暮循隄還舊隱，一杯那復較醨醇。"]'),
('1b9357b0-c9a6-4ab4-99f4-1bdbb32f60a6','晚晴','李光','宋','宋诗','song-poetry','','[]','宿雲解駮遠峰青，谷鳥驚呼報午晴。',64,'全唐诗/poet.song.82000.json','["宿雲解駮遠峰青，谷鳥驚呼報午晴。", "屋冷籬疏茅店迥，路平沙軟筍輿輕。", "行窮坡嶺山方好，捲盡旌旗眼更明。", "慷慨未須關世務，胸懷得酒暫能平。"]'),
('4e3879f9-9029-42d2-aebf-778e43c24237','贈池元堅  其一','李光','宋','宋诗','song-poetry','','[]','去國曾聞首扣閽，今聆議論汗漿飜。',64,'全唐诗/poet.song.82000.json','["去國曾聞首扣閽，今聆議論汗漿飜。", "忠忱我愧西都向，行誼君賢太學蕃。", "壁水門開趨輦路，黄封囊奏乞神幡。", "英風義概幾成俗，涵養都由聖主恩。"]'),
('bf4c649b-b215-4fbe-abea-5d844360e1f9','贈池元堅  其二','李光','宋','宋诗','song-poetry','','[]','常丞若問老庸齋，屋借湖光一鏡開。',64,'全唐诗/poet.song.82000.json','["常丞若問老庸齋，屋借湖光一鏡開。", "執卷多應鵠袍至，載醪無復繡衣來。", "漁樵賸喜皆予伍，鷗鷺相忘不我猜。", "翰長鄰居清健甚，時時賡唱亦奇哉。"]'),
('27dfe242-823b-4747-bc09-4f7278c9fa40','孤坐有懷','李光','宋','宋诗','song-poetry','','[]','燭底黄花伴獨醒，小窗寒月半櫳明。',64,'全唐诗/poet.song.82000.json','["燭底黄花伴獨醒，小窗寒月半櫳明。", "滿添宿火留香霧，重理殘杯漬落英。", "老驥自能尋舊櫪，偏師暫喜解長城。", "獨餘惠遠秋蓮社，懷抱時時得再傾。"]'),
('f1bc6d0a-f2af-455b-bd34-9472c76ff638','蘧庵道人寄和重九感懷詩五章語皆超勝意兼釋老輙次其韻','李光','宋','宋诗','song-poetry','','[]','百歲光陰日半斜，因緣已透更何嗟。',64,'全唐诗/poet.song.82000.json','["百歲光陰日半斜，因緣已透更何嗟。", "飽參禪窟傳心印，一見桃溪悟落花。", "了得頓門方自在，修持徑路斷無差。", "世人學道徒勤苦，終日蒸炊只是沙。"]'),
('ff2a4521-84f2-4059-bc0a-504be3eb0023','次曾敦史會秀野詩韻  其一','李光','宋','宋诗','song-poetry','','[]','握手相逢醉别筵，興酣真是飲中仙。',64,'全唐诗/poet.song.82000.json','["握手相逢醉别筵，興酣真是飲中仙。", "一枰聊欲觀成敗，三盞何勞辨聖賢。", "老去不傳巫峽夢，夜來頻嚥玉池泉。", "鑑湖自昔多清賞，結約芒鞋上釣船。"]'),
('e2189d04-6f94-4db9-b376-19349e9d56fa','次曾敦史會秀野詩韻  其二','李光','宋','宋诗','song-poetry','','[]','閑地逢君懷抱開，攜壺選勝得同來。',64,'全唐诗/poet.song.82000.json','["閑地逢君懷抱開，攜壺選勝得同來。", "青山滿眼空排闥，紅袖何人爲舉杯。", "四面軒窗供眺望，一時簪履許参陪。", "黄昏渺渺溪橋路，燈火微明恨獨回。"]'),
('6b38c613-5dca-4d48-af88-0179e048b1ca','厲安行結小庵湖山之間破竹激水甚自適杜得之作詩因次其韻','李光','宋','宋诗','song-poetry','','[]','不慕軒裳慕隱淪，直將富貴比浮雲。',64,'全唐诗/poet.song.82000.json','["不慕軒裳慕隱淪，直將富貴比浮雲。", "竹溝引水通銀漢，石甃澄瀾起縠紋。", "湖上三間容我卜，溪邊一派與君分。", "枕流潄石平生事，黜陟從今了不聞。"]'),
('c8b69514-530f-45e7-bf6b-b54e711ca9fe','比見客談東福昌之勝若可避世恨未能一遊偶杜某出諸公宿雲庵詩軸戲題其後','李光','宋','宋诗','song-poetry','','[]','聞道招提枕半岡，結茅真在白雲鄉。',64,'全唐诗/poet.song.82000.json','["聞道招提枕半岡，結茅真在白雲鄉。", "嵐光滴瀝衣裳冷，爽氣空濛枕簟凉。", "幻滅不傳神女夢，心清時到贊公房。", "是身直與雲相似，肯與衆生出岫忙。"]'),
('b4821860-b69d-42cd-9d1a-ac11c93c133e','不出示鄰士','李光','宋','宋诗','song-poetry','','[]','小窗秋半日暉暉，蠧簡陳編漸可窺。',64,'全唐诗/poet.song.82000.json','["小窗秋半日暉暉，蠧簡陳編漸可窺。", "晨起已空摩詰室，晚凉深下董生帷。", "參差紅影蕉臨水，散漫寒香菊遶籬。", "從此杖藜休引步，習池花草任離披。"]'),
('9f9cf61c-5ae4-4b10-8a56-37628353f81e','與得之手談約不勝者賦詩探題得題厲吉老所居得之當作予和之云','李光','宋','宋诗','song-poetry','','[]','聞道全家避亂離，數間茅屋畏人知。',64,'全唐诗/poet.song.82000.json','["聞道全家避亂離，數間茅屋畏人知。", "閑尋倦鳥安巢處，静看孤雲出岫時。", "甕釀濁醪緣好客，棋翻妙著待贏詩。", "從來谷口稱真隱，應笑通衢賣卜醫。"]'),
('bbb362b2-11fe-47cb-ad7c-a459f53b61e3','陳氏園亭','李光','宋','宋诗','song-poetry','','[]','花逕微通竹逕幽，暮年清賞在林丘。',64,'全唐诗/poet.song.82000.json','["花逕微通竹逕幽，暮年清賞在林丘。", "登臨未覺三山隔，俯仰常隨萬壑流。", "樂土自應多樂事，閑身居此得閑遊。", "酒杯棋局平生事，莫把枯腸數攪搜。"]'),
('397c8f7d-b7e2-4837-a75a-cf64b6de86b0','遊智林寺','李光','宋','宋诗','song-poetry','','[]','扁舟來訪小叢林，花木通幽院落深。',64,'全唐诗/poet.song.82000.json','["扁舟來訪小叢林，花木通幽院落深。", "旋拂胡床成午夢，閑持貝葉動秋吟。", "竹聲瑟瑟生虚籟，山意峨峨入素琴。", "更喜老綱能會事，手携鑪銚自相尋。"]'),
('a915252d-a79f-4cd6-8bf0-2ad0830c29a0','獨宿報恩寺次韻','李光','宋','宋诗','song-poetry','','[]','竹枝桐葉滿秋霜，愁倚欄干望草堂。',64,'全唐诗/poet.song.82000.json','["竹枝桐葉滿秋霜，愁倚欄干望草堂。", "過澗歇時芳草渡，遶池遊處芰荷香。", "應思佳客傷情遠，欲訴衷情促拍忙。", "好是山亭宴僚友，夜深紅燭映天長。"]'),
('683ea7f6-ada7-4d41-939c-eab0e0c95d03','幹譽舍人将赴召前一日錄示左丞公昔年見寄佳什輙用韻奉送  其一','李光','宋','宋诗','song-poetry','','[]','不用移文託北山，須公一出濟時艱。',64,'全唐诗/poet.song.82000.json','["不用移文託北山，須公一出濟時艱。", "飛鳬自欲朝天闕，老驥終思入帝閑。", "直使姦諛俱落膽，要令凋瘵變驩顔。", "中興事業須耆傑，炯炯何妨兩鬢斑。"]'),
('aec052a8-4a94-455a-9828-ee0a9b3eb538','幹譽舍人将赴召前一日錄示左丞公昔年見寄佳什輙用韻奉送  其二','李光','宋','宋诗','song-poetry','','[]','陰崖結屋全家隱，世路風波任險艱。',64,'全唐诗/poet.song.82000.json','["陰崖結屋全家隱，世路風波任險艱。", "白首嗟予三黜慣，青山羡子十年閑。", "時危莫忘頻攀檻，主聖何妨數犯顔。", "賈誼歸來定前席，金鑾玉簡綴清班。"]'),
('486d7b27-a3d9-4b6d-9ca8-7440ccdb93cb','世綵堂','李光','宋','宋诗','song-poetry','','[]','耕桑不擾罷開邊，家國安榮二百年。',64,'全唐诗/poet.song.82000.json','["耕桑不擾罷開邊，家國安榮二百年。", "三世綵衣疑有種，一門忠孝豈無傳。", "遭時自致公卿貴，積慶多因父祖賢。", "鶴骨松標長照世，不須圖畫上凌烟。"]'),
('0f3b949d-8a8d-42d6-b484-172048f5c26f','送張子猷給亊帥福唐','李光','宋','宋诗','song-poetry','','[]','五馬東來隘里閭，旌旗照海奉安輿。',64,'全唐诗/poet.song.82000.json','["五馬東來隘里閭，旌旗照海奉安輿。", "時危未暇寛徭役，歲歉無勞進羡餘。", "赤子弄兵先解散，烏衣侮法費驅除。", "兵戈滿眼瞻王室，郵傳時時附諌書。"]'),
('a2778f1b-74ee-4c29-8c42-028571d16744','十二月二十五日詩悼傅子駿給事','李光','宋','宋诗','song-poetry','','[]','歸尋北海橋邊路，慟哭斯人但故廬。',64,'全唐诗/poet.song.82000.json','["歸尋北海橋邊路，慟哭斯人但故廬。", "三徑空存陶令菊，萬籖難見鄴侯書。", "丹青寫照空留影，慷慨論文孰起予。", "歎息平生英妙氣，只今寂寞契真如。"]'),
('9aca7c30-59a3-446e-b31a-39e4af33fb52','悼陸公彦常右司','李光','宋','宋诗','song-poetry','','[]','藴藉風流絕世稀，妙年詞賦邁雲機。',64,'全唐诗/poet.song.82000.json','["藴藉風流絕世稀，妙年詞賦邁雲機。", "漢庭留滯馮唐老，越國雍容賀監歸。", "方喜鏘金翔禁闥，忽驚埋玉掩泉扉。", "傷心里巷從游地，獨對秋風淚濕衣。"]'),
('c60ef21e-d2c9-40c8-ae31-d05c5a398720','送廖用中侍郎知漳州','李光','宋','宋诗','song-poetry','','[]','羡君忠孝兩無虧，出處雍容自造微。',64,'全唐诗/poet.song.82000.json','["羡君忠孝兩無虧，出處雍容自造微。", "供帳都門疏受去，懷章郡邸買臣歸。", "君恩已荷全家飽，治績行看百姓肥。", "回首文昌舊游地，相從漸覺故人稀。"]'),
('1bbddcd8-372e-4797-8a2e-19259e30a99d','自天姥入石橋路雖險絕而氣象殊勝殆非人境予将遙禮方廣諸尊者偶成鄙句','李光','宋','宋诗','song-poetry','','[]','曉入天台訪石梁，縈紆嶺路遶羊腸。',64,'全唐诗/poet.song.82000.json','["曉入天台訪石梁，縈紆嶺路遶羊腸。", "溪田溢水層層落，巖壑經秋步步凉。", "花乳散甌爭供茗，瑞光騰彩競拈香。", "心知未是真消息，方丈蓬壺共渺茫。"]'),
('454ca663-5fee-47ca-8dda-1a12b61323e7','亨仲察判赴召以重陽日酌酒夢草堂賦詩送行','李光','宋','宋诗','song-poetry','','[]','夢草池邊一笑同，冥冥雲迹羡飛鴻。',64,'全唐诗/poet.song.82000.json','["夢草池邊一笑同，冥冥雲迹羡飛鴻。", "青山不屬紅蓮客，黄菊羞簪白髪翁。", "直使淮南叛謀寝，未妨冀北馬羣空。", "中興事業須公等，勿憚危言達聖聰。"]'),
('966f1662-3ad8-4924-a7d6-36602533de4d','遠蒙宫使密學侍郎寵示和章謹再用韻寄呈','李光','宋','宋诗','song-poetry','','[]','疇昔心親迹異同，端如社燕與秋鴻。',64,'全唐诗/poet.song.82000.json','["疇昔心親迹異同，端如社燕與秋鴻。", "關河此日歸真主，巖壑他年屬兩翁。", "老去熟知交友態，憂來頓悟世緣空。", "傳聞敵騎謀深入，好爲提兵勦勒聰。"]'),
('42d45b66-0c47-4015-b47d-d6bdb7d92555','和戴禹功游水雲館','李光','宋','宋诗','song-poetry','','[]','舉目江山有異同，笑談尊俎恨匆匆。',64,'全唐诗/poet.song.82000.json','["舉目江山有異同，笑談尊俎恨匆匆。", "雲烟杳靄長淮隔，花木扶疏曲逕通。", "閑伴鳬鷗浮野水，未隨鷹隼擊秋空。", "會當雪後尋君去，不學子猷清興終。"]'),
('9a4c93b3-2236-4fa8-86b9-fc90d32dbf73','送禹功還錫山','李光','宋','宋诗','song-poetry','','[]','羽書烽火迫防秋，努力聊寛聖主憂。',64,'全唐诗/poet.song.82000.json','["羽書烽火迫防秋，努力聊寛聖主憂。", "契闊友生多散落，急難兄弟自相求。", "歸歟便可追吴隱，相對安能效楚囚。", "從此音塵渺江海，相思時上庾公樓。"]'),
('c39379a2-f035-4809-932e-aeeb12eb57c0','九日會南樓坐客十有二人以人世難逢開口笑菊花須插滿頭歸分韻得歸字','李光','宋','宋诗','song-poetry','','[]','不用攜壺上翠微，南樓風景古云稀。',64,'全唐诗/poet.song.82000.json','["不用攜壺上翠微，南樓風景古云稀。", "寧辭坐上吹烏帽，應笑籬邊候白衣。", "舉目佳山傷客意，滿園叢菊待人歸。", "分題未盡賓僚數，更看紋楸小合圍。"]'),
('95ea935a-28db-4fed-a9a6-8cf2beff5cd6','次韻子忱郎中九日南樓宴集','李光','宋','宋诗','song-poetry','','[]','登樓把酒面孱顔，富貴功名了不關。',64,'全唐诗/poet.song.82000.json','["登樓把酒面孱顔，富貴功名了不關。", "千古池臺悲帝子，一時賓幕陋龍山。", "影沈寒水鴈聲斷，香抱秋花蝶意閑。", "八郡往來聊自哂，孤雲出岫尚知還。"]'),
('dce926bb-82e5-479e-a9bb-f7ea122fa06f','達明宫使右丞寵寄新詩輙次韻爲謝二首  其一','李光','宋','宋诗','song-poetry','','[]','吏役無因棹酒船，一杯蕭寺破茶煙。',64,'全唐诗/poet.song.82000.json','["吏役無因棹酒船，一杯蕭寺破茶煙。", "文章雅健追前輩，交舊凋零感暮年。", "聞道巖廊勤注想，豈容琳館久回旋。", "好風吹寄凌雲句，無數珠璣堕我前。"]'),
('8dd98653-6b9b-470b-b3b8-3202a7e47021','達明宫使右丞寵寄新詩輙次韻爲謝二首  其二','李光','宋','宋诗','song-poetry','','[]','衰白相逢贛水邊，十年存沒竟誰賢。',64,'全唐诗/poet.song.82000.json','["衰白相逢贛水邊，十年存沒竟誰賢。", "别來舊隱荒三徑，醉後高談驚四筵。", "晚節功名君未免，半生憂患我堪憐。", "秋風久負蓴鱸約，歸夢時時到剡川。"]'),
('c4cec757-a1db-4733-9ecf-5599b22a6c19','宫使少卿作喜雨詩予輙續貂然連日烝鬰雨意殊未解霅川地瀕太湖畏雨而喜旱亦有足憂者輙再和賀子忱韻并呈少卿公一笑','李光','宋','宋诗','song-poetry','','["\u592a\u6e56"]','老鈍安能濟中興，知君此意每推誠。',64,'全唐诗/poet.song.82000.json','["老鈍安能濟中興，知君此意每推誠。", "邦人雖喜天心格，農夫預憂禾耳生。", "秋後竹陰侵簟冷，夢回蛩響雜堦聲。", "雨溪自昔傳佳詠，雲水相依夜自明。"]'),
('106d71df-fbc7-4037-babc-526a9ae1993c','次韻劉仲臯少卿喜雨','李光','宋','宋诗','song-poetry','','[]','漢詔寛慈下玉京，人心天意格精誠。',64,'全唐诗/poet.song.82000.json','["漢詔寛慈下玉京，人心天意格精誠。", "初欣父老扶攜聽，忽看風雲洶湧生。", "千里沾濡隨渥澤，萬家愁嘆變歡聲。", "南樓夜色晴方好，與子賡歌待月明。"]'),
('868e99dd-a3a7-4fd3-bef6-bf542708a4ab','富陽道中懷劉希顔兼得道任書寄二公','李光','宋','宋诗','song-poetry','','[]','渺渺平蕪雪正晴，旋驅征騎出郊坰。',64,'全唐诗/poet.song.82000.json','["渺渺平蕪雪正晴，旋驅征騎出郊坰。", "越山似我頭全白，江柳如君眼欲青。", "有信梅花傳驛使，忘機鷗鳥戀沙汀。", "洞霄結約香燈社，便欲相從老翠屏。"]'),
('6f80a74c-91ab-4a5b-af69-b827f9081d0a','余丈中大自虔還鄱陽弭節豫章南浦亭下相從累日議論慨然志節彌勵感歎不足成鄙句送行','李光','宋','宋诗','song-poetry','','[]','抗志潛心六籍中，文章直欲擬軻雄。',64,'全唐诗/poet.song.82000.json','["抗志潛心六籍中，文章直欲擬軻雄。", "誰云前輩風流盡，尚有斯人氣味同。", "南浦送行傷碧草，北窗歸卧享清風。", "君王寤寐思黄髪，會見蒲輪徴此翁。"]'),
('793b38da-fb58-48f5-9e70-63dadd3d6318','予得罪南遷朝廷樞密院凖備差遣張君送伴凡八十日予嘉其勤於其行也作詩送之  其一','李光','宋','宋诗','song-poetry','','[]','日日孤村對落暉，瘴烟深處忍分離。',64,'全唐诗/poet.song.82000.json','["日日孤村對落暉，瘴烟深處忍分離。", "追攀重見蔡明遠，贖罪難逢郭子儀。", "南渡可憂鳶共堕，北轅應喜鴈相随。", "馬蹄慣踏關山路，他日重來更送誰。"]'),
('da6e24df-bbca-44f6-94d4-3df3b346506e','予得罪南遷朝廷樞密院凖備差遣張君送伴凡八十日予嘉其勤於其行也作詩送之  其二','李光','宋','宋诗','song-poetry','','[]','瘦筇羸馬一貂裘，江浙湖湘得縱遊。',64,'全唐诗/poet.song.82000.json','["瘦筇羸馬一貂裘，江浙湖湘得縱遊。", "萬里遠勞君伴送，隔年應笑我淹留。", "默祈衡嶽雲開嶺，夜入浯溪月滿舟。", "北闕舊交如問訊，爲言白盡老人頭。"]'),
('42eb566a-8a19-452e-a5f8-9bfbf4009590','分水鋪步月','李光','宋','宋诗','song-poetry','','[]','人随烏鵲正南飛，月到中天列宿稀。',64,'全唐诗/poet.song.82000.json','["人随烏鵲正南飛，月到中天列宿稀。", "遠近江巒明霽色，横斜烟霧助清輝。", "危亭搔首風傳笛，迥野微行露濕衣。", "兒女未須頻悵望，春來應與鴈同歸。"]'),
('99c07b11-8fe6-4a06-855b-4a8be8fcf46b','余將卜居水東先以詩寄吳令','李光','宋','宋诗','song-poetry','','[]','茅齋背郭面孱顔，已有幽人約往還。',64,'全唐诗/poet.song.82000.json','["茅齋背郭面孱顔，已有幽人約往還。", "學道遠尋岣嶁令，卜居長占荔支灣。", "窗間山色紅塵遠，竹外棋聲白晝閑。", "静掃風軒同宴坐，柴扉應爲夜留關。"]'),
('21ada082-dcfc-4d41-a8fc-51bcc28ac33d','簽判黄元功頃攝守蔚平枕江有小亭予假居久之稍加葺治且作詩其上名之曰横江今既還職輒用寫呈','李光','宋','宋诗','song-poetry','','[]','西來一水護山城，突兀横江占小亭。',64,'全唐诗/poet.song.82000.json','["西來一水護山城，突兀横江占小亭。", "春盡浪花浮竹屋，夜深漁火亂沙汀。", "支頤塵榻清無夢，隱几明窗醉有經。", "掃灑待君還舊隱，却來相對守黄庭。"]'),
('a8a7da49-abb7-4d29-801c-30794e8b4bbc','寄內','李光','宋','宋诗','song-poetry','','[]','學道參禪久不成，惟將麴糵破愁城。',64,'全唐诗/poet.song.82000.json','["學道參禪久不成，惟將麴糵破愁城。", "三杯徑醉客已去，一枕未回天欲明。", "長羡籬邊元亮醉，誰憐澤畔屈原醒。", "甕頭濁酒須多釀，凖擬歸來細細傾。"]'),
('ab0f0b14-714e-4825-9bc7-553dd4773867','遷城南新居','李光','宋','宋诗','song-poetry','','[]','背郭通幽面翠微，病軀野性最相宜。',64,'全唐诗/poet.song.82000.json','["背郭通幽面翠微，病軀野性最相宜。", "旋栽花竹頻開逕，恐礙雲山短著籬。", "曉日臨窗時讀易，晚涼隔屋聽評棋。", "三年瘴嶺無歸日，聊向深林占一枝。"]'),
('2ba9bf8a-47ad-446b-bcd8-6f35fd3ee87c','次前韻','李光','宋','宋诗','song-poetry','','[]','甕牖茅簷白版扉，地偏猶與病相宜。',64,'全唐诗/poet.song.82000.json','["甕牖茅簷白版扉，地偏猶與病相宜。", "雨添山澗苔侵徑，竹近陽陂筍過籬。", "三爵沉酣陶令酒，一奩成敗謝公棋。", "車塵不到門前路，漸覺蒿萊長舊枝。"]'),
('c9c6ae8b-395c-49c9-a139-16acae476447','申之移竹數十竿植之後圃增賁幽人之居作詩爲謝','李光','宋','宋诗','song-poetry','','[]','節概平生慕此君，晚年流落偶相親。',64,'全唐诗/poet.song.82000.json','["節概平生慕此君，晚年流落偶相親。", "裝添小圃林泉勝，隔盡權門車馬塵。", "雨浥寒梢香掩冉，月歸疏影夜精神。", "他年亭下清陰滿，誰記當時種蒔人。"]'),
('c48a5fa0-8328-4b28-ac9a-f2c9c9268b32','再蒙自然使君寵和竹詩率爾爲謝','李光','宋','宋诗','song-poetry','','[]','畫手休誇最逼真，東牆月影畫難親。',64,'全唐诗/poet.song.82000.json','["畫手休誇最逼真，東牆月影畫難親。", "常陪翠柏凌寒景，幾見夭桃委路塵。", "鳴鳳引雛來應瑞，籜龍得雨便能神。", "雙泉異日增幽勝，開盞時時中聖人。"]'),
('c984a468-bc29-4940-9c0d-c7f06ed667b4','自然使君連賦竹詩輒復次韻','李光','宋','宋诗','song-poetry','','[]','閑客攜觴日對君，歲寒相與獨心親。',64,'全唐诗/poet.song.82000.json','["閑客攜觴日對君，歲寒相與獨心親。", "栽培野外千竿碧，抖擻胸中萬斛塵。", "月影臨窗如見畫，風輪長笋不無神。", "使君好事頻吟賞，蕭灑襟懷似晉人。"]'),
('d575bee3-71e6-49f4-af58-2fbf7f80f833','瓊臺','李光','宋','宋诗','song-poetry','','[]','玉臺孤聳出塵寰，碧瓦朱甍縹緲間。',64,'全唐诗/poet.song.82000.json','["玉臺孤聳出塵寰，碧瓦朱甍縹緲間。", "爽氣遙通天際月，滄波不隔海中山。", "潮平賈客連檣至，日晚耕牛带犢還。", "安得此身生羽翼，便乘風馭叩天關。"]'),
('f9c6547e-6264-47b2-b41c-4c554ca68f76','庭植家瓊山水北小園頗幽勝予頃寓雙泉每食罷招鄰士杖策訪之園有小亭常與客對奕因名坐隱今歲亭側輒生雙竹庭植二子皆卓然有立豈造物者産此以瑞其家庭乎作長句贈之','李光','宋','宋诗','song-poetry','','[]','桃笙澀勒漫成林，並立林亭一徑深。',64,'全唐诗/poet.song.82000.json','["桃笙澀勒漫成林，並立林亭一徑深。", "月下競看雙鳳影，風來時聽二龍吟。", "冰霜不改夷齊操，富貴無忘魯衞心。", "寄語園人頻愛護，等閑莫遣斧斤侵。"]'),
('53056e75-0443-473a-a4ea-3d3a874b6e02','用孟博寄孟堅韻','李光','宋','宋诗','song-poetry','','[]','汝到家時解我憂，歸來何處遇中秋。',64,'全唐诗/poet.song.82000.json','["汝到家時解我憂，歸來何處遇中秋。", "夢遊滄海休回首，路入浯灘穩泛舟。", "屋裏琴書無汝愛，宅邊松菊爲吾留。", "朋遊若問南方事，莫說瓊州勝越州。"]'),
('ae19eefa-c6a0-422e-95eb-d1c121a6f371','丙寅元日偶出見桃李已離披海南風土之異不無感歎獨追維三伏中荔支之勝又江浙所不及也因并見于詩','李光','宋','宋诗','song-poetry','','[]','逐客新年偶歎嗟，海南風物異中華。',64,'全唐诗/poet.song.82000.json','["逐客新年偶歎嗟，海南風物異中華。", "溪邊赤足多蠻女，門外青帘盡酒家。", "庭院秋深時有燕，園林春半已無花。", "堆盤荔子如冰雪，惟此堪將北地誇。"]'),
('470a46eb-bf13-4f3a-b052-863607158bfa','久旱得雨奉呈申之權郡學士','李光','宋','宋诗','song-poetry','','[]','不用椎牛瀆帝鄉，精誠端可格穹蒼。',64,'全唐诗/poet.song.82000.json','["不用椎牛瀆帝鄉，精誠端可格穹蒼。", "舉頭忽見千山雨，默禱惟憑一瓣香。", "已度南天三伏旱，未妨北牖午風涼。", "老蛟欲睡重鞭起，莫遣晴鳩喚夕陽。"]'),
('b2cafb85-bf59-4e65-befe-9f1e3f5de4e4','次林庭植喜雨韻','李光','宋','宋诗','song-poetry','','[]','一瓣黎沈徹九幽，随車甘雨散民憂。',64,'全唐诗/poet.song.82000.json','["一瓣黎沈徹九幽，随車甘雨散民憂。", "風聲震海驅雲出，雨點翻空捲地流。", "午夜村墟無吠犬，夕陽坡隴有耕牛。", "歡謡不獨聞田父，更向東陵覓故侯。"]'),
('dee38579-e7c1-48fb-ab5e-4cd385a9d418','題將領占勝亭亭據雙泉之上盡見城東南風物之勝落成之初屢來乞詩爲賦長句云','李光','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','結茅坡頂俯平川，占得城東勝概全。',64,'全唐诗/poet.song.82000.json','["結茅坡頂俯平川，占得城東勝概全。", "衮衮長江通瀚海，森森喬木带雲煙。", "月當庭戶初圓夜，霧隱樓臺欲雨天。", "玉帳今聞罷刁斗，却來閑處翫林泉。"]'),
('16a0368c-25de-4998-bfc2-68a9c18e9537','阜通閣','李光','宋','宋诗','song-poetry','','[]','危閣峥嶸枕碧流，籌心計慮匪人謀。',64,'全唐诗/poet.song.82000.json','["危閣峥嶸枕碧流，籌心計慮匪人謀。", "千颿不隔雲中樹，萬貨來從徼外舟。", "富國要先除國蠧，利民須急去民蟊。", "使君不日歸華近，要路翺翔徧十州。"]'),
('b1fc9483-1fe3-41d3-80ed-820d8f2af06c','重陽後二日會嚴氏野趣亭坐客吳德永裴堯文杜志林林元憲李彦實嚴君錫魏介然及予八人因成拙詩以紀一時之集云','李光','宋','宋诗','song-poetry','','[]','已過重陽得勝遊，海南秋色尚遲留。',64,'全唐诗/poet.song.82000.json','["已過重陽得勝遊，海南秋色尚遲留。", "旋沽白酒君須醉，未信黄花蝶解愁。", "菡萏香浮曲沼静，檳榔葉暗小亭幽。", "始知風景中原隔，對泣何須效楚囚。"]'),
('5849936f-7658-4c75-b5ea-c0199218d061','唐常建作破山寺詩云竹徑通幽處禪房花木深歐陽永叔毎歎賞此句以爲不可及温陵康元壽守瓊踰年樂其地僻而事簡以清静治之於郡圃植竹數百竿中有小亭因榜曰通幽偶成拙句','李光','宋','宋诗','song-poetry','','[]','蕭灑襟懷慕子猷，賸栽修竹徑通幽。',64,'全唐诗/poet.song.82000.json','["蕭灑襟懷慕子猷，賸栽修竹徑通幽。", "三間遠比淵明宅，百尺徒誇庾亮樓。", "風送鳥聲春寂寂，日篩簾影夢悠悠。", "破山絕景親曾到，誰遣移來海外州。"]'),
('d53d74ec-ef30-43f5-a3c0-2a7131af7674','八月十六夜江邊對月','李光','宋','宋诗','song-poetry','','[]','晚雨冥濛洗瘴塵，斷雲遮月尚鱗鱗。',64,'全唐诗/poet.song.82000.json','["晚雨冥濛洗瘴塵，斷雲遮月尚鱗鱗。", "影涵漲浦搖金鏡，光動天街碾玉輪。", "村市更無沽酒客，小樓時見捲簾人。", "不須辛苦瓊臺上，展席移觴近水濱。"]'),
('2bd4ff6c-4329-48fc-9935-01aaa3c0e462','丁卯二月二十七日與客縱步至判官陳師正所居前有花竹後有港浦愛其幽勝退作此詩師正歷官九任今年六十有一母年九十二歲杜門養親不復仕宦蓋瓊士之安貧守道者也','李光','宋','宋诗','song-poetry','','[]','幽居非是避危機，澀勒遮藏客到稀。',64,'全唐诗/poet.song.82000.json','["幽居非是避危機，澀勒遮藏客到稀。", "白髪不傳毛義檄，青衫常戲老萊衣。", "舟行别浦随潮去，燕認低簷带雨歸。", "從此欲尋棋酒社，肯論時節叩柴扉。"]'),
('d806dbed-0a3f-4c6a-aade-f517f012d506','寄內','李光','宋','宋诗','song-poetry','','[]','裊裊秋風度泬寥，卧聞微雨打芭蕉。',64,'全唐诗/poet.song.82000.json','["裊裊秋風度泬寥，卧聞微雨打芭蕉。", "黄花籬落重陽近，白髪江津客路遙。", "家信隔年新恨過，箧衣經暑舊香消。", "小槽正想珍珠滴，海舶來時寄一瓢。"]'),
('38609c30-090b-4fae-b5d0-5350697231c2','悼亡子詩','李光','宋','宋诗','song-poetry','','[]','脱屣塵寰委蜕蟬，真形渺渺駕非烟。',64,'全唐诗/poet.song.82000.json','["脱屣塵寰委蜕蟬，真形渺渺駕非烟。", "丹臺路杳無歸日，白玉樓成不待年。", "宴坐我方依古佛，空行汝去作飛仙。", "恩深父子情難割，淚滴千行到九泉。"]'),
('36068c23-314b-4b43-91ba-a5d04cde5462','次韻陳列之感春二首  其一','李光','宋','宋诗','song-poetry','','[]','新年人物自熙熙，綵索青帘到處垂。',64,'全唐诗/poet.song.82000.json','["新年人物自熙熙，綵索青帘到處垂。", "日暖桃蹊花落盡，雨深茅屋燕歸遲。", "登山野屐應頻蠟，出郭輕車想載脂。", "老境逢春正愁絕，爲君援筆強題詩。"]'),
('8d60df4f-bdc0-47bf-a59c-672f7740ea50','次韻陳列之感春二首  其二','李光','宋','宋诗','song-poetry','','[]','堤柳垂垂拂路塵，長條祇解絆歸人。',64,'全唐诗/poet.song.82000.json','["堤柳垂垂拂路塵，長條祇解絆歸人。", "營巢燕子穿簾急，带雨花枝照眼新。", "一壑風煙如可擅，滿牀書帙未全貧。", "狂吟痛飲須公等，枯木菴前草自春。"]'),
('fb7ed048-98c5-4fb3-8262-bf4313859f76','四月十四日晚陳列之見顧追涼翫月於東橋之上輒成長句以寫一時風景之勝','李光','宋','宋诗','song-poetry','','[]','小橋浮動似乘槎，坐看歸牛带晚鴉。',64,'全唐诗/poet.song.82000.json','["小橋浮動似乘槎，坐看歸牛带晚鴉。", "風捲斷雲飛玉馬，水搖明月走金蛇。", "影翻鳳尾檳榔葉，香散龍涎茉莉花。", "絕景勝遊仍有伴，不妨流落在天涯。"]'),
('0db6ee23-2099-4b67-8cdd-add8d4ef3c76','列之将歸温陵以詩告别因次韻送行二首  其一','李光','宋','宋诗','song-poetry','','[]','相逢海上欲忘年，誰似君家父子賢。',64,'全唐诗/poet.song.82000.json','["相逢海上欲忘年，誰似君家父子賢。", "氣比金莖吞沆瀣，文如巖壑带雲烟。", "追随里巷吾無伴，獨步詩騷子有權。", "青紫他年應俯拾，定中何必問諸天。"]'),
('a6c58d28-97fe-4376-8b7f-5255a70e02aa','列之将歸温陵以詩告别因次韻送行二首  其二','李光','宋','宋诗','song-poetry','','[]','八年嶺海未歸人，萬里天涯老病身。',64,'全唐诗/poet.song.82000.json','["八年嶺海未歸人，萬里天涯老病身。", "久堕黎蠻難擇友，頻經憂患易沾巾。", "我無妙策甘捐葉，子有長才預選掄。", "後夜更邀橋上月，爲傳羲御且停輪。"]'),
('b5da47da-3c56-40cd-b370-8fbaa51a5533','孟堅将北歸枕上成送行','李光','宋','宋诗','song-poetry','','[]','還家凖擬作重陽，行止升沈豈在忙。',64,'全唐诗/poet.song.82000.json','["還家凖擬作重陽，行止升沈豈在忙。", "童稚迎門歸亦好，雲山作伴住何妨。", "經行汝政窮幽賞，宴坐吾今喜夜長。", "解柁徑須尋舊隱，誅茅先葺竹間堂。"]'),
('7375689f-f583-40e4-94f2-8e21f03b0df7','己巳二月已發書殊不盡意偶成長句寄諸子姪并示元發商叟德舉資萬里一笑','李光','宋','宋诗','song-poetry','','[]','囊空無物寄妻兒，萬里惟憑一首詩。',64,'全唐诗/poet.song.82000.json','["囊空無物寄妻兒，萬里惟憑一首詩。", "舊日琴書都藞䕢，新年行步漸羸垂。", "時開竹戶通幽徑，旋結茅庵傍小池。", "永日無人惟宴坐，不貪杯酒不枰棋。"]'),
('decfb937-cab0-469a-b14c-60c5b33091e4','己巳重九小集拙詩記海外風景之異呈亨叔','李光','宋','宋诗','song-poetry','','[]','十年重九老天涯，異域空驚節物佳。',64,'全唐诗/poet.song.82000.json','["十年重九老天涯，異域空驚節物佳。", "楊柳枝頭無落葉，芙蓉池面有殘花。", "籬邊菊好延陶令，坐上詩成戲孟嘉。", "随分清歡須酩酊，歸時風帽任欹斜。"]'),
('7343b6be-d8f5-4d71-97a5-15baa630ad2d','秋日題池南壁間','李光','宋','宋诗','song-poetry','','[]','牢落雙泉一病翁，十年憂患掃還空。',64,'全唐诗/poet.song.82000.json','["牢落雙泉一病翁，十年憂患掃還空。", "荷稀竹密宜秋雨，戶窄簷低耐颶風。", "盡日抄書北窗下，有時閑步小橋東。", "誰知萬水千山外，亦與鄉居興味同。"]'),
('a5c6b040-70ee-401d-b8d2-b8e837d284ac','記夢一首','李光','宋','宋诗','song-poetry','','[]','夢魂忽到姜山寺，竹徑松門夜不關。',64,'全唐诗/poet.song.82000.json','["夢魂忽到姜山寺，竹徑松門夜不關。", "堂上千燈還閃閃，池中一水自潺潺。", "十年迥悟空心法，萬里歸尋葬骨山。", "欹枕覺來城角動，牀頭殘月尚彎環。"]'),
('9a53a0fe-b860-4db1-b90c-14282f1cb714','和郡守喜雨之什','李光','宋','宋诗','song-poetry','','[]','一犁甘澤應虔恭，頓覺山川返舊容。',64,'全唐诗/poet.song.82000.json','["一犁甘澤應虔恭，頓覺山川返舊容。", "宿靄釀成千嶂雨，迅雷驚起九淵龍。", "水生洲渚寛溪女，潤浹郊原慰老農。", "衰病不知春過去，強持杯酒略相從。"]'),
('c4991ce5-acbd-4a50-b8d3-8262c0583dc4','魏子介然甲戌中春不遠數百里訪予寂寞之濱予方厄窮適此久旱市無魚肉園乏佳蔬介然處之宴然眷眷不忍捨去予與介然别久介然氣貌議論益超然孟夏既望慨然請辭欲歸築室讀未見之書科舉之文不足學走筆作長句送行且勉使力學志其遠且大者仍用喜雨詩韻','李光','宋','宋诗','song-poetry','','[]','愛君凛凛有英風，刮目相看爲改容。',64,'全唐诗/poet.song.82000.json','["愛君凛凛有英風，刮目相看爲改容。", "榻解久懸延孺子，樓登百尺卧元龍。", "貨因縷積成良賈，學務深耕鄙惰農。", "已約三冬重過我，盡攜書史日相從。"]'),
('5600a146-307d-4ff6-95c1-c32032d83c3a','人日偶得酒果因與客飲成鄙句并紀海外風物之異','李光','宋','宋诗','song-poetry','','[]','燕歸茅屋草芊綿，節物方驚海外偏。',64,'全唐诗/poet.song.82000.json','["燕歸茅屋草芊綿，節物方驚海外偏。", "風掃落花春寂寂，雨添幽澗水涓涓。", "臘醅每謝鄰邦餽，北果來從賈客船。", "勝日漫逢聊一笑，白頭那問歲時遷。"]'),
('92774718-59a5-4e42-b01c-06231bbfa4f2','二月三日作真率會遊載酒堂呈坐客  其一','李光','宋','宋诗','song-poetry','','[]','郊外初聞黄栗留，仲春風物漸和柔。',64,'全唐诗/poet.song.82000.json','["郊外初聞黄栗留，仲春風物漸和柔。", "殺雞炊黍成真率，挈榼攜棋得勝遊。", "聊欲勸君終日醉，未須悲我十年流。", "朝來已換輕衫窄，酒盡何妨典破裘。"]'),
('ef154a2c-4107-4446-b273-d1cca854f47f','二月三日作真率會遊載酒堂呈坐客  其二','李光','宋','宋诗','song-poetry','','[]','路接蓬瀛日景遲，塵心消盡忘歸期。',64,'全唐诗/poet.song.82000.json','["路接蓬瀛日景遲，塵心消盡忘歸期。", "雨餘荒草侵三徑，風起微瀾皺一池。", "晚色遠涵殘照外，春光欲近禁烟時。", "黄鸝不肯簷間語，隔葉相呼過别枝。"]'),
('b58fee60-e0cd-41a0-a584-8f050e74e430','二月九日北園小集烹茗奕棋抵暮坐客及予皆霑醉無志一時之勝者今晨枕上偶成鄙句寫呈逢時使君并坐客','李光','宋','宋诗','song-poetry','','[]','勝日邀朋醉北園，森森喬木欲參天。',64,'全唐诗/poet.song.82000.json','["勝日邀朋醉北園，森森喬木欲參天。", "更無粉色汙尊俎，只有琴聲敵管絃。", "臘酒旋開浮綠蟻，春芽初破瀹新泉。", "欲修禊事清明近，曲水流觴擬晉賢。"]'),
('38f9185b-d289-4bfa-9589-89e5379c748b','七月既望雨後對月招鄰人夜飲不至獨酌成詩一首以寫一時之景','李光','宋','宋诗','song-poetry','','[]','虹斂江空正寂寥，苦無燈火夜蕭蕭。',64,'全唐诗/poet.song.82000.json','["虹斂江空正寂寥，苦無燈火夜蕭蕭。", "暮潮和雨歸滄海，華月穿雲上碧霄。", "沙路微行塵不到，柴門深閉客難招。", "一杯黎酒還成醉，羈枕時聞犬度橋。"]'),
('d0ae9aef-201b-419c-acb6-5717bf963077','秋夜有懷','李光','宋','宋诗','song-poetry','','[]','金爐未冷旋添香，風静雲開月到廊。',64,'全唐诗/poet.song.82000.json','["金爐未冷旋添香，風静雲開月到廊。", "何處獨吹西塞曲，無人同醉北窗涼。", "鱗鴻路隔書難寄，鼓角聲遲夜漸長。", "明日欲尋真率約，濁醪時許過鄰牆。"]'),
('2f55dad5-f57e-4de7-94b1-37a258e54a71','海南氣候與中州異羣花皆早發至春時已盡獨荷花自三四月開至窮臘與梅菊相接雖花頭小而香色可愛頃歲蘇端明謫居此郡嘗和淵明詩其略云城南有荒池瑣細誰復採幽姿小芙蕖香色獨未改即此池也今五十餘年池益增廣臨川陳使君復結屋其上名賓燕堂今夏得雨遲七月末花方盛開因成此詩約勝日爲採蓮之集云','李光','宋','宋诗','song-poetry','','[]','秋來雨足溢方塘，華屋臨流四面涼。',64,'全唐诗/poet.song.82000.json','["秋來雨足溢方塘，華屋臨流四面涼。", "風颭圓荷翻翠蓋，水涵芳蘂艶紅粧。", "淡煙難掩天真色，薄日時烘自在香。", "詩老未須譏瑣細，解陪梅菊到冰霜。"]'),
('5e7b116f-352a-4194-ab8b-a3ca6e64a5ab','昨晚約逢時使君今日食後過賓燕瀹茗觀蓮今日雨忽作因記東坡遊西湖遇雨詩云湖光瀲灔晴方好山色空濛雨亦奇之句作雨中觀蓮詩戲呈并示同行諸君','李光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城南方沼盡栽蓮，得雨花開晚更妍。',64,'全唐诗/poet.song.82000.json','["城南方沼盡栽蓮，得雨花開晚更妍。", "自有清芬來襲袂，不須紅粉笑當筵。", "彤霞暈臉深還淺，碧蓋跳珠碎復圓。", "更擬中秋陪燕賞，月娥休妬水中仙。"]'),
('3206470b-53a2-437a-a73f-25cd2ecd67b6','移具訪逢時堅白堂','李光','宋','宋诗','song-poetry','','[]','已許攜壺就綺羅，却因風雨斷經過。',64,'全唐诗/poet.song.82000.json','["已許攜壺就綺羅，却因風雨斷經過。", "不辭美酒十分勸，欲聽佳人一曲歌。", "掌上要觀摩勒果，池中難借右軍鵝。", "使君獨醒空回去，被冷燈青客奈何。"]'),
('8af4c951-0f7e-4e23-a756-b5b4d6b45103','庚午重九予以憂患經此節物亦強舉杯復同坐客步至陳氏水閣率爾成韻','李光','宋','宋诗','song-poetry','','[]','累歲嚴亭會衆賓，今年九日未全貧。',64,'全唐诗/poet.song.82000.json','["累歲嚴亭會衆賓，今年九日未全貧。", "樽中有酒須招客，籬外無花免笑人。", "竹杖芒鞋行自慣，風軒水閣坐來頻。", "鬢邊強把茱萸插，萬里誰嗟老病身。"]'),
('2d7e33b0-d8ab-444f-a449-9a324175aa1e','辛未歲旦用蘇子由韻成兩詩寄諸子姪  其一','李光','宋','宋诗','song-poetry','','[]','朋遊族黨死生分，老壽今居第二人。',64,'全唐诗/poet.song.82000.json','["朋遊族黨死生分，老壽今居第二人。", "松竹飽經炎海瘴，柳梅空想越溪春。", "身行九折心無轉，息住三田氣自新。", "白晝漸長窗日暖，始知羲馭解停輪。"]'),
('6e5661ba-a790-4615-b054-d377d2b15ea3','辛未歲旦用蘇子由韻成兩詩寄諸子姪  其二','李光','宋','宋诗','song-poetry','','[]','頻把光陰惜寸分，十年閲盡世中人。',64,'全唐诗/poet.song.82000.json','["頻把光陰惜寸分，十年閲盡世中人。", "衰容暗換圖中象，和氣潛回海底春。", "香裊金爐沉水暖，茶烹石鼎乳泉新。", "丹元息息添真火，肯使空花翳五輪。"]'),
('59e8f8e3-0181-4dc9-9015-b97dc43bd675','吳德永遠寄乾栗五百顆荷其厚意戲作長句謝之','李光','宋','宋诗','song-poetry','','[]','海山深處住多年，容貌雖衰齒尚堅。',64,'全唐诗/poet.song.82000.json','["海山深處住多年，容貌雖衰齒尚堅。", "長使玉泉歸絳闕，毎留真火暖丹田。", "感君特地貽乾栗，知我猶能咬石蓮。", "土物欲尋香翠報，近來行市正增錢。"]'),
('57c17d60-dd96-4c72-9487-5a46eac78258','四月望夜郡寮悉赴盛集羊荆華林伯壽伯安相繼見過同登涌月閣待月成拙詩并呈常往來諸友','李光','宋','宋诗','song-poetry','','[]','杖藜欲往歎塗窮，賴有林廬寓此翁。',64,'全唐诗/poet.song.82000.json','["杖藜欲往歎塗窮，賴有林廬寓此翁。", "日暮凭欄看涌月，夜涼開牖濯清風。", "浮沉直擬羣鷗鷺，冷暖安能效燕鴻。", "獨酌城南二三子，攜棋挈榼笑言同。"]'),
('a77b7b36-ea89-4149-bd40-57693d507877','羊荆華敞小軒面叢竹予以細香名之蓋用杜子美風吹細細香之句因賦此詩','李光','宋','宋诗','song-poetry','','[]','負郭林廬带草堂，小亭軒敞對修篁。',64,'全唐诗/poet.song.82000.json','["負郭林廬带草堂，小亭軒敞對修篁。", "祖師但指青青色，詩老能聞細細香。", "風過戶庭常掩冉，雨餘衾枕自清涼。", "幽蘭茉莉徒芬郁，氣味不如君久長。"]'),
('3b93b7dd-bc44-412b-850f-dada49fba972','昌化雖窮寂今歲偶諸處寄酒東船至得北果又老庖自海康來人日與客飲邂逅成醉座中賦此','李光','宋','宋诗','song-poetry','','[]','去年人日醉陳園，竹外風流洗瘴烟。',64,'全唐诗/poet.song.82000.json','["去年人日醉陳園，竹外風流洗瘴烟。", "花落野桃春寂寂，潮回南浦水涓涓。", "臘醅每謝鄰邦使，北果常随賈客船。", "佳節漫逢聊一笑，老庖能鱠海鱸鮮。"]'),
('86763fa0-69bf-4b8d-8bb4-7c2c1017d245','悼程伯宇尚書  其一','李光','宋','宋诗','song-poetry','','[]','目斷佳城戶一扃，名山千古返英靈。',64,'全唐诗/poet.song.82000.json','["目斷佳城戶一扃，名山千古返英靈。", "郡祠空復存圖像，朝路無由認履聲。", "大節已書班氏筆，豐碑應勒退之銘。", "文章不朽傳賢嗣，收拾何勞假六丁。"]'),
('d42de050-f958-417a-8002-819a1cc679f9','悼程伯宇尚書  其二','李光','宋','宋诗','song-poetry','','[]','壯節滋培雨露深，褎然文采冠儒林。',64,'全唐诗/poet.song.82000.json','["壯節滋培雨露深，褎然文采冠儒林。", "恩霑二族全純孝，忠貫三朝秉一心。", "墓木未懸吳札劍，斷弦誰續伯牙琴。", "傷情故篋存遺帖，灑淚行間自不禁。"]'),
('8fd436eb-1034-4df8-b4e7-4e92ceb27a54','八月一日詣新學瞻禮廟像退與客徜徉訪尋幽勝所至清談瀹茗晚至陳氏園亭酌乳泉而歸一時清集無愧前人主簿趙元弼乃有厄陳之歎形於篇詠因次其韻兼呈諸友','李光','宋','宋诗','song-poetry','','[]','郊居多與泮宫鄰，回首清游迹已陳。',64,'全唐诗/poet.song.82000.json','["郊居多與泮宫鄰，回首清游迹已陳。", "曳杖入門瞻廟像，穿林度壑訪幽人。", "遠稽鄒魯衣冠古，近揖江山氣象新。", "飲水飯蔬真樂趣，始知席上有儒珍。"]'),
('666ca9ab-7db2-46d3-9cbe-fa3f393dd86a','元弼主簿喜飲而吝於開閣又累輸棋不償同僚頗以爲言八月朔出郊乃有戹陳之歎因再次其韻','李光','宋','宋诗','song-poetry','','[]','飛蓋追随訪隱淪，坐中佳客有荀陳。',64,'全唐诗/poet.song.82000.json','["飛蓋追随訪隱淪，坐中佳客有荀陳。", "貪盃且可偷鄰甕，愛竹何須問主人。", "雨後已看山色爽，雲頭漸喜月華新。", "烹羊載酒邀同社，冷落盃盤笑集珍。"]'),
('d5939d1d-8f69-4b35-83b0-c11f8bfe8e25','郡學落成之初八月二十二日陪郡守同來仍榜郡學二字遒勁結密觀者興歎是日燕郡僚并學職郡守謂予本起諸生俾預燕集因成鄙句呈逢時坐客','李光','宋','宋诗','song-poetry','','[]','氣清天朗屬中秋，黌舍初成燕魯侯。',64,'全唐诗/poet.song.82000.json','["氣清天朗屬中秋，黌舍初成燕魯侯。", "依舊規模環璧水，斬新牌牓燦銀鈎。", "青衿士子欣榮遇，白髪迂儒預勝遊。", "尼父道行千載後，坐令南海變東周。"]'),
('718bad5d-3add-4c31-b9f6-129e5d0105a1','海外自去冬不雨至今農圃俱病郡侯率僚友爲民祈禱二月十八日祭社致齋是日雨作喜而成詩呈逢時使君','李光','宋','宋诗','song-poetry','','[]','随車甘雨應精祈，樂歲豊年喜有期。',64,'全唐诗/poet.song.82000.json','["随車甘雨應精祈，樂歲豊年喜有期。", "草色青青連粟壠，竹聲細細想荷池。", "欣逢山路花開日，正值田家酒熟時。", "凖擬明朝風日好，野桃應有未開枝。"]'),
('bc6e31e9-285d-4601-b467-87ce026c3ecc','靈真道人久無詩來用協甫韻并前篇寄之且拉爾耳翁同賦','李光','宋','宋诗','song-poetry','','[]','道人何處是生涯，山遶孤村水繞家。',64,'全唐诗/poet.song.82000.json','["道人何處是生涯，山遶孤村水繞家。", "鬢裏雪霜全掃白，胸中梨棗旋開花。", "已乘綠景功初就，更服黄精善莫加。", "若向静中生妄想，還如炎地走冰車。"]'),
('192bf79b-c711-4e48-baad-21d97e05f7bc','林庭植雖已受代勉爲感思之行交印後即浩然歸隱徜徉里巷間以棋自娛樂哉未易得也因成拙句贈行','李光','宋','宋诗','song-poetry','','[]','歷徧昌江守令權，却回小邑作神仙。',64,'全唐诗/poet.song.82000.json','["歷徧昌江守令權，却回小邑作神仙。", "宦游未遂心先淡，歸槖雖空意愈堅。", "濁酒三杯須滿酌，枯棋一局要爭先。", "閑居自得閑中趣，更活人間七十年。"]'),
('055c8390-2a02-4fcd-b9e2-471f2c59013e','吏隱堂','李光','宋','宋诗','song-poetry','','[]','海邦地僻少迎將，心逸身閑白晝長。',64,'全唐诗/poet.song.82000.json','["海邦地僻少迎將，心逸身閑白晝長。", "賸欲哦詩追沈謝，不求名迹擬龔黄。", "旋移松石成雲壑，時引笙簫入醉鄉。", "吏散簾垂公事畢，清風一榻傲羲皇。"]'),
('532a0490-6343-49bc-a81f-44ba06fddb33','拙詩奉送厚之權郡還闕','李光','宋','宋诗','song-poetry','','[]','天衢未擬縱驊騮，南顧聊寛聖主憂。',64,'全唐诗/poet.song.82000.json','["天衢未擬縱驊騮，南顧聊寛聖主憂。", "民頌永傳儋耳國，家聲夙著虎頭州。", "簿書脱屣歸華貫，翰墨收功入勝流。", "去去願將民疾苦，盡攄胸臆副旁求。"]'),
('b6c5f9b8-b21d-4ff1-a64f-b7f268164d60','獨居自遣一首寄厚之','李光','宋','宋诗','song-poetry','','[]','平生憂道不憂貧，萬里風波一葉身。',64,'全唐诗/poet.song.82000.json','["平生憂道不憂貧，萬里風波一葉身。", "路滑須憑木上座，天寒那用竹夫人。", "閑尋獨鶴爲仙友，笑指孤雲作近鄰。", "北客不勞頻問訊，已拚終老海南濱。"]'),
('47575160-13e6-45cf-9152-9f2fc711b224','送秦令元發赴吉陽','李光','宋','宋诗','song-poetry','','[]','百里威風已震驚，朱幡夾道聳先聲。',64,'全唐诗/poet.song.82000.json','["百里威風已震驚，朱幡夾道聳先聲。", "耕桑不擾民歸業，香翠無求吏自清。", "老去方知五馬貴，愁來未覺一杯輕。", "世情冷暖難開口，懷抱因君得盡傾。"]'),
('aa2762f5-c646-49d6-85b6-99c33d8ecfe8','象臺','李光','宋','宋诗','song-poetry','','[]','全家卜築面孱顔，變態煙雲坐卧看。',64,'全唐诗/poet.song.82000.json','["全家卜築面孱顔，變態煙雲坐卧看。", "丘壑時應攜妓女，階庭還見産芝蘭。", "水涵山影千尋碧，路轉松陰十里寒。", "杖策它年容叩戶，盡驅佳處入毫端。"]'),
('0d164dbe-df9a-485e-981f-1639164863c5','和雨後對月','李光','宋','宋诗','song-poetry','','[]','載酒人無顧寂寥，秋來門巷更蕭蕭。',64,'全唐诗/poet.song.82000.json','["載酒人無顧寂寥，秋來門巷更蕭蕭。", "風驅雨脚收千嶂，雲捲月輪升九霄。", "松竹此時聊谷隱，巾車指日見弓招。", "登臨莫作殊鄉念，乘興時尋小石橋。"]'),
('26118a29-2af3-4da2-a622-229586ed851e','海外氣候每歲三四月間已如劇暑客有自吉陽至者寓館問漢亭累日且言吉陽氣候晝夜如炊因歎此邦之勝乃知人生無有足時不經熱惱豈知平日之清凉乎故古之達者毎以此對治釋氏云推落大火坑火坑變成池皮鞋和尚以爲即時清凉也蘇公亦云嶺南瘴毒地有此江月寒乃知天壤間何人不清安予謫居嶺海踰十五年見聞習熟不以爲異因作此詩以自慰且以警世之賤丈夫一不快即愁歎怨憤或譏謗怒罵如柳劉之徒蓋未足以語此也','李光','宋','宋诗','song-poetry','','[]','客自東來說吉陽，始知儋耳本清凉。',64,'全唐诗/poet.song.82000.json','["客自東來說吉陽，始知儋耳本清凉。", "潮聲卷海千峰雨，月色侵門滿地霜。", "更欲何方尋佛國，此生真欲老蠻鄉。", "安心守一師吾祖，尚覺人間日月長。"]'),
('e5d876df-cff3-4e5a-929f-ef03de5d86e0','予生世幾八十年交游士友有昧平生而一見氣合者有同鄉並舍而終身情乖者因悟笑曰此釋氏所謂宿緣也知此則可以忘憂惱泯是非免輪迴而脱生死也因作拙句以道其意云','李光','宋','宋诗','song-poetry','','[]','路隔仙凡只一塵，浮生出没轉風輪。',64,'全唐诗/poet.song.82000.json','["路隔仙凡只一塵，浮生出没轉風輪。", "宿緣未斷形雖換，異世相逢意自親。", "圓澤再來尋舊伴，房公一笑悟前身。", "若將愛見迷真性，萬劫難超未了因。"]'),
('b6c0b115-3ec3-4738-9b29-0d6e61472079','丙子正月二十三日紀事','李光','宋','宋诗','song-poetry','','[]','風捲陰霾日月明，鯨鯢已戮海波平。',64,'全唐诗/poet.song.82000.json','["風捲陰霾日月明，鯨鯢已戮海波平。", "姦憸藉手捐奇貨，交友通書免詭名。", "舊俗衣冠回左衽，新疆兵革偃長城。", "聖君若用當時將，一洗烟塵宇宙清。"]'),
('c9147a70-dd38-4330-ba92-726ffd712d85','離陽壽縣百餘里遇大風雨溪流漲溢宿修仁境小寺新潔可喜不復有滯留之歎偶成長句老病字畫欹斜輙自笑也仲子孟堅同來','李光','宋','宋诗','song-poetry','','[]','逐客多年住海濱，今朝喜作北鄉人。',64,'全唐诗/poet.song.82000.json','["逐客多年住海濱，今朝喜作北鄉人。", "飄風掃地捲煩暑，驟雨翻空洗瘴塵。", "境惡乍離賓館陋，眼明欣覩佛祠新。", "松林竹徑俱幽勝，留滯何庸歎苦辛。"]'),
('10d729a1-8288-43eb-a672-c6be9add71e8','某到郴幾兩月適當重陽而菊猶未開然江山清遠又仙佛所居有足樂者因成鄙句以寫離憂','李光','宋','宋诗','song-poetry','','[]','重陽從古多傷感，逐客南來重歎嗟。',64,'全唐诗/poet.song.82000.json','["重陽從古多傷感，逐客南來重歎嗟。", "鏡裏但驚添白髪，樽前猶未見黄花。", "求仙頓覺三山近，成佛無令一念差。", "習氣平生都掃盡，更憑橘水洗塵沙。"]'),
('1704358a-b1ee-4295-8303-b0cd7cdd1c6b','郴士爲作暖閣既成是夕雪作喜而成詩','李光','宋','宋诗','song-poetry','','[]','暖閣初成荷北鄰，歡然一笑欲烘春。',64,'全唐诗/poet.song.82000.json','["暖閣初成荷北鄰，歡然一笑欲烘春。", "香煙苒苒縈紆轉，鼻息齁齁出入勻。", "睡美忽驚天曈曨，夜寒誰怕脚舒伸。", "老兵來報雪床厚，凖擬明朝共飲醇。"]'),
('98c269c0-f87a-44cc-a6f6-bb5d5ad86547','悼程伯宇尚書','李光','宋','宋诗','song-poetry','','[]','人物江東第一流，天衢闊步縱驊騮。',96,'全唐诗/poet.song.82000.json','["人物江東第一流，天衢闊步縱驊騮。", "彈冠事主俱青紱，握手論交到白頭。", "照世詞華窺賈馬，致君事業擬伊周。", "平生自謂孔北海，晚節欲爲陳太丘。", "危行危言逢有道，一生一死見交遊。", "自憐罪大無歸日，哭送松門嘆莫由。"]'),
