('b7909c4c-3a03-49bf-b0c6-f9c0172cc5d7','問漢亭','李光','宋','宋诗','song-poetry','','[]','河畔牽牛織女星，東西相望幾千程。',32,'全唐诗/poet.song.83000.json','["河畔牽牛織女星，東西相望幾千程。", "乘槎我欲機邊坐，應解停梭問姓名。"]'),
('437bdf33-419c-47ab-ad00-ed1a87e771f9','城南池','李光','宋','宋诗','song-poetry','','[]','枯木摧殘色境空，西風獨占水芙蓉。',64,'全唐诗/poet.song.83000.json','["枯木摧殘色境空，西風獨占水芙蓉。", "瑤池飲散紅妝鬧，洛浦人歸翠蓋重。", "日影透簾香掩苒，月華侵坐客從容。", "閑花瑣細能長久，免被移栽太華峰。"]'),
('3925f9cf-96ca-4b4e-b3a7-c4a8bfa2680d','昌江','李光','宋','宋诗','song-poetry','','[]','昌江真陋邦，芋魁的盈尺。',24,'全唐诗/poet.song.83000.json','["昌江真陋邦，芋魁的盈尺。", "逐客方阨陳，飽食度終日。"]'),
('3376bbf8-9cd7-4971-b067-9677917b1077','破山寺','李光','宋','宋诗','song-poetry','','[]','招提清絕冠諸方，溪繞山圍勝氣藏。',64,'全唐诗/poet.song.83000.json','["招提清絕冠諸方，溪繞山圍勝氣藏。", "好在池塘存舊址，依然花木隱禪房。", "風生殿閣元無暑，雨後松篁自有香。", "日暮不教清興盡，更登絕頂瞰微茫。"]'),
('36a33d4c-485b-4a67-8442-de9ce8e7093e','勝法寺','李光','宋','宋诗','song-poetry','','[]','舍南舍北竹千竿，鏡凈無塵碧玉寒。',32,'全唐诗/poet.song.83000.json','["舍南舍北竹千竿，鏡凈無塵碧玉寒。", "中有老人清似水，晚來相對倚欄桿。"]'),
