('dbee4718-52ef-4fd3-865c-9ec9d9ce17fd','句  其五','李光','宋','宋诗','song-poetry','','[]','銅盆湛冰雪，誰謂無寒泉。',12,'全唐诗/poet.song.83000.json','["銅盆湛冰雪，誰謂無寒泉。"]'),
('0d1b46a5-49bf-436f-bc5b-cc8a13f9cfe7','句  其六','李光','宋','宋诗','song-poetry','','[]','昌江古佳郡。',6,'全唐诗/poet.song.83000.json','["昌江古佳郡。"]'),
('596294c0-9c85-4f93-b834-379d6af1d4eb','除夕','鄭望之','宋','宋诗','song-poetry','','[]','可是今年老也無，兒孫次第飲屠蘇。',32,'全唐诗/poet.song.83000.json','["可是今年老也無，兒孫次第飲屠蘇。", "一門骨肉知多少，日出高時到老夫。"]'),
('b5107ff9-af59-4136-8dfb-f283db8a225a','建炎丞相成國呂忠穆公退老堂','鄭望之','宋','宋诗','song-poetry','','[]','熙陵嘗賦釣魚篇，意屬磻溪舊所傳。',128,'全唐诗/poet.song.83000.json','["熙陵嘗賦釣魚篇，意屬磻溪舊所傳。", "治世代天今六相，中興扶日跨羣賢。", "已栽桃李滿天下，更卜林泉占海邊。", "不似東山攜妓女，一觴一詠度長年。", "一從奉得去年書，報道江山已定居。", "應料于今台岳畔，還同自昔輞川圖。", "君臣終始如公少，將相聲名自古無。", "何日雍容陪杖屨，松風山徑竹籃輿。"]'),
('e2975995-fdc5-40f4-b190-d7e0f1c04066','賦漢印','唐悊','宋','宋诗','song-poetry','','[]','關中金印豈秦關，想見風流漢已還。',64,'全唐诗/poet.song.83000.json','["關中金印豈秦關，想見風流漢已還。", "大饗似書譙縣石，蘭亭寧數會稽山。", "空餘此日歸囊櫜，曾是當年雜佩環。", "萬戶況將取如斗，此章何足繫腰間。"]'),
('34f84846-679b-4900-9ee8-d4a5d123aba4','題宗室趙大年橫卷','唐悊','宋','宋诗','song-poetry','','[]','聞君新得小山川，畫手來從郜雍賢。',64,'全唐诗/poet.song.83000.json','["聞君新得小山川，畫手來從郜雍賢。", "不學農夫焉用稼，若爲王子豈知田。", "我真壠上躬耕客，親見人間小隱天。", "始識何年京樣熟，菊籬寧似景龍邊。"]'),
('74b5fdd9-7b5a-456f-9380-ba0ec6b4cd60','題延慶寺  其一','范坦','宋','宋诗','song-poetry','','[]','煙村水寺若江湖，林麓山川入畫圖。',32,'全唐诗/poet.song.83000.json','["煙村水寺若江湖，林麓山川入畫圖。", "壁上薰風爲誰製，柄臣曾此耀歸途。"]'),
('e7fa9c5c-30f4-4ffd-8f65-2a68019d9e1c','題延慶寺  其二','范坦','宋','宋诗','song-poetry','','[]','寺閣涵虛跨碧潭，菰蒲楓柳認江南。',32,'全唐诗/poet.song.83000.json','["寺閣涵虛跨碧潭，菰蒲楓柳認江南。", "侍臣家世俱遊此，雁敘題名在壁龕。"]'),
('48c2ca33-5d09-4808-a8a9-1ed8c1261082','劍門關','何甫','宋','宋诗','song-poetry','','[]','一門橫大道，雙劍插長空。',24,'全唐诗/poet.song.83000.json','["一門橫大道，雙劍插長空。", "鼓鑄非人力，磨礱任化工。"]'),
('019575f6-9428-408c-aee0-1ecb8a93c305','廣勝寺','曹量','宋','宋诗','song-poetry','','[]','駐車長道莫加鞭，得到幽藍頓豁然。',64,'全唐诗/poet.song.83000.json','["駐車長道莫加鞭，得到幽藍頓豁然。", "千仞嵐高晴聚翠，萬年枝花莫生煙。", "滿窗夜到天涯月，一枕秋深海眼泉。", "自是寂中有真趣，如何瀟灑不忘筌。"]'),
('2f8d0261-e69e-49c1-94d5-8715364b0e80','別葉館伴','韓繳如','宋','宋诗','song-poetry','','[]','泣涕汍瀾欲別離，此生無復再來期。',32,'全唐诗/poet.song.83000.json','["泣涕汍瀾欲別離，此生無復再來期。", "漫將寶玉陳深意，莫忘思人見物時。"]'),
('ffccca2f-43b7-4b81-9635-650fb3f204db','挽黄忠文公  其一','家誠之','宋','宋诗','song-poetry','','[]','自從朱邸翊元良，聖學磨礱日就將。',64,'全唐诗/poet.song.83000.json','["自從朱邸翊元良，聖學磨礱日就將。", "嗜飽豈容登鼎俎，剪桐爭肯戲圭璋。", "經筵猶有八圖在，御座俄驚一鑑亡。", "恤典隆名雖寵渥，何如大政細平章。"]'),
('085d1918-3082-456a-ada9-0b6cdf61afd6','挽黄忠文公  其二','家誠之','宋','宋诗','song-poetry','','[]','棘闈尚記一窗鄰，把酒論文情獨親。',64,'全唐诗/poet.song.83000.json','["棘闈尚記一窗鄰，把酒論文情獨親。", "轍跡我猶循井絡，履聲公已上星辰。", "追思九鼎回天力，莫贖千金報國身。", "老去驅車隻劍道，忍看高冢臥麒麟。"]'),
('78954363-3b6a-4c4e-8e95-230597eeef1c','句','馮如愚','宋','宋诗','song-poetry','','[]','地靈人秀誰稱首，文屬君華武硬弓。',16,'全唐诗/poet.song.83000.json','["地靈人秀誰稱首，文屬君華武硬弓。"]'),
('0baa8f7b-0f46-4ac2-b10e-5cefd1a0f440','夢中作','王耕','宋','宋诗','song-poetry','','[]','樓上虛懷待月時，寫景應難不賦詩。',32,'全唐诗/poet.song.83000.json','["樓上虛懷待月時，寫景應難不賦詩。", "一天列宿坐中見，萬里青天雲外歸。"]'),
('3e19836b-8e8e-439d-b185-5821870c0ee6','雲根書院作','謝安時','宋','宋诗','song-poetry','','[]','結屋傍雲根，溪山似陸渾。',48,'全唐诗/poet.song.83000.json','["結屋傍雲根，溪山似陸渾。", "釣舟藏荻渚，吟逕入花村。", "竹月盡滿壁，松風時款門。", "靜中元有物，浩氣塞乾坤。"]'),
('6f63f8ea-e919-4d73-a9b5-94435cce8959','句  其一','李元亮','宋','宋诗','song-poetry','','[]','人閑知晝永，花落見春深。',12,'全唐诗/poet.song.83000.json','["人閑知晝永，花落見春深。"]'),
('b85c2593-c8d4-4d4f-b689-3a318b7b3cc3','句  其二','李元亮','宋','宋诗','song-poetry','','[]','朝雨未休還暮雨，臘寒才過又春寒。',16,'全唐诗/poet.song.83000.json','["朝雨未休還暮雨，臘寒才過又春寒。"]'),
('36b5543e-2bcf-4bc4-afcd-706f9d4f1ec7','句  其三','李元亮','宋','宋诗','song-poetry','','[]','可憐三萬六千日，長做東西南北人。',16,'全唐诗/poet.song.83000.json','["可憐三萬六千日，長做東西南北人。"]'),
('1bf52adc-dafd-47c5-a2b4-bf4cd6f50114','草堂寺','孫鰲','宋','宋诗','song-poetry','','[]','雙樹輪囷五百年，開華結實兩爭妍。',32,'全唐诗/poet.song.83000.json','["雙樹輪囷五百年，開華結實兩爭妍。", "我來問道師知否，祖意元無法可傳。"]'),
('98223bbd-0ffc-426c-ae22-063ccf1d4781','贈故人','綦革','宋','宋诗','song-poetry','','[]','三月楊花滿路飛，金人遊騎拍鞍歸。',32,'全唐诗/poet.song.83000.json','["三月楊花滿路飛，金人遊騎拍鞍歸。", "高天二聖猶難保，誰道雄關是可依。"]'),
('09469193-be8d-4b16-b801-a5c0b69c3d6d','祈澤寺  其一','季季','宋','宋诗','song-poetry','','[]','虛窗雲暗青燈小，松檜無風春悄悄。',32,'全唐诗/poet.song.83000.json','["虛窗雲暗青燈小，松檜無風春悄悄。", "子規枝上叫夢回，清磬一聲山月曉。"]'),
('4a1f17da-0e05-4bb3-8f09-bcec6b6d5714','祈澤寺  其二','季季','宋','宋诗','song-poetry','','[]','官南官北添身累，年去年來換鬢青。',32,'全唐诗/poet.song.83000.json','["官南官北添身累，年去年來換鬢青。", "何日歸來閑歲月，掃山廬墓過餘齡。"]'),
('f341afbc-b56e-4c7d-8fc8-b7b08c8d5906','偈','釋妙喜','宋','宋诗','song-poetry','','[]','萬仞懸崖忽放身，起來依舊卻惺惺。',32,'全唐诗/poet.song.83000.json','["萬仞懸崖忽放身，起來依舊卻惺惺。", "饑餐渴飲無餘事，那論昔人非昔人。"]'),
('772ed3c6-4861-4a8a-8026-a4fea6a9f5ce','和覺禪師賦六湛堂','釋妙喜','宋','宋诗','song-poetry','','[]','非湛非搖此法源，當機莫厭假名存。',64,'全唐诗/poet.song.83000.json','["非湛非搖此法源，當機莫厭假名存。", "直須過量英靈漢，方入無邊廣大門。", "萬境交羅元不二，六窗晝夜未嘗昏。", "翻思龐老事無別，擲劍揮空豈有痕。"]'),
('f7fcee9e-1f50-4de3-aea5-f450a396c725','偈','釋妙喜','宋','宋诗','song-poetry','','[]','通身一穿金鎖骨，堪與人天爲軌則。',32,'全唐诗/poet.song.83000.json','["通身一穿金鎖骨，堪與人天爲軌則。", "要識臨濟小廝兒，便是當年白拈賊。"]'),
('c6e55af8-aa2c-4de1-8b3c-5f4100479513','和馮濟川題枯髏圖','釋妙喜','宋','宋诗','song-poetry','','[]','只此形骸，即是其人。',20,'全唐诗/poet.song.83000.json','["只此形骸，即是其人。", "一靈皮袋，皮袋一靈。"]'),
('16ffb082-053b-4183-afbc-869a8c8c9da0','冬夜','李若璞','宋','宋诗','song-poetry','','[]','蒼蒼夜色雲云遠，葉落風林噪亂鴉。',64,'全唐诗/poet.song.83000.json','["蒼蒼夜色雲云遠，葉落風林噪亂鴉。", "香篆暖煙濃結穗，暗窗寒雪密飄花。", "瑯瑯翠竹幽音碎，耿耿青燈孤影斜。", "忘累俗情添興雅，晚眠獨啜滿甌茶。"]'),
('54df4465-6bf8-4d93-8ba5-6eaad4335c36','桔槔頌','薛道光','宋','宋诗','song-poetry','','[]','軋軋相從響發時，不從他得豁然知。',32,'全唐诗/poet.song.83000.json','["軋軋相從響發時，不從他得豁然知。", "桔槔說盡無生曲，井裏泥蛇舞柘枝。"]'),
('2db6be72-fcb2-4f5d-98a5-756ef37a951f','臨終頌','薛道光','宋','宋诗','song-poetry','','[]','鐵馬奔入海，泥蛇飛上天。',24,'全唐诗/poet.song.83000.json','["鐵馬奔入海，泥蛇飛上天。", "蓬萊三島路，元不在西邊。"]'),
('38688261-de73-435b-8c0a-a25c15ddda60','還丹復命篇 五言十六首 其一','薛道光','宋','宋诗','song-poetry','','[]','有物含靈體，無名本自然。',48,'全唐诗/poet.song.83000.json','["有物含靈體，無名本自然。", "赤龍藏宇宙，白虎隱丹田。", "北斗南辰下，眉毛助睫邊。", "灰心行水火，定息見真鉛。"]'),
('7da45674-7fe3-42ef-a0bb-b30a72873cf9','還丹復命篇 五言十六首 其二','薛道光','宋','宋诗','song-poetry','','[]','精氣元無本，神靈共一家。',48,'全唐诗/poet.song.83000.json','["精氣元無本，神靈共一家。", "但能擒五賊，自可結三花。", "甲乙無令失，庚辛不要差。", "一陽歸正令，七返轉河車。"]'),
('8b17c8f7-2430-4050-be54-71892e1609e3','還丹復命篇 五言十六首 其三','薛道光','宋','宋诗','song-poetry','','[]','此事誠難測，賢愚總不分。',48,'全唐诗/poet.song.83000.json','["此事誠難測，賢愚總不分。", "雀應非鳳類，馬不入羊羣。", "㹀產都三百，乾坤共一斤。", "巡行十二路，赤脚猛將軍。"]'),
('0b55dabe-e3cf-4c7f-9bf4-d363dbfbc763','還丹復命篇 五言十六首 其四','薛道光','宋','宋诗','song-poetry','','[]','一二三四五，南辰對北辰。',48,'全唐诗/poet.song.83000.json','["一二三四五，南辰對北辰。", "虎龍含碧玉，金木孕珠珍。", "雲散家家月，花開處處春。", "幾多雲外客，盡是世間人。"]'),
('5715a9e5-93bb-4f1b-9874-b3366989ee2a','還丹復命篇 五言十六首 其五','薛道光','宋','宋诗','song-poetry','','[]','受得真仙訣，陰中鍊至陽。',48,'全唐诗/poet.song.83000.json','["受得真仙訣，陰中鍊至陽。", "地雷潛動處，星斗共商量。", "八卦看成母，三才始見昌。", "不愁生死繫，但覺地天長。"]'),
('63253de6-9b56-41d7-a2c4-17df7a65b7cd','還丹復命篇 五言十六首 其六','薛道光','宋','宋诗','song-poetry','','[]','古仙同一術，妙絕大幽深。',48,'全唐诗/poet.song.83000.json','["古仙同一術，妙絕大幽深。", "用意尋庚申，專心事丙壬。", "擒歸鳥與兔，捉取水和金。", "辨得東西物，修成不二心。"]'),
('213323e7-708e-4cf0-999c-664fc34e64d7','還丹復命篇 五言十六首 其七','薛道光','宋','宋诗','song-poetry','','[]','窈窕並姿態，嬌羞弄軟柔。',48,'全唐诗/poet.song.83000.json','["窈窕並姿態，嬌羞弄軟柔。", "無情弦裏取，魂魄土中收。", "笄冠聯鉛汞，靈光射斗牛。", "少陽陰與類，無使老春秋。"]'),
('93d23bb4-2287-4112-bf82-08eca0b34602','還丹復命篇 五言十六首 其八','薛道光','宋','宋诗','song-poetry','','[]','散誕無拘繫，翛然道轉高。',48,'全唐诗/poet.song.83000.json','["散誕無拘繫，翛然道轉高。", "妙中藏黑白，閑裏惡塵勞。", "坐臥三峰穩，丹田二氣牢。", "定知逃世網，名字列仙曹。"]'),
('db79bafd-d312-4b7a-b7fc-89131b700861','還丹復命篇 五言十六首 其九','薛道光','宋','宋诗','song-poetry','','[]','採取須教密，誠心辨醜妍。',48,'全唐诗/poet.song.83000.json','["採取須教密，誠心辨醜妍。", "事難尋意脈，容易失寒泉。", "師指青龍汞，配歸白虎鉛。", "兩般都會合，水火鍊經年。"]'),
('c6061c54-ba26-4fc5-9030-ae83a5b73587','還丹復命篇 五言十六首 其一○','薛道光','宋','宋诗','song-poetry','','[]','守一壇中要，機藏十二時。',48,'全唐诗/poet.song.83000.json','["守一壇中要，機藏十二時。", "數中無走失，火候莫教遲。", "達士方爲侶，真仙正合宜。", "幾年雲水上，懷抱有誰知。"]'),
('7a6a449b-87f3-4f50-b61a-ade6ccb53fd8','還丹復命篇 五言十六首 其一一','薛道光','宋','宋诗','song-poetry','','[]','人有最靈物，依稀在北辰。',48,'全唐诗/poet.song.83000.json','["人有最靈物，依稀在北辰。", "不知將謂氣，識後自然真。", "心凈如冰雪，身輕似碧雲。", "若無十萬歲，作甚世間人。"]'),
('250f9e9f-3df1-4334-8cfa-3e71f8a51167','還丹復命篇 五言十六首 其一二','薛道光','宋','宋诗','song-poetry','','[]','廛市通人處，明明與往還。',48,'全唐诗/poet.song.83000.json','["廛市通人處，明明與往還。", "悟來惟一物，昧處隔千山。", "神水丹田下，華池水火間。", "一元能造化，返老作童顔。"]'),
('b5b99f93-3a69-46a2-bb1a-06eb29aade0b','還丹復命篇 五言十六首 其一三','薛道光','宋','宋诗','song-poetry','','[]','巧拙仍藏伏，神精用意包。',48,'全唐诗/poet.song.83000.json','["巧拙仍藏伏，神精用意包。", "坎離或互用，金木喜相交。", "白雪能同鼎，黄芽共一包。", "乾坤推九六，復姤運初爻。"]'),
('6427cc5f-be25-4635-ad44-e3e02a06c755','還丹復命篇 五言十六首 其一四','薛道光','宋','宋诗','song-poetry','','[]','一物分爲二，能知二者名。',48,'全唐诗/poet.song.83000.json','["一物分爲二，能知二者名。", "鼎爐藏日月，漏滴已三更。", "夫婦同交媾，嬰兒始結成。", "脫胎並洗澤，攜養鎮長生。"]'),
('016d528f-a004-4474-bffe-8e7ee79e5567','還丹復命篇 五言十六首 其一五','薛道光','宋','宋诗','song-poetry','','[]','飲了靈丹藥，純陽自在人。',48,'全唐诗/poet.song.83000.json','["飲了靈丹藥，純陽自在人。", "洞明常寂照，蓬島鎮長春。", "去就渾無繫，縱世已絕塵。", "但知周甲子，不在守庚申。"]'),
('1dd7d916-4440-44e9-bdb9-875dafb82977','還丹復命篇 五言十六首 其一六','薛道光','宋','宋诗','song-poetry','','[]','訪道復尋真，優游四海賓。',48,'全唐诗/poet.song.83000.json','["訪道復尋真，優游四海賓。", "外多含忍辱，內省任邅迍。", "爲厭人間事，忻逢紫府賓。", "一言親點化，玉洞碧桃春。"]'),
('41308ec6-2f11-42a9-98fa-9ae8499ef055','還丹復命篇 七言三十首 其一','薛道光','宋','宋诗','song-poetry','','[]','萬物皆從一氣生，天清地濁稟生成。',32,'全唐诗/poet.song.83000.json','["萬物皆從一氣生，天清地濁稟生成。", "真龍真虎纔交媾，一鼎紅鉛鍊甲庚。"]'),
('fa1a5129-ec05-4f71-a69c-de26e3af2d36','還丹復命篇 七言三十首 其二','薛道光','宋','宋诗','song-poetry','','[]','陰陽配合法君臣，動靜相兼氣血精。',32,'全唐诗/poet.song.83000.json','["陰陽配合法君臣，動靜相兼氣血精。", "壬癸位中男擊浪，丙丁巖畔女嚬呻。"]'),
('b8c079fb-46fd-4077-8208-0854a2c1f038','還丹復命篇 七言三十首 其三','薛道光','宋','宋诗','song-poetry','','[]','龍虎一交相眷戀，坎離纔媾便成胎。',32,'全唐诗/poet.song.83000.json','["龍虎一交相眷戀，坎離纔媾便成胎。", "溶溶一掬乾坤髓，著意求他啜取來。"]'),
('db7d4e19-2de6-425f-8c6b-b87ce4959099','還丹復命篇 七言三十首 其四','薛道光','宋','宋诗','song-poetry','','[]','方以類聚物羣分，兩畔兩秤共一斤。',32,'全唐诗/poet.song.83000.json','["方以類聚物羣分，兩畔兩秤共一斤。", "戊己宮中藏水火，小心調理武和文。"]'),
('e9b2489d-13f0-4f70-9deb-f009e00a164f','還丹復命篇 七言三十首 其五','薛道光','宋','宋诗','song-poetry','','[]','離宮有象藏真水，坎戶無形隱赤龍。',32,'全唐诗/poet.song.83000.json','["離宮有象藏真水，坎戶無形隱赤龍。", "時節正時須急採，莫教芽蘖隘黄宮。"]'),
