('38832003-4cfd-4d2b-be6b-0c7b361d56c6','句','盛子充','宋','宋诗','song-poetry','','[]','竹筒牙籤日滿前，何妨心醉六經眠。',16,'全唐诗/poet.song.83000.json','["竹筒牙籤日滿前，何妨心醉六經眠。"]'),
('dc627473-40da-4c77-90bf-78ad14eb34af','滁州希真堂並蒂菊','梅執禮','宋','宋诗','song-poetry','','[]','前輩風流掃地空，秋香無復伍春紅。',64,'全唐诗/poet.song.83000.json','["前輩風流掃地空，秋香無復伍春紅。", "旋培數本當幽砌，忽作雙英滿翠叢。", "可但斷金私雨露，故應連璧傲霜風。", "得來稱瑞毋輕剪，留此甘棠壽醉翁。"]'),
('b546abc4-a6b0-4bd5-b17b-a15d78ba1331','宣和四年東陽梅某出守蘄州以五月十九日齋宿山谷黎明奉親朝謁真源萬壽宮少休五雲寺賦此','梅執禮','宋','宋诗','song-poetry','','[]','灊高夙所仰，妙想嗟未圓。',120,'全唐诗/poet.song.83000.json','["灊高夙所仰，妙想嗟未圓。", "邂逅一麾出，安輿奉華顛。", "駸駸涉勝境，獲締香火緣。", "徘徊慶基殿，稽首頌堯年。", "徐步俯松杪，幽尋值靈篇。", "軒窗散急雨，四座屯霏煙。", "向來玉京夢，了了墮目前。", "恍疑雞犬資，今在第幾天。", "平生修無怍，自視應得仙。", "孺子審可教，凡軀佇加鞭。"]'),
('494e0bad-a463-4dee-a162-dfd715143209','句','梅執禮','宋','宋诗','song-poetry','','[]','有令可干難閉戶，無人堪訪懶移舟。',16,'全唐诗/poet.song.83000.json','["有令可干難閉戶，無人堪訪懶移舟。"]'),
('faef8ac6-fef5-45c9-9d1a-5d419f7134dd','訪道者','杜崟','宋','宋诗','song-poetry','','[]','洞門深鎖白雲橫，旛影壇高夕照明。',32,'全唐诗/poet.song.83000.json','["洞門深鎖白雲橫，旛影壇高夕照明。", "落葉滿階人語寂，翩然野鶴啄棋枰。"]'),
('f1b03151-78f7-45b1-98e1-9dad714f9b44','題澹山巖','李公彥','宋','宋诗','song-poetry','','[]','地靈欲借一握天，神剜鬼劃無留堅。',160,'全唐诗/poet.song.83000.json','["地靈欲借一握天，神剜鬼劃無留堅。", "欻然豃豁空而圓，陽烏飛景光自穿。", "古藤繞石翠欲牽，石果垂結紛如拳。", "中有巖寶吐細泉，六月客坐寒入肩。", "昔聞修蟒何蜿蜒，誅茅判木不敢前。", "誰令結此殊勝緣，化作寶坊可棲禪。", "我非貴客來塵軿，訓狐挾狡聲亦先。", "飛上巖前枯樹顛，喚起山丁夜不眠。", "涪翁有筆大如椽，七字要與山俱傳。", "續貂顧我不著便，千古一笑夔憐蚿。"]'),
('25e9c854-32fe-46ef-bd0f-4420a671e84f','頌古四十首  其一','釋守珣','宋','宋诗','song-poetry','','[]','兜羅綿手指天地，紺目重瞳顧四維。',32,'全唐诗/poet.song.83000.json','["兜羅綿手指天地，紺目重瞳顧四維。", "七步周行渾屬我，一生賣弄小孩兒。"]'),
('d3228dfe-c4fb-457e-b1f3-ad793c1ee04b','頌古四十首  其二','釋守珣','宋','宋诗','song-poetry','','[]','瞿罷身心如泥，女子肝腸似鐵。',58,'全唐诗/poet.song.83000.json','["瞿罷身心如泥，女子肝腸似鐵。", "文殊貪尋鍋子，罔明由來著楔。", "歷觀大地衆生，不解閉門作活。", "不動干戈建太平，雨過青山如黛潑。"]'),
('4558a6f9-5574-4f46-bb67-9e335e780161','頌古四十首  其三','釋守珣','宋','宋诗','song-poetry','','[]','涅槃一路同來往，寸步寧虧達本鄉。',64,'全唐诗/poet.song.83000.json','["涅槃一路同來往，寸步寧虧達本鄉。", "鶖子黠兒輕借便，由如啞子喫生薑。", "月上女，太無良，不塗紅粉自風光。", "金鎖玄關留不住，百尺竿頭信脚行。"]'),
('6e47e9da-eec1-4754-a5a6-ccad63377b60','頌古四十首  其四','釋守珣','宋','宋诗','song-poetry','','[]','帝子遊春不逐他，相邀諸姊入屍陀。',56,'全唐诗/poet.song.83000.json','["帝子遊春不逐他，相邀諸姊入屍陀。", "死人堆裏出身路，撥動煙塵見也麽。", "靈利漢，不消多。", "回頭踏著自家底，洞雲深處舊煙蘿。"]'),
('17b4ac84-0106-456c-a2e5-115cc7715045','頌古四十首  其五','釋守珣','宋','宋诗','song-poetry','','[]','百萬人天普請看，頭陀末上獨開顔。',32,'全唐诗/poet.song.83000.json','["百萬人天普請看，頭陀末上獨開顔。", "堪笑衣穿瘦骨露，一肩授手搭金襴。"]'),
('736624eb-04bb-4601-9d96-23b07d2f91ad','頌古四十首  其六','釋守珣','宋','宋诗','song-poetry','','[]','難兄難弟問來端，百衲金襴遞代傳。',32,'全唐诗/poet.song.83000.json','["難兄難弟問來端，百衲金襴遞代傳。", "弟應兄呼成底事，免認剎竿頭指天。"]'),
('9d49502d-ef96-40c0-b749-d7fcd0242b7c','頌古四十首  其七','釋守珣','宋','宋诗','song-poetry','','[]','展陣開旗便要贏，誰知御駕不親征。',32,'全唐诗/poet.song.83000.json','["展陣開旗便要贏，誰知御駕不親征。", "把定鏘旗收陣脚，直向熊峰不出兵。"]'),
('4d89178d-eb47-4f92-8fb5-d3636c299995','頌古四十首  其八','釋守珣','宋','宋诗','song-poetry','','[]','三拜勤劬雪到腰，覓心無處強相饒。',32,'全唐诗/poet.song.83000.json','["三拜勤劬雪到腰，覓心無處強相饒。", "神光冷地思量著，始覺春來雪自消。"]'),
('0188eb3d-4395-4559-af0b-47a611b1752b','頌古四十首  其九','釋守珣','宋','宋诗','song-poetry','','[]','老大不堪用，約去了還來。',40,'全唐诗/poet.song.83000.json','["老大不堪用，約去了還來。", "伸腳縮腳裏，貪程啟快哉。", "有娘生面無爺姓，趁得曇華五葉開。"]'),
('40191d03-4b76-4d03-8bf6-7e56ff859a42','頌古四十首  其一○','釋守珣','宋','宋诗','song-poetry','','[]','不是風兮不是旛，幾人北斗面南看。',32,'全唐诗/poet.song.83000.json','["不是風兮不是旛，幾人北斗面南看。", "祖師直下無窼臼，眼綻皮穿較不難。"]'),
('44d3f88a-2515-463f-95c3-2907b4dc1fbe','頌古四十首  其一一','釋守珣','宋','宋诗','song-poetry','','[]','倚竈爲靈自不靈，靈蹤斷處一堆塵。',32,'全唐诗/poet.song.83000.json','["倚竈爲靈自不靈，靈蹤斷處一堆塵。", "野老不來敲祭鼓，打正因邪別是春。"]'),
('b92f427b-83da-4c06-88ff-9bb5731bf8e5','頌古四十首  其一二','釋守珣','宋','宋诗','song-poetry','','[]','坐禪成佛心中病，作鏡磨磚眼裏華。',52,'全唐诗/poet.song.83000.json','["坐禪成佛心中病，作鏡磨磚眼裏華。", "一掣牢關金鎖斷，等閑信步便歸家。", "馬駒子，實堪誇。", "自從胡亂後，著處是生涯。"]'),
('a0c14b49-23d7-4ae2-a143-dafd0edd05d0','頌古四十首  其一三','釋守珣','宋','宋诗','song-poetry','','[]','廬陵米價若爲酬，入市知行趣自由。',32,'全唐诗/poet.song.83000.json','["廬陵米價若爲酬，入市知行趣自由。", "借問年來何所直，大宋山河四百州。"]'),
('f46341ba-cde5-459f-8310-0282cab29a7a','頌古四十首  其一四','釋守珣','宋','宋诗','song-poetry','','[]','即心是佛一家風，馬祖聲傳四海中。',32,'全唐诗/poet.song.83000.json','["即心是佛一家風，馬祖聲傳四海中。", "靈利衲僧纔一顧，娘生賦性出天聰。"]'),
('af3bfb14-0615-49bd-82cf-d676078ee782','頌古四十首  其一五','釋守珣','宋','宋诗','song-poetry','','[]','近日尊位復如何，日面月面哩來囉。',32,'全唐诗/poet.song.83000.json','["近日尊位復如何，日面月面哩來囉。", "自從舞得三臺後，拍拍元來總是歌。"]'),
('ba01308b-0ff6-4ba1-8e87-d18d494a6958','頌古四十首  其一六','釋守珣','宋','宋诗','song-poetry','','[]','野鴨羣飛勢莫留，瞥然一過已高秋。',32,'全唐诗/poet.song.83000.json','["野鴨羣飛勢莫留，瞥然一過已高秋。", "和聲搊著平生痛，短綆毋勞繫鼻頭。"]'),
('2be03b09-1cdf-4556-a192-c0ca5885c36d','頌古四十首  其一七','釋守珣','宋','宋诗','song-poetry','','[]','安國安家不在兵，魯連一箭亦多情。',32,'全唐诗/poet.song.83000.json','["安國安家不在兵，魯連一箭亦多情。", "三千劍客今何在，獨許將軍建太平。"]'),
('e2eb844b-ebe5-491c-9e6c-857fb2190bb5','頌古四十首  其一八','釋守珣','宋','宋诗','song-poetry','','[]','要得貍奴覿面酬，渾如鉗口鎖咽喉。',32,'全唐诗/poet.song.83000.json','["要得貍奴覿面酬，渾如鉗口鎖咽喉。", "一刀兩段從公斷，直得悲風動地愁。"]'),
('f67fe7fa-08f1-4394-87ea-f1efbc9a4cd6','頌古四十首  其一九','釋守珣','宋','宋诗','song-poetry','','[]','犀牛扇子用多年，歷掌清機授手傳。',32,'全唐诗/poet.song.83000.json','["犀牛扇子用多年，歷掌清機授手傳。", "頭角不全收拾取，雨餘風月滿長川。"]'),
('7f41157f-5cd3-4541-aad3-02f84dc783b5','頌古四十首  其二○','釋守珣','宋','宋诗','song-poetry','','[]','紅輪決定沉西去，未委魂靈往那方。',56,'全唐诗/poet.song.83000.json','["紅輪決定沉西去，未委魂靈往那方。", "踏得故鄉田地穩，本來面目露堂堂。", "人只在，不曾亡。", "率陀天上非人世，須知別有好商量。"]'),
('24f131fd-1c5a-4be4-b532-0feb84011d5b','頌古四十首  其二一','釋守珣','宋','宋诗','song-poetry','','[]','貪觀天上月，失卻手中橈。',36,'全唐诗/poet.song.83000.json','["貪觀天上月，失卻手中橈。", "石臼山下路，歸計轉迢遙。", "覿面光輝日，拍手笑吾曹。"]'),
('c03f353c-4722-46f0-8a00-55fa49ad286f','頌古四十首  其二二','釋守珣','宋','宋诗','song-poetry','','[]','老倒丹霞燒木佛，院主眉鬚剛突出。',32,'全唐诗/poet.song.83000.json','["老倒丹霞燒木佛，院主眉鬚剛突出。", "罪過從來作底當，誰道千虛不博實。"]'),
('b004f9dc-c041-4c04-b19a-6545e7544e74','頌古四十首  其二三','釋守珣','宋','宋诗','song-poetry','','[]','三種佳名一箇過，邀君把手上高坡。',32,'全唐诗/poet.song.83000.json','["三種佳名一箇過，邀君把手上高坡。", "時人自沒登山力，空負當年一曲歌。"]'),
('5ba4928d-72b2-4f16-954f-27ccda7b0113','頌古四十首  其二四','釋守珣','宋','宋诗','song-poetry','','[]','連天野火了無涯，起處猶來辨作家。',56,'全唐诗/poet.song.83000.json','["連天野火了無涯，起處猶來辨作家。", "眼裏瞳人雙翳盡，面前遍界絕空華。", "道吾老，也堪誇。", "汲水僧歸林下寺，待船人立渡頭沙。"]'),
('1250a4b2-d099-4721-8f72-60254032da1a','頌古四十首  其二五','釋守珣','宋','宋诗','song-poetry','','[]','孰云天地與同根，事角爭如理見親。',60,'全唐诗/poet.song.83000.json','["孰云天地與同根，事角爭如理見親。", "一檻庭花渾己物，滿天風月與誰論。", "堪笑南泉老作，猶來因語識人。", "可憐陸亘大夫，對面埋沒家珍。"]'),
('5739dbc3-9116-4da5-846f-c1072546d777','頌古四十首  其二六','釋守珣','宋','宋诗','song-poetry','','[]','青青庭柏指西來，趙老門風八字開。',32,'全唐诗/poet.song.83000.json','["青青庭柏指西來，趙老門風八字開。", "歲寒枝有深深意，誰把靈根著處栽。"]'),
('cd0195df-9658-4e4a-88e1-0895a98b8e16','頌古四十首  其二七','釋守珣','宋','宋诗','song-poetry','','[]','張公末醉李公扶，從此嘉聲滿道途。',32,'全唐诗/poet.song.83000.json','["張公末醉李公扶，從此嘉聲滿道途。", "卻被金剛開口笑，誰能愛你護身符。"]'),
('c5436e9e-c209-48f9-9e40-d282dae8e5f4','頌古四十首  其二八','釋守珣','宋','宋诗','song-poetry','','[]','見成公案便相當，秤則稱兮斗則量。',32,'全唐诗/poet.song.83000.json','["見成公案便相當，秤則稱兮斗則量。", "非較非年三十棒，至今平步也翱翔。"]'),
('044ad659-ef4e-4197-96bb-7246b063c2e5','頌古四十首  其二九','釋守珣','宋','宋诗','song-poetry','','[]','終日看天不舉頭，桃花爛熳始擡眸。',32,'全唐诗/poet.song.83000.json','["終日看天不舉頭，桃花爛熳始擡眸。", "饒君便有遮天網，到得牢關即便休。"]'),
('4953cfa4-0fc0-4cfb-bbd2-db139d267605','頌古四十首  其三○','釋守珣','宋','宋诗','song-poetry','','[]','無寒暑處洞山語，多少禪人迷處所。',32,'全唐诗/poet.song.83000.json','["無寒暑處洞山語，多少禪人迷處所。", "寒時向火熱乘涼，一生免得避寒暑。"]'),
('c6872a05-eaa1-4bc1-9cc0-e428bad4f06a','頌古四十首  其三一','釋守珣','宋','宋诗','song-poetry','','[]','捲則渾崙無縫，舒則八面生光。',52,'全唐诗/poet.song.83000.json','["捲則渾崙無縫，舒則八面生光。", "百千諸佛，同處一方。", "轉機輪於掌握，奮大用於當場。", "非獨三十年後，面前薝蔔馨香。"]'),
('48cf7dc6-4a90-4622-b9df-fbae19dde073','頌古四十首  其三二','釋守珣','宋','宋诗','song-poetry','','[]','殘羹餿飯，無處安著。',34,'全唐诗/poet.song.83000.json','["殘羹餿飯，無處安著。", "換手搥胸，劈頭蓋卻。", "兩箇無孔鐵槌，一樣無繩自縛。"]'),
('c0bb6d0d-2c39-47a2-af85-aefb5cdc0a7a','頌古四十首  其三三','釋守珣','宋','宋诗','song-poetry','','[]','發足超方，地頭親到。',56,'全唐诗/poet.song.83000.json','["發足超方，地頭親到。", "遇著險峻道途，殺活杖子變豹。", "米倉大路平如砥，未免漆桶裏著到。", "不搽紅粉也風流，大抵還他肌骨好。"]'),
('79160f3d-31ea-47fa-a9f6-73417d99dbfb','頌古四十首  其三四','釋守珣','宋','宋诗','song-poetry','','[]','無孔笛子兩頭吹，韻出青霄徹九維。',32,'全唐诗/poet.song.83000.json','["無孔笛子兩頭吹，韻出青霄徹九維。", "可憐一對冤家種，人人鼻孔大頭垂。"]'),
('83db2a51-dc7e-4db8-87a1-4437bcf20bf7','頌古四十首  其三五','釋守珣','宋','宋诗','song-poetry','','[]','雲門餬餅對超談，多少禪流看不穿。',32,'全唐诗/poet.song.83000.json','["雲門餬餅對超談，多少禪流看不穿。", "若是孔門真弟子，自然知道化三千。"]'),
('667f820d-efca-4665-aae1-f26708bf71c0','頌古四十首  其三六','釋守珣','宋','宋诗','song-poetry','','[]','問佛唯言乾屎橛，非獨抽釘兼拔楔。',32,'全唐诗/poet.song.83000.json','["問佛唯言乾屎橛，非獨抽釘兼拔楔。", "不是韶陽老古錐，爭得親言出親舌。"]'),
('6e5d56c4-9cc4-4c76-9b2e-13826771a67d','頌古四十首  其三七','釋守珣','宋','宋诗','song-poetry','','[]','鼠既不靈，官馬相踏。',36,'全唐诗/poet.song.83000.json','["鼠既不靈，官馬相踏。", "借使乘風，廝挨廝拶。", "干戈中立太平基，凜凜嘉聲振蘭若。"]'),
('6af536ba-de02-4224-8893-9b2389c6a9a1','頌古四十首  其三八','釋守珣','宋','宋诗','song-poetry','','[]','借婆裙子拜婆朝，問佛唯言汝惠超。',32,'全唐诗/poet.song.83000.json','["借婆裙子拜婆朝，問佛唯言汝惠超。", "萬古石頭城下水，終歸大海作波濤。"]'),
('061c41b3-03cb-4021-bdac-aec0eccba439','頌古四十首  其三九','釋守珣','宋','宋诗','song-poetry','','[]','泥水未分紅菡萏，雨餘先透碧波香。',32,'全唐诗/poet.song.83000.json','["泥水未分紅菡萏，雨餘先透碧波香。", "千般意路終難會，一著歸根便廝當。"]'),
('828fe48a-cb6a-4129-875b-bdb7946c762c','頌古四十首  其四○','釋守珣','宋','宋诗','song-poetry','','[]','問處分明答處親，青峰八字打開門。',32,'全唐诗/poet.song.83000.json','["問處分明答處親，青峰八字打開門。", "頭頭盡是吾家物，何必臨歧更問津。"]'),
('2f73faed-06a0-4cf3-8709-c964255f253e','偈二首  其一','釋守珣','宋','宋诗','song-poetry','','[]','𨍏轢鑽，住山斧，佛祖出頭未輕與。',58,'全唐诗/poet.song.83000.json','["𨍏轢鑽，住山斧，佛祖出頭未輕與。", "縱使醍醐滿世間，你無寶器如何取。", "阿呵呵，神山打羅，道吾作舞。", "甜甜徹蒂甜，苦瓠連根苦。"]'),
('c69a5f8d-06c0-4997-8906-053cb1f06524','偈二首  其二','釋守珣','宋','宋诗','song-poetry','','[]','如來禪，祖師道，切忌將心外邊討。',106,'全唐诗/poet.song.83000.json','["如來禪，祖師道，切忌將心外邊討。", "從門所得即非珍，特地埋藏衣裏寶。", "禪家流，須及早，撥動祖師關捩，抖擻多年布襖。", "是非毀譽付之空，竪闊橫長渾恰好。", "君不見寒山老，終日嬉嬉，長年把掃。", "人問其中事若何，入荒田不揀信手拈來草。"]'),
('414a4de1-03fd-4c09-8fbd-63916a0fcbca','次（毛友）玉晨鑒義真公見訪韻','翁彥深','宋','宋诗','song-poetry','','[]','聞道三茅五洞門，翛然來往御風仙。',64,'全唐诗/poet.song.83000.json','["聞道三茅五洞門，翛然來往御風仙。", "雲深騏驥那容步，松古龜蛇莫問年。", "邂逅江頭披霧語，尋思巖畔枕流眠。", "自憐天柱曾孫老，句曲清游合有緣。"]'),
('aa01ff3d-f25a-4edf-8803-a62aa4a64afd','聞馬擴參議棄官  其一','王次翁','宋','宋诗','song-poetry','','[]','徙薪曲突論無憑，太尉山中混耦耕。',32,'全唐诗/poet.song.83000.json','["徙薪曲突論無憑，太尉山中混耦耕。", "頭額爛焦曾未錄，參謀先已享專城。"]'),
('53a2b126-9b89-4001-be95-a2003e6630b0','聞馬擴參議棄官  其二','王次翁','宋','宋诗','song-poetry','','[]','近來出處事何如，先輩風流掃地無。',32,'全唐诗/poet.song.83000.json','["近來出處事何如，先輩風流掃地無。", "忽有子充驚末俗，一言未契便長驅。"]'),
('3b73a3a0-175e-4959-951f-020dcdb5af76','偈  其一','釋善果','宋','宋诗','song-poetry','','[]','冰壺雪室坐禪時，世事紛紜莫可知。',32,'全唐诗/poet.song.83000.json','["冰壺雪室坐禪時，世事紛紜莫可知。", "仰羨一堂雲水客，忘機寂默是便宜。"]'),
('efbbaf56-323b-462b-af0a-7baacb263a75','偈  其二','釋善果','宋','宋诗','song-poetry','','[]','韶陽一曲二十五，不屬宮商角徵羽。',32,'全唐诗/poet.song.83000.json','["韶陽一曲二十五，不屬宮商角徵羽。", "寥寥千古共誰論，明眼衲僧未輕許。"]'),
('6c5377da-d41a-4a14-9915-50d49facba3b','偈  其三','釋善果','宋','宋诗','song-poetry','','[]','松風清，霜月白。',40,'全唐诗/poet.song.83000.json','["松風清，霜月白。", "妙應無私，靈光烜赫。", "不用思量，何須揀擇。", "一句定乾坤，千古爲標格。"]'),
('9d8bf5f7-b16b-4674-bc60-bb69e2965ed4','偈  其四','釋善果','宋','宋诗','song-poetry','','[]','德山棒，臨濟喝，不是橫該與竪抹。',64,'全唐诗/poet.song.83000.json','["德山棒，臨濟喝，不是橫該與竪抹。", "拈來直下要承當，透網金鱗活鱍鱍。", "活鱍鱍，任人看，碧天雲靜冷光寒。", "行行莫謂知音少，佛祖總在一亳端。"]'),
('3d2e7839-9509-4e87-9232-5a5ef62791a8','偈  其五','釋善果','宋','宋诗','song-poetry','','[]','蘇州有，常州有，吸盡西江只一口。',48,'全唐诗/poet.song.83000.json','["蘇州有，常州有，吸盡西江只一口。", "百八數珠數不盡，須知天長與地久。", "騰今煥古作嘉祥，一一面南看北斗。"]'),
('bdafe63b-0d4b-4f6b-a95c-bb82fc50e000','偈  其六','釋善果','宋','宋诗','song-poetry','','[]','鴉鳴鵲噪爲祥瑞，明月清風作近鄰。',32,'全唐诗/poet.song.83000.json','["鴉鳴鵲噪爲祥瑞，明月清風作近鄰。", "入座笑談欣亹亹，怡然世外兩閑人。"]'),
('9e5eb1f1-4c8d-45b8-82f5-71c2eb604d81','偈  其七','釋善果','宋','宋诗','song-poetry','','[]','數日霶沱大雨，元來不落別處。',44,'全唐诗/poet.song.83000.json','["數日霶沱大雨，元來不落別處。", "滴穿釋迦鼻孔，浸爛彌勒眼睛。", "溪澗豈能魚得住，終歸大海作波濤。"]'),
('7f61451f-26a0-4ac6-9573-33362566ce49','偈  其八','釋善果','宋','宋诗','song-poetry','','[]','九夏光陰一瞬間，休論城市與深山。',32,'全唐诗/poet.song.83000.json','["九夏光陰一瞬間，休論城市與深山。", "大圓覺是安居處，坐斷毗盧境界寬。"]'),
('99921b61-ed44-4d21-ad50-b8e911048d0f','偈  其九','釋善果','宋','宋诗','song-poetry','','[]','桃花紅，李花白，萬壑千巖光烜赫。',43,'全唐诗/poet.song.83000.json','["桃花紅，李花白，萬壑千巖光烜赫。", "靈雲悟處勿遮藏，賢沙正是白拈賊。", "賊賊，說甚釋迦與彌勒。"]'),
('ef0ae813-7421-480c-a7c3-71d0e9a65b04','偈  其一○','釋善果','宋','宋诗','song-poetry','','[]','是法不可示，言詞相寂滅。',24,'全唐诗/poet.song.83000.json','["是法不可示，言詞相寂滅。", "擊破太虛空，萬里一條鐵。"]'),
('d3f87ab6-1224-4371-998c-7308d36f89fd','偈  其一一','釋善果','宋','宋诗','song-poetry','','[]','心生法亦生，心滅法亦滅。',24,'全唐诗/poet.song.83000.json','["心生法亦生，心滅法亦滅。", "心法兩俱忘，烏龜喚作鼈。"]'),
('614998eb-2d9b-443c-ba10-17790b2565b7','虜中作三首  其一','宇文虛中','宋','宋诗','song-poetry','','[]','滿腹詩書漫古今，頻年流落易傷心。',64,'全唐诗/poet.song.83000.json','["滿腹詩書漫古今，頻年流落易傷心。", "南冠終日囚車府，北雁何時到上林。", "開口摧頹空抱璞，脅肩奔走尚腰金。", "莫邪利劍今安在，不斬姦邪恨最深。"]'),
('a2d8f510-ed66-44f6-98b1-9941debdba30','虜中作三首  其二','宇文虛中','宋','宋诗','song-poetry','','[]','遙夜沈沈滿幕霜，有時歸夢到家鄉。',64,'全唐诗/poet.song.83000.json','["遙夜沈沈滿幕霜，有時歸夢到家鄉。", "傳聞已筑西河館，自許能肥北海羊。", "回首兩朝俱草莽，馳心萬里絕農桑。", "人生一死渾閑事，裂眥穿胸不汝忘。"]'),
('dc6c634a-aa4a-4cf3-95a2-0534021e4a3d','虜中作三首  其三','宇文虛中','宋','宋诗','song-poetry','','[]','不堪垂老尚蹉跎，有口無辭可奈何。',64,'全唐诗/poet.song.83000.json','["不堪垂老尚蹉跎，有口無辭可奈何。", "強食小兒猶解事，學妝嬌女最憐他。", "故衾愧見霑秋雨，短褐寧忘拆海波。", "倚仗循環如可待，未愁來日苦無多。"]'),
('2e02c2c0-5714-4d5f-98ba-ce45948c6251','鄭下趙光道與余有十五年家世之舊守官代郡之崞縣聞余以使事羈留平城與諸公相從皆一時英彥遂以應舉自免去駕短轅下澤車驅一僮二驢扶病以來相聚凡旬日而歸昔白樂天與元微之偶相遇於夷陵峽口既而作詩敘別雖憔悴哀傷感念存沒至歎泣不能自已而終篇之意蓋亦自開慰况吾輩今日可無片言以識一時之事邪因各題數句而余爲之敘夜將半各有酒所語不復鍛鍊要之皆肺腑中流出也','宇文虛中','宋','宋诗','song-poetry','','[]','窮愁詩滿篋，孤憤氣填胸。',72,'全唐诗/poet.song.83000.json','["窮愁詩滿篋，孤憤氣填胸。", "脱身枳棘下，顧我雪窖中。", "竟日朋盍簪，論文一樽同。", "飜然南飛燕，卻背北歸鴻。", "人生悲與樂，倚伏如張弓。", "莫言竟憒憒，作書怨天公。"]'),
('aef1b25b-8d2a-4f99-98ff-f4665adabc4f','古劍行','宇文虛中','宋','宋诗','song-poetry','','[]','公家祖皇提三尺，素靈中斷開王迹。',128,'全唐诗/poet.song.83000.json','["公家祖皇提三尺，素靈中斷開王迹。", "自從武庫衝屋飛，化作文星照東壁。", "夫君安得此龍泉，秋水湛湛浮青天。", "夔魖奔喘禺強護，中夜躍出光蜿蜒。", "拄頤櫑具男兒飾，彈鋏長歌氣填臆。", "嶙峋折檻霽天威，將軍拜伏姦臣泣。", "龍泉爾莫矜雄鋩，不見鳥盡良弓藏。", "會當鑄汝爲農器，一劍不如書數行。"]'),
('a4a4554d-516f-41cc-bf41-e60a08f84f47','白菊','宇文虛中','宋','宋诗','song-poetry','','[]','西風蕭颯百草黄，南齋白菊占秋芳。',128,'全唐诗/poet.song.83000.json','["西風蕭颯百草黄，南齋白菊占秋芳。", "主人好事不專饗，擷送客館分幽香。", "幽香清豔兩難得，冰雪肌膚龍麝裛。", "悄然坐我蘂珠宫，玉斧瑤姬皆舊識。", "仙家蓻菊名日精，我今號爾爲月英。", "月中風露秋夕好，感此仙種來曾城。", "憑君傳與金天令，月與霜姿駐清景。", "重陽好伴白衣來，五柳先生憶三逕。"]'),
('71bda4ae-a4cc-4eab-9eec-64524c6c87c7','還舍作','宇文虛中','宋','宋诗','song-poetry','','[]','燕山歸來頭已白，自笑客中仍作客。',64,'全唐诗/poet.song.83000.json','["燕山歸來頭已白，自笑客中仍作客。", "此生悲歡不可料，况復吾年過半百。", "故人驚我酒尚狂，爲洗缾罍貯春色。", "酒闌人散月盈庭，静聽清渠流㶁㶁。"]'),
('37b78084-3eca-45a6-88a1-e5dc65d4e605','庭下養三鴛鴦忽去不反戲爲作詩','宇文虛中','宋','宋诗','song-poetry','','[]','先生久忘機，爲爾虞矰繳。',48,'全唐诗/poet.song.83000.json','["先生久忘機，爲爾虞矰繳。", "一朝長羽翮，萬里翔寥廓。", "誰信惡溝鴟，忽作華表鶴。", "豈無三玉環，遺音嗣黄雀。"]'),
('f1002cfd-1ce6-4ae4-9030-cb5d566919be','予寫金剛經與王正道正道與朱少章復以詩來輒次二公韻  其一','宇文虛中','宋','宋诗','song-poetry','','[]','平生幸識繫珠衣，窮走他鄉未得歸。',64,'全唐诗/poet.song.83000.json','["平生幸識繫珠衣，窮走他鄉未得歸。", "有客爲傳祗樹法，此心便息漢陰機。", "百千三昩一門入，四十九年諸事非。", "寄與香山老居士，要憑二義發餘輝。"]'),
('b0e60b68-2857-46c3-aa46-62731ca54d35','予寫金剛經與王正道正道與朱少章復以詩來輒次二公韻  其二','宇文虛中','宋','宋诗','song-poetry','','[]','前世曾爲粥飯僧，此生隨處且騰騰。',64,'全唐诗/poet.song.83000.json','["前世曾爲粥飯僧，此生隨處且騰騰。", "經中因認人我相，教外都忘大小乘。", "寫去欲云居士頌，信來如續祖師燈。", "他年辱贈茅庵句，誰謂因緣昔未曾。"]'),
('5588a247-66b1-400f-b40b-7140324bc3fa','郊居','宇文虛中','宋','宋诗','song-poetry','','[]','芒屨松冠野外装，茶鐺藥竈静中忙。',64,'全唐诗/poet.song.83000.json','["芒屨松冠野外装，茶鐺藥竈静中忙。", "含風荇逐波紋展，著雨花連土氣香。", "停策仰簷朝覓句，披襟穿樹晚追涼。", "蓬蒿似欲荒三逕，疏懶誰知意更長。"]'),
('9b96c7eb-49bc-4717-8db9-ab89640d8f9e','歳寒堂','宇文虛中','宋','宋诗','song-poetry','','[]','洞戶延清吹，庭除貯綠陰。',48,'全唐诗/poet.song.83000.json','["洞戶延清吹，庭除貯綠陰。", "不隨風月媚，肯受雪霜侵。", "潤入珠泉爽，聲傳玉帳深。", "主人留勝賞，同此歲寒心。"]'),
('1e3bafc1-592f-4e72-aee5-cc24b9567907','重陽旅中偶記二十年前二詩因而有作','宇文虛中','宋','宋诗','song-poetry','','[]','舊日重陽厭旅裝，而今身世更悲凉。',64,'全唐诗/poet.song.83000.json','["舊日重陽厭旅裝，而今身世更悲凉。", "愁添白髪先春雪，淚著黄花助晚霜。", "客館病餘紅日短，家山信斷碧雲長。", "故人不恨村醪薄，乘興能來共一觴。"]'),
('bdcc5480-e77d-48e6-b74e-e4b111d148ff','春日','宇文虛中','宋','宋诗','song-poetry','','[]','北洹春事休嗟晚，三月尚寒花信風。',32,'全唐诗/poet.song.83000.json','["北洹春事休嗟晚，三月尚寒花信風。", "遙憶東吳此時節，滿江鴨綠弄殘紅。"]'),
('adc0032d-01bb-497d-970a-cdb2f9c7f92d','己丑重陽在劍門梁山鋪','宇文虛中','宋','宋诗','song-poetry','','[]','兩年重九皆羈旅，萬水千山厭遠遊。',64,'全唐诗/poet.song.83000.json','["兩年重九皆羈旅，萬水千山厭遠遊。", "白酒黄花聊度日，青萍綠綺共忘憂。", "却憐風雨梁山路，不似蓴鱸楚澤秋。", "何必東臯是三逕，此身天地一虚舟。"]'),
('143805ff-3242-42f5-b1dc-6f40836f8d06','生日和甫同諸公載酒袖詩爲禮感佩之餘以詩爲謝','宇文虛中','宋','宋诗','song-poetry','','[]','詞人詩句壓離騷，按膝長吟意自豪。',64,'全唐诗/poet.song.83000.json','["詞人詩句壓離騷，按膝長吟意自豪。", "袖裏虹蜺衝霽色，筆端風雨駕雲濤。", "將衰難稱千年祝，增重虚蒙隻字褒。", "太史已應飛急奏，文星偏傍使星高。"]'),
('655a8c95-3715-4dbb-bef9-2860a2c59f46','和題稽古軒','宇文虛中','宋','宋诗','song-poetry','','[]','堆架縑緗粲蔀居，眼前長物埽無餘。',64,'全唐诗/poet.song.83000.json','["堆架縑緗粲蔀居，眼前長物埽無餘。", "避囂肯要鄰人卜，論友先尋上世書。", "汲古不須憂綆短，隨波聊復任舟虚。", "勿欺文室纔容膝，六合神游有日車。"]'),
('dfe08cb4-a455-4483-a7b5-e98d995fbee6','己酉歳書懷','宇文虛中','宋','宋诗','song-poetry','','[]','去國匆匆遂隔年，公私無益兩茫然。',64,'全唐诗/poet.song.83000.json','["去國匆匆遂隔年，公私無益兩茫然。", "當時議論不能固，今日窮愁何足憐。", "生死已從前世定，是非留與後人傳。", "孤臣不爲沈湘恨，悵望三韓別有天。"]'),
('34b5f572-1cdd-4cd0-a2f5-5d7f813c98cc','涇王許以酒餉龍溪老人幾月不至以詩促之','宇文虛中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','先生寂莫草玄文，正要侯芭作富鄰。',64,'全唐诗/poet.song.83000.json','["先生寂莫草玄文，正要侯芭作富鄰。", "客至但須樽有酒，日高不怕甑生塵。", "急催嶺外傳梅使，來餉籬邊采菊人。", "已埽明窗供點筆，爲君擬賦洞庭春。"]'),
('c7037557-c189-4afb-93f7-fccca33f8a52','從人借琴','宇文虛中','宋','宋诗','song-poetry','','[]','嶧陽慣聽鳳雛鳴，瀉出泠然萬籟聲。',64,'全唐诗/poet.song.83000.json','["嶧陽慣聽鳳雛鳴，瀉出泠然萬籟聲。", "已厭笙簧非雅曲，幸從炊爨脱餘生。", "昭文不鼓緣何意，靖節無絃且寄情。", "乞與南冠囚縶客，爲君一奏變春榮。"]'),
('33c2d419-351e-4aa2-aa21-ab9d4a7c48f8','過居庸關','宇文虛中','宋','宋诗','song-poetry','','[]','奔峭從天拆，懸流赴壑清。',48,'全唐诗/poet.song.83000.json','["奔峭從天拆，懸流赴壑清。", "路回穿石細，崖裂與藤爭。", "花已從南發，人今又北行。", "節旄都落盡，奔走愧平生。"]'),
('5caa2c3d-5358-4095-a0f0-f0ff070c91ce','晚宿耀武關','宇文虛中','宋','宋诗','song-poetry','','[]','山與烟雲暝，溪兼冰雪流。',48,'全唐诗/poet.song.83000.json','["山與烟雲暝，溪兼冰雪流。", "寒枝啼秸鞠，煬室聚咿嚘。", "此日征行困，何時喪亂休。", "尚矜爭席好，無復舊鳴騶。"]'),
('4baead21-7dd6-4cb6-b1bc-50955e64aa62','安定道中','宇文虛中','宋','宋诗','song-poetry','','[]','落日塵埃壯，陰風天地昏。',48,'全唐诗/poet.song.83000.json','["落日塵埃壯，陰風天地昏。", "牛羊爭隘道，鳥雀聚空村。", "跛曳傷行役，光華誤主恩。", "未甘遲莫景，伏櫪意猶存。"]'),
('758c0a67-2afb-4752-93b0-a0b4c8d58538','上烏林天使三首  其一','宇文虛中','宋','宋诗','song-poetry','','[]','平生隨牒浪推移，只爲生民不爲私。',64,'全唐诗/poet.song.83000.json','["平生隨牒浪推移，只爲生民不爲私。", "萬里翠輿猶遠播，一身幽圄敢終辭。", "魯人除館西河外，漢使驅羊北海湄。", "不是故人高議切，肯來軍府問鍾儀。"]'),
('5084404e-8415-4c74-b14d-44674e427432','上烏林天使三首  其二','宇文虛中','宋','宋诗','song-poetry','','[]','拭玉轅門吐寸誠，敢將緩頰沮天兵。',64,'全唐诗/poet.song.83000.json','["拭玉轅門吐寸誠，敢將緩頰沮天兵。", "雷霆儻肯矜彫弊，草芥何須計死生。", "定鼎未應周命改，登壇合許趙人平。", "知君妙有經邦策，存取威懷萬世名。"]'),
('fe76eaaf-9e6b-47d4-b6c3-33dc855f831d','上烏林天使三首  其三','宇文虛中','宋','宋诗','song-poetry','','[]','當時初結兩朝歡，曾見軍前捧血槃。',64,'全唐诗/poet.song.83000.json','["當時初結兩朝歡，曾見軍前捧血槃。", "本爲萬年依蔭厚，那知一日遽盟寒。", "羊牽已作俘囚獻，魚漏終期網罟寛。", "幸有故人知底藴，下臣獲考敢謀安。"]'),
('6a635cf9-d578-4088-8a1f-24bae859b24e','姑蘇滕惇禮榜所居閣曰齋心成都宇文某作詩以廣其意','宇文虛中','宋','宋诗','song-poetry','','[]','不是憑虚避世喧，此中於物本無緣。',64,'全唐诗/poet.song.83000.json','["不是憑虚避世喧，此中於物本無緣。", "静看畏影徒勞爾，題作齋心亦且然。", "意識已隨言語斷，生涯聊任歲時遷。", "老夫亦涉天游趣，三復南華第四篇。"]'),
('6e36f24e-15ae-4613-a003-760f21b697fc','和高子文秋興二首  其一','宇文虛中','宋','宋诗','song-poetry','','[]','沙碧平猶漲，霜紅粉已多。',48,'全唐诗/poet.song.83000.json','["沙碧平猶漲，霜紅粉已多。", "駒年驚過隙，鳬影倦隨波。", "散步雙扶老，棲身一養和。", "羞看使者節，甘荷牧人蓑。"]'),
('d0bda20a-2c51-4580-9fab-fce33652f025','和高子文秋興二首  其二','宇文虛中','宋','宋诗','song-poetry','','[]','搖落山城莫，棲遲客館幽。',48,'全唐诗/poet.song.83000.json','["搖落山城莫，棲遲客館幽。", "葵衰前日雨，菊老異鄉秋。", "自信浮沈數，仍懷顧望愁。", "蜀江歸棹在，浩蕩逐春鷗。"]'),
('8a68a586-5095-4db0-b21c-754f5ff138f1','又和九日','宇文虛中','宋','宋诗','song-poetry','','[]','老畏年光短，愁隨秋色來。',48,'全唐诗/poet.song.83000.json','["老畏年光短，愁隨秋色來。", "一持旌節出，五見菊花開。", "強忍玄猿淚，聊浮綠蟻杯。", "不堪南向望，故國又叢臺。"]'),
('36ea4fe4-cf48-454b-aab2-69138a349801','中秋覓酒','宇文虛中','宋','宋诗','song-poetry','','[]','今夜家家月，臨筵照綺樓。',48,'全唐诗/poet.song.83000.json','["今夜家家月，臨筵照綺樓。", "那知孤館客，獨抱故鄉愁。", "感激時難遇，謳吟意未休。", "應分千斛酒，來洗百年憂。"]'),
('53b9cbcc-33a8-43d4-9a7e-88de9a2965e5','四序回文十二首 春 其一','宇文虛中','宋','宋诗','song-poetry','','[]','短草鋪茸綠，殘紅照雪稀。',24,'全唐诗/poet.song.83000.json','["短草鋪茸綠，殘紅照雪稀。", "暖輕還錦褥，寒峭怯羅衣。"]'),
('bce51590-7b92-4126-a86c-a25cc98350c9','四序回文十二首 春 其二','宇文虛中','宋','宋诗','song-poetry','','[]','翠漣冰綻日，香徑晚多花。',24,'全唐诗/poet.song.83000.json','["翠漣冰綻日，香徑晚多花。", "細筍抽蒲密，長條舞柳斜。"]'),
('84de94dd-9f79-47ac-b615-220a96c261c1','四序回文十二首 春 其三','宇文虛中','宋','宋诗','song-poetry','','[]','折花幽檻小，傾酒綠杯深。',24,'全唐诗/poet.song.83000.json','["折花幽檻小，傾酒綠杯深。", "蝶舞輕風曉，鶯啼老樹陰。"]'),
('01376497-cdda-48e4-b1ef-960c189f6c6b','四序回文十二首 夏 其一','宇文虛中','宋','宋诗','song-poetry','','[]','翠密圍窗竹，青圓貼水荷。',24,'全唐诗/poet.song.83000.json','["翠密圍窗竹，青圓貼水荷。", "睡多嫌晝永，醒少得風和。"]'),
('ae8fb14f-f4d7-49b0-961c-086e46a5fb9e','四序回文十二首 夏 其二','宇文虛中','宋','宋诗','song-poetry','','[]','草徑迷深綠，蓮池浴膩紅。',24,'全唐诗/poet.song.83000.json','["草徑迷深綠，蓮池浴膩紅。", "早蟬鳴樹曲，鮮鯉躍潭東。"]'),
('f1e240a0-ac82-4871-b10c-7965e96ddef4','四序回文十二首 夏 其三','宇文虛中','宋','宋诗','song-poetry','','[]','暴雨隨雲驟，驚雷隱地平。',24,'全唐诗/poet.song.83000.json','["暴雨隨雲驟，驚雷隱地平。", "好風搖箑透，輕汗挹冰清。"]'),
('8db6b8c3-689f-4a35-b04a-e6b20c94e133','四序回文十二首 秋 其一','宇文虛中','宋','宋诗','song-poetry','','[]','晚日欣簾捲，凉風覺袂搖。',24,'全唐诗/poet.song.83000.json','["晚日欣簾捲，凉風覺袂搖。", "遠吟高興遣，長醉宿愁銷。"]'),
('81784e9c-bc16-44e8-bdaf-521f719af900','四序回文十二首 秋 其二','宇文虛中','宋','宋诗','song-poetry','','[]','短葦低殘雨，虚舟带晚潮。',24,'全唐诗/poet.song.83000.json','["短葦低殘雨，虚舟带晚潮。", "斷鴻歸暗浦，疏葉堕寒梢。"]'),
('d1a7a726-a269-49d8-ab10-7b3f7408b5f4','四序回文十二首 秋 其三','宇文虛中','宋','宋诗','song-poetry','','[]','慼慼蛬吟苦，茫茫水驛孤。',24,'全唐诗/poet.song.83000.json','["慼慼蛬吟苦，茫茫水驛孤。", "日銜山色莫，霜带菊叢枯。"]'),
('b58c4c9a-5483-4837-96d9-23a09e6c4638','四序回文十二首 冬 其一','宇文虛中','宋','宋诗','song-poetry','','[]','鶻健呼風急，烏啼促景殘。',24,'全唐诗/poet.song.83000.json','["鶻健呼風急，烏啼促景殘。", "窟深宜兔蟄，蒲折蔭魚寒。"]'),
('132a20fc-b886-4af1-a21b-afb518d8770d','四序回文十二首 冬 其二','宇文虛中','宋','宋诗','song-poetry','','[]','裂瓦寒霜重，鋪窗月影清。',24,'全唐诗/poet.song.83000.json','["裂瓦寒霜重，鋪窗月影清。", "滅燈驚好夢，孤枕念深情。"]'),
('23986f32-8fbb-4a16-98e2-54d6a839af6c','四序回文十二首 冬 其三','宇文虛中','宋','宋诗','song-poetry','','[]','秀柏留陰綠，芳梅蘸影斜。',24,'全唐诗/poet.song.83000.json','["秀柏留陰綠，芳梅蘸影斜。", "溜簷冰結玉，裝樹雪飛花。"]'),
('79c8ba8f-2d7a-43ac-aa24-ac6f149f95b7','燈碑五首  其一','宇文虛中','宋','宋诗','song-poetry','','[]','清陰靄靄匝城闉，萬井熙熙桃杏春。',32,'全唐诗/poet.song.83000.json','["清陰靄靄匝城闉，萬井熙熙桃杏春。", "紫陌傳呼旌斾出，重臣新佩玉麒麟。"]'),
('851c7f19-c249-494f-994c-3dda1f833373','燈碑五首  其二','宇文虛中','宋','宋诗','song-poetry','','[]','鈿軸天章拜異恩，驛驂花騎暎朝暾。',32,'全唐诗/poet.song.83000.json','["鈿軸天章拜異恩，驛驂花騎暎朝暾。", "手持禁鑰千門肅，官壓東宫二品尊。"]'),
('876215fb-bfa6-42c5-a7dc-c5e40a05c34b','燈碑五首  其三','宇文虛中','宋','宋诗','song-poetry','','[]','壘原清照白登山，彌隴連天麥浪寒。',32,'全唐诗/poet.song.83000.json','["壘原清照白登山，彌隴連天麥浪寒。", "劍戟漸銷農器出，人家只識勸農官。"]'),
('332f0d91-00c9-46a7-b4d9-708253ffd23f','燈碑五首  其四','宇文虛中','宋','宋诗','song-poetry','','[]','九夏南風入舜琴，恩風澤雨浹飛沈。',32,'全唐诗/poet.song.83000.json','["九夏南風入舜琴，恩風澤雨浹飛沈。", "陪京最是儀形地，先識君王解愠心。"]'),
('42ca5d03-cd36-40c6-a326-3aa739107618','燈碑五首  其五','宇文虛中','宋','宋诗','song-poetry','','[]','枹鼓無聲訟獄空，懽謡擊壤萬家同。',32,'全唐诗/poet.song.83000.json','["枹鼓無聲訟獄空，懽謡擊壤萬家同。", "時人共解班春意，兵寢刑清第一功。"]'),
('e1e992a8-a71f-45a8-8b3b-d67e05c1de76','館中書事','宇文虛中','宋','宋诗','song-poetry','','[]','雨來蒸欝似江鄉，雨過西風特地凉。',32,'全唐诗/poet.song.83000.json','["雨來蒸欝似江鄉，雨過西風特地凉。", "尚有庭花共客恨，可無尊酒慰幽芳。"]'),
('de5d0309-11da-48e5-8ce6-dcd11ab88d32','時習齋','宇文虛中','宋','宋诗','song-poetry','','[]','未厭平生習氣濃，更將餘事訓兒童。',32,'全唐诗/poet.song.83000.json','["未厭平生習氣濃，更將餘事訓兒童。", "魯論二萬三千字，悟入從初一句中。"]'),
('57a4e6ab-f51c-4e4c-bc58-0005599afb6d','醉經齋','宇文虛中','宋','宋诗','song-poetry','','[]','傍人但笑腹便便，枕藉詩書正晝眠。',32,'全唐诗/poet.song.83000.json','["傍人但笑腹便便，枕藉詩書正晝眠。", "不識先生真悟處，未離文字已逃禪。"]'),
('21865976-0ccf-471f-8025-109c920017ee','醉墨齋','宇文虛中','宋','宋诗','song-poetry','','[]','旋汲清泉起縠紋，定知婁永是前身。',32,'全唐诗/poet.song.83000.json','["旋汲清泉起縠紋，定知婁永是前身。", "箇中自可逃真性，不用淋漓汙葛巾。"]'),
('34d4ceb5-d7dc-4cf7-8d0e-c6f259767406','烏夜啼','宇文虛中','宋','宋诗','song-poetry','','[]','汝琴莫作歸鳳鳴，汝曲莫裁白鶴怨。',96,'全唐诗/poet.song.83000.json','["汝琴莫作歸鳳鳴，汝曲莫裁白鶴怨。", "明珠破璧挂高城，上有烏啼人不見。", "堂中蠟炬紅生花，門前紺幰七香車。", "博山夜長香燼冷，悠悠蕩子留倡家。", "妾機尚餘數梭錦，織恨傳情還未忍。", "城烏爲我盡情啼，知道單棲淚盈枕。"]'),
('322664d7-51d7-4310-b2b2-cdb087d5ab50','句','宇文虛中','宋','宋诗','song-poetry','','[]','有人若問南冠客，爲道西山賦蕨薇。',16,'全唐诗/poet.song.83000.json','["有人若問南冠客，爲道西山賦蕨薇。"]'),
('20df6b81-b85c-4e98-82cf-2a41f4e6ba9b','詠古四首  其一','汪藻','宋','宋诗','song-poetry','','[]','相士如相馬，滅没深天機。',96,'全唐诗/poet.song.83000.json','["相士如相馬，滅没深天機。", "區區銅馬法，徒識牝與驪。", "人言當塗公，惡人知其微。", "如何許邵語，受之不復疑。", "知人固不易，人亦未易知。", "媸妍在水鏡，鉛粉徒自欺。", "孰爲仁義人，未假已不歸。", "伯樂不可作，思與曹瞞期。"]'),
('3395864d-6134-4dd7-9710-f766da529f3d','詠古四首  其二','汪藻','宋','宋诗','song-poetry','','[]','世事如大弩，人若材官然。',108,'全唐诗/poet.song.83000.json','["世事如大弩，人若材官然。", "乘勢易發機，非時勞控弦。", "又如大水中，置彼萬斛船。", "雖有帆與檣，亦須風動天。", "不見周公瑾，弱齡已飛鶱。", "不見師尚父，鷹揚在華顛。", "彼非生而材，此豈晚乃賢。", "鎡基喻智慧，要必有待焉。", "嘆息狂馳子，嘗爲愚者憐。"]'),
('657fd32b-9836-4e59-81a0-6d87a6d8b49d','詠古四首  其三','汪藻','宋','宋诗','song-poetry','','[]','崑山有璞玉，外質而內美。',48,'全唐诗/poet.song.83000.json','["崑山有璞玉，外質而內美。", "惟其不自衒，故與頑石齒。", "和也速于售，再獻甘滅趾。", "在玉庸何傷，惜君兩足耳。"]'),
('6b2b2d83-3432-460a-80f5-3e495a29b530','詠古四首  其四','汪藻','宋','宋诗','song-poetry','','[]','堂堂明堂柱，根節幾歲寒。',48,'全唐诗/poet.song.83000.json','["堂堂明堂柱，根節幾歲寒。", "使與蒲柳同，扶廈良亦難。", "我衣敝緼袍，我飯苜蓿盤。", "天公方試我，劍鋏勿妄彈。"]'),
('99f12bee-c8a6-445b-83e6-5de834592983','題張公明賞晴軒','汪藻','宋','宋诗','song-poetry','','[]','端居有何好，名與勝會并。',132,'全唐诗/poet.song.83000.json','["端居有何好，名與勝會并。", "人生豈長閑，天宇不屢晴。", "邂逅風日佳，一醉萬事輕。", "君家大父客，詩如九韶鳴。", "浮春散無垠，攬取造物驚。", "坐令綠野堂，岌嶪睢陽城。", "風流被三世，諸郎未慚卿。", "開軒著尊酒，報答千花明。", "飲罷遣客休，仰空看雲行。", "是中有佳處，遑恤身後名。", "寧爲秋雨歎，更作秋蟲聲。"]'),
('4440eb3f-6b73-4381-a505-647f7e3adbfc','題折樞密保真草堂','汪藻','宋','宋诗','song-poetry','','[]','軒冕有何樂，書生分尤慳。',144,'全唐诗/poet.song.83000.json','["軒冕有何樂，書生分尤慳。", "都盧百年中，強半墮險艱。", "能著屐幾兩，恨無茅三間。", "儻非身世忘，那得方寸閑。", "不見葆真老，功成鬂毛斑。", "飄然日邊來，復作晝掩關。", "所至書滿屋，鉛黄不停刪。", "開窗尋丈餘，要看湘南山。", "夕待明月至，朝期白雲還。", "醉吟如樂天，但少素與蠻。", "嗟哉道脩阻，無由結朱顔。", "惟應夢見之，千里同躋攀。"]'),
('055b07f8-2954-4fa2-a654-bc85fec76366','泊召伯埭','汪藻','宋','宋诗','song-poetry','','[]','孤舟渺無根，夜歷數村雨。',72,'全唐诗/poet.song.83000.json','["孤舟渺無根，夜歷數村雨。", "今朝亂晴景，水鏡寫霜樹。", "哀鴻念羣聲，正到客愁處。", "男兒有懷抱，何事亦關汝。", "蒼烟接牛斗，惝恍迷歸路。", "明發問吾儂，乘流去復住。"]'),
('b770c946-92cb-462b-aa52-79b23824a6ad','尤袤大暑留召伯埭','汪藻','宋','宋诗','song-poetry','','[]','清風不肯來，烈日不肯暮。',84,'全唐诗/poet.song.83000.json','["清風不肯來，烈日不肯暮。", "平生山林下，散髪頗箕踞。", "一官走王事，三伏在道路。", "我非褦襶兒，亦爾困馳騖。", "居然戀俎豆，安得免羈馽。", "區區竟何營，汨汨此飄寓。", "淵明應笑人，有底不歸去。"]'),
('7bd46750-121e-4f07-892a-f47f75ce7081','大熱行旌德山中不可車馬步至凌氏林亭詩','汪藻','宋','宋诗','song-poetry','','[]','踞石休蠒足，掬泉洗赬容。',84,'全唐诗/poet.song.83000.json','["踞石休蠒足，掬泉洗赬容。", "于何脱冠履，共指雲外峰。", "翳彼園屋小，鉤簾蒼翠重。", "庭空燕雀乳，樹老莓苔封。", "露泫過牆竹，風凄橫澗松。", "欣然曲肱卧，鼻息春醅濃。", "推床上馬去，孰是陳元龍。"]'),
('377d2403-fa68-4134-bc83-c3f87faa6a64','次韻周聖舉從子乞紙','汪藻','宋','宋诗','song-poetry','','[]','溪翁搗冰時，寒甚龜手絮。',96,'全唐诗/poet.song.83000.json','["溪翁搗冰時，寒甚龜手絮。", "千金售詞客，妙語零唾霧。", "回看烏絲欄，一嫡輕百庶。", "長供蠆尾落，肯受蠅頭汙。", "今朝持贈君，真似翼傅虎。", "應緣未給札，欲草子虚賦。", "他年五十萬，渠復願鄰富。", "行看醉帖來，家不設寒具。"]'),
('c2ef3d45-81ae-4c4e-8990-ca96f127cccf','鄭固道累書求寓屋詩走筆封寄','汪藻','宋','宋诗','song-poetry','','[]','平生金石交，政爾一固道。',216,'全唐诗/poet.song.83000.json','["平生金石交，政爾一固道。", "佳哉固道乎，所至即爲寶。", "人言醒而狂，我見影亦好。", "憶初烟塵飛，環纍十萬竈。", "夕烽通甘泉，兵氣塞穹昊。", "公爲魯仲連，麾去如振槁。", "功成拂衣去，不羨中令攷。", "每逢泉石佳，便欲事幽討。", "晚行龜峰旁，愛此千嶂抱。", "亟營背郭堂，羞作出山草。", "慨然懸其車，避俗長卻掃。", "所嗟高明家，華屋幾人保。", "既留楊柳枝，仍占杏花島。", "真成醉吟翁，何況無病惱。", "屬聞鴻冥冥，痛恨歸不早。", "何當釋羈囚，把臂共傾倒。", "餘光玩桑榆，踵息養棃棗。", "買鄰會有時，來往成二老。"]'),
('6ae60ea7-fa42-4de1-8526-59e53bf9d842','題伯禹給事漫吾亭','汪藻','宋','宋诗','song-poetry','','[]','人生天地間，同一幻泡影。',192,'全唐诗/poet.song.83000.json','["人生天地間，同一幻泡影。", "偶然相值過，便有人與境。", "那知兩皆漫，直寄彈指頃。", "古來賢達士，物我均土梗。", "程侯東南俊，少日忠義秉。", "周旋正色地，四海憚嚴冷。", "立朝二十年，憤世欲生癭。", "班雖近日月，志則在箕潁。", "中年拂衣歸，絕意向鐘鼎。", "澤幽成小築，勝會已獨領。", "清寒挹湍瀨，秀色攬諸嶺。", "聊將不羈身，對此無閼景。", "回首浯溪老，便覺加數等。", "從渠春風顛，那得到古井。", "高詞出胸臆，妙處如灌頂。", "讀罷眷樊籠，悠然發深省。"]'),
('6aef637a-ad5c-46df-8d9e-2d0e494dd72e','次韻趙叔問侍郎送曾吉甫學士按刑淛右篇末見及之作','汪藻','宋','宋诗','song-poetry','','[]','我老不足惜，餘年苦匆匆。',240,'全唐诗/poet.song.83000.json','["我老不足惜，餘年苦匆匆。", "願爲名山遊，何必問所終。", "一艤若溪櫂，星杓幾回東。", "長年秋雨邊，醉卧聽船蓬。", "故人幸弭節，相見宿昔同。", "酒酣說經過，授我書一通。", "云自天末至，諸賢盛游從。", "臨分出新詩，句法何舂容。", "凜若臨大敵，誰能觸其鋒。", "攜持數千里，不愧行橐空。", "篇末亦及予，依依古人風。", "讀罷百憂失，衰顔爲成童。", "歸來北窗下，自寫團扇中。", "君方著繡衣，行佩金印重。", "朱絃付君賞，寧循牙曠聰。", "我病擁僧衲，深慚服非衷。", "還觀了無取，此意何當蒙。", "心知坡陀卑，難並衡霍崇。", "尚喜盛山卷，兼收醉吟翁。", "他年定撫掌，秋蛇間雲鴻。"]'),
('64a51fa0-179d-498c-9297-d303f916009d','次韻周聖舉過蘇次元四首  其一','汪藻','宋','宋诗','song-poetry','','[]','往聞蘇趙公，黄閣望諸老。',48,'全唐诗/poet.song.83000.json','["往聞蘇趙公，黄閣望諸老。", "功名四夷知，無愧越裳操。", "同時卿相家，紈綺或傭保。", "至今子孫賢，庭有書带草。"]'),
('7f00e43c-baa5-4530-9685-cc93d1c26dc8','次韻周聖舉過蘇次元四首  其二','汪藻','宋','宋诗','song-poetry','','[]','世人如冰蠶，不知天有暑。',48,'全唐诗/poet.song.83000.json','["世人如冰蠶，不知天有暑。", "紛紛謗傷兒，寧識真實語。", "當家勤采穫，兩耳得韶濩。", "要須追此公，勿問燕與許。"]'),
('b1908978-8ae1-4df2-b6c5-d45dacf4d6ed','次韻周聖舉過蘇次元四首  其三','汪藻','宋','宋诗','song-poetry','','[]','蘇郎年少時，萬象愁雕鐫。',48,'全唐诗/poet.song.83000.json','["蘇郎年少時，萬象愁雕鐫。", "應知等兒戲，區區止啼錢。", "三生綺語習，一悟心超然。", "胡爲作解嘲，切切相悲憐。"]'),
('c5f7d6cd-9c65-46f1-9746-fb39e5429520','次韻周聖舉過蘇次元四首  其四','汪藻','宋','宋诗','song-poetry','','[]','吳兒雅多姿，不肯藏白地。',48,'全唐诗/poet.song.83000.json','["吳兒雅多姿，不肯藏白地。", "因君更增情，吹雨作春淚。", "三年師命留，千日中山醉。", "一聞高唐賦，令我有仙意。"]'),
('63e54b20-c679-4dbc-97af-132446868d24','藻蒙叔雅祠部重九日惠花惠酒惠詩繼爲袁家碣鈷鉧潭之遊因循不能答再承佳句見寄今用來韻率課一篇參陪杖履之勝幸一笑而去之以覆醬瓿而作紙絞也','汪藻','宋','宋诗','song-poetry','','[]','秋風入瀟湘，千嶂倚天外。',180,'全唐诗/poet.song.83000.json','["秋風入瀟湘，千嶂倚天外。", "使君挽衰翁，行樂秋色界。", "放船下空闊，舒笑鳧鷖會。", "永懷愚溪人，千載有遺愛。", "延緣訪遺跡，佳處時擊汰。", "飛沈各獻狀，領略在我輩。", "匆匆莫能數，頗似慰無賴。", "盃行未云半，落日已相對。", "歸來有酒所，方省欠詩債。", "朱轓幸停軫，嘉汝山水最。", "金莖峙霄漢，行矣分沆瀣。", "何妨共流轉，今古同一概。", "非君箇中人，孰使此中大。", "伊余漂泊者，他日名亦在。", "一聞款乃聲，蓬蓽忘湫隘。"]'),
('9e8a36df-a5f3-4f7f-bca1-9d15dc7b90a8','從稚子出前溪','汪藻','宋','宋诗','song-poetry','','[]','霜斂萬壑凈，鐘鳴空楚山。',48,'全唐诗/poet.song.83000.json','["霜斂萬壑凈，鐘鳴空楚山。", "夕陽當我沈，風烟迫梅殘。", "西嶺月未上，數峰深作寒。", "枝間鳥競赴，亦復循溪還。"]'),
('d23efe55-ab68-46a7-ba5e-811883da5b03','同張昌時宿高明寺','汪藻','宋','宋诗','song-poetry','','[]','幽卧不知覺，窗懸寒日初。',132,'全唐诗/poet.song.83000.json','["幽卧不知覺，窗懸寒日初。", "矧伊夜來雨，谿聲到吾廬。", "故人挽我出，忽枉天際書。", "躋險敢自休，青山轉籃輿。", "相逢竹間寺，共擷園中蔬。", "殘僧誰在亡，奄忽十載餘。", "茗果話疇昔，新晴報鐘魚。", "東雷亦已鳴，百草苕穎舒。", "奈何與之子，齒髪日夜疏。", "眷此不能發，牽衣更躊蹰。", "明朝各回首，世事將焉如。"]'),
('6819dc8d-e239-448e-9cbc-d409e3c73f20','孫益遠試歸墮車敗面已而薦書至作詩戲之以送其行','汪藻','宋','宋诗','song-poetry','','[]','羊公作三公，政辦一肱折。',168,'全唐诗/poet.song.83000.json','["羊公作三公，政辦一肱折。", "功名方鼎來，詎嘆養生拙。", "孫郎少奇偉，面滿若霜月。", "胡爲忽顛隮，有物食之缺。", "寧非造物意，怪子卧巖穴。", "長年臉邊紅，漫自供酒纈。", "顧令冠蓋底，未省識此傑。", "何妨暫相顧，一訪唐舉決。", "朝來清鏡裏，黄色兩眉徹。", "居然萬馬羣，老驥已超絕。", "聊將釣竿手，遮日向西闕。", "瓊林風帽穩，醉度櫻笋節。", "從渠關宴上，兒女笑鬷蔑。", "誰能爲公豪，玉瑑揮作雪。"]'),
('0188d538-2864-4cfd-bcfa-209fa4f6cfdb','徽州班春古巖寺呈諸僚友','汪藻','宋','宋诗','song-poetry','','[]','揆日奉明詔，班春出孤城。',216,'全唐诗/poet.song.83000.json','["揆日奉明詔，班春出孤城。", "和風遞鼓鼙，細雨迷斾旌。", "渺渺度阡陌，谿山照人明。", "幽花不孤芳，好鳥相應鳴。", "隴麥已爭秀，畦秧亦微萌。", "食新知有期，及我凋瘵氓。", "古寺依絕壁，林端列飛甍。", "殘僧四五人，靜若無所營。", "石室廣百肘，嵌空自天成。", "泉甘與茶宜，就挹巖下清。", "伏檻肆遐矚，歸雲入簷楹。", "數農前致辭，貌野意則誠。", "兹幸枉冠蓋，使君豈無情。", "頻年苦饑虚，奚用恤此生。", "守昔在閭里，先疇毎躬耕。", "起家三絕餘，謬忝符竹榮。", "無術布寛大，低頭愧鰥惸。", "願言同撫綏，永絕愁嘆聲。"]'),
('1fb892aa-62da-4697-8660-6a524a61649e','阻溪漲宿諸暨縣上省院','汪藻','宋','宋诗','song-poetry','','[]','暑濕倦行役，依投得禪關。',96,'全唐诗/poet.song.83000.json','["暑濕倦行役，依投得禪關。", "空堂納清風，坐見香霏還。", "積水共天遠，高僧與雲閑。", "傳聞扁舟人，宿昔廬兹山。", "姝者已千載，諸峰高烟鬟。", "當時功名成，止在談笑間。", "今豈無國士，宸遊一何艱。", "憑高望行朝，小雨猶斑斑。"]'),
('6eaf02f1-a5cb-4a78-a964-5dcecebd44cb','試闈同宋德操陳純中登稽古閣曉望','汪藻','宋','宋诗','song-poetry','','[]','雙睫不能熟，疏鐘起初曉。',144,'全唐诗/poet.song.83000.json','["雙睫不能熟，疏鐘起初曉。", "危欄扶力上，層簷掛雲表。", "羣峰蒼玉如，開簾四環繞。", "向來聲利場，自今眼界小。", "兩君天下士，一見意傾倒。", "有此風味佳，未受秋思惱。", "我昔溪上住，盟言寄鷗烏。", "今年縱得來，官事間日少。", "樊籠更樊籠，歸途天樣杳。", "是處非不佳，千慮舒懷抱。", "浮雲且東來，吾家隔林杪。", "境熟斷難忘，終念今朝好。"]'),
('de055f0b-b6ff-497a-a1ef-36e0a30d2f8a','芳美亭','汪藻','宋','宋诗','song-poetry','','[]','東風不世情，幽谷渠亦至。',60,'全唐诗/poet.song.83000.json','["東風不世情，幽谷渠亦至。", "誰分玄都種，爲我作春事。", "朝來花氣暖，詩眼先自醉。", "祇愁貪結子，零落烟雨際。", "聞今新蹊成，有酒且頻置。"]'),
('8d543230-c0c2-4218-bca5-8109e4d995e4','十月二十六日會于北禪分韻賦詩應辰得多字呂治先酒熟亦欲會客故末意及之','汪藻','宋','宋诗','song-poetry','','[]','爲此升斗粟，來往如飛梭。',120,'全唐诗/poet.song.83000.json','["爲此升斗粟，來往如飛梭。", "桂林在何許，水險山嵯峨。", "驪駒偶未至，于焉少婆娑。", "幸陪英俊遊，不覺日月過。", "今夕復何夕，朔風捲寒波。", "肴核雖草草，聊以供笑歌。", "子如不飲酒，視此庭前柯。", "濃綠光薿薿，所餘今幾何。", "鄰家釀新熟，頗聞旨且多。", "更當奮餘勇，往舉金叵羅。"]'),
('a7947109-1766-44f1-b7da-61e2b355f838','題葉尚書普光明庵','汪藻','宋','宋诗','song-poetry','','[]','長樂七閩會，山川富登臨。',144,'全唐诗/poet.song.83000.json','["長樂七閩會，山川富登臨。", "重城十萬家，間以烟樹林。", "何許肆遐矚，城西最高岑。", "主人厭直歸，與世相浮沈。", "三宿得勝地，八還見初心。", "明窗一蒲團，宴坐依横參。", "面面來遠色，層層列清陰。", "閑翻貝葉書，靜聽頻迦音。", "萬法照了處，人居兩幽深。", "嗟予晚聞道，況迫桑榆侵。", "如何結保社，去脱頭上簪。", "從公刮眼膜，儻借箆千金。"]'),
('9120e1de-2262-43a5-9f22-9b5b71774853','病中偶成','汪藻','宋','宋诗','song-poetry','','[]','衰病乃其理，移牀卧南軒。',96,'全唐诗/poet.song.83000.json','["衰病乃其理，移牀卧南軒。", "雖懷飲冰憂，賴有清賞存。", "春去芳草積，羅生滿庭萱。", "花房向夕斂，似與吾忘言。", "數蝶亦多態，差差傍叢飜。", "客來同一欣，何必臨芳樽。", "常恐秋節至，嚴霜霣其根。", "吾生尚悠悠，眷爾安足論。"]'),
('afee669b-d8eb-42a3-b6b8-474a552b74f0','再過凌氏園復用前韻','汪藻','宋','宋诗','song-poetry','','[]','兒輩病元亮，斗筲羈曼容。',84,'全唐诗/poet.song.83000.json','["兒輩病元亮，斗筲羈曼容。", "何時跨鴻鵠，食藕蓮花峰。", "小檻再遊歷，輕寒裘未重。", "人家當巵黍，不愧千戶封。", "願因琴高生，儻見喬與松。", "從兹毁車馬，永絕世味濃。", "歲晚復來此，清陰期籜龍。"]'),
('019c4a05-83c6-40d1-add4-a10676e42661','聚山閣爲吳氏題','汪藻','宋','宋诗','song-poetry','','[]','緣江故多峰，秀色無可揀。',144,'全唐诗/poet.song.83000.json','["緣江故多峰，秀色無可揀。", "何須著腳力，政欲長在眼。", "詩翁築飛閣，似恨山意懶。", "縱橫數州碧，收拾付酒醆。", "客來何所命，濯濯千髻綰。", "晴嵐入肺腑，寶唾落碑版。", "翁家誠可樂，人境兩蕭散。", "爐香侣趺坐，終日對編簡。", "風流前輩接，細說鬚自挽。", "居然典刑在，聽者輒忘返。", "會須營一壑，萬事等鵬鷃。", "從翁時對榻，卧看烟雨晚。"]'),
('efb5722e-2315-49bd-afef-22723992a961','偶書','汪藻','宋','宋诗','song-poetry','','[]','長簟北窗下，抛書任縱橫。',156,'全唐诗/poet.song.83000.json','["長簟北窗下，抛書任縱橫。", "娟娟穉篠上，熠熠叢榴明。", "眷此感佳節，怊然愴平生。", "少年文翰場，結客俱擅名。", "瑤草俟采掇，雲鴻肆遐征。", "如何二十載，日與憂患并。", "骨肉隨逝水，兒童長柴荆。", "向來交臂人，接武霄漢行。", "姻親歲時會，尊酒懷抱傾。", "兹余豈復願，顧影良自驚。", "飛雨夜來急，濤翻江上城。", "田家夢亦好，想像秋稼成。", "新春了在眼，續我齋庖清。"]'),
('b0c175c1-5543-40c0-80bf-8da33a8a66f0','吳傅朋以王逸少遺意作游絲之書古今所無恨未之見也爲賦此詩','汪藻','宋','宋诗','song-poetry','','[]','吳侯能書聲，不減銘瘞鶴。',204,'全唐诗/poet.song.83000.json','["吳侯能書聲，不減銘瘞鶴。", "臺郎今獨步，誰數衛與索。", "官黄臨小楷，老筆更沈著。", "年來雞鶩間，兒輩妄穿鑿。", "超然出新意，非用元和腳。", "游絲隨春風，忽向窗几落。", "傳觀懍飛動，安得此健藥。", "自言臨池時，屢閲更歲籥。", "毫端幾百鍊，始到蟲網絡。", "誰云右軍後，兹事秘冥漠。", "一朝神明還，千載宛如昨。", "乃知鑪鎚妙，信手皆合作。", "於皇雲漢章，神授等河洛。", "光芒下照燭，萬帖悉糟粕。", "君命幸逢時，當草鳯尾諾。", "胡爲尚留滯，未便持漢橐。", "行看誠懸歸，佳句題殿閣。"]'),
('3f0b0eb9-d94f-4e55-8936-0a4bb2c0a29a','書局晚歸','汪藻','宋','宋诗','song-poetry','','[]','平生麋鹿姿，不意華屋居。',144,'全唐诗/poet.song.83000.json','["平生麋鹿姿，不意華屋居。", "一爲軒裳攖，所得非所如。", "弱跡踵諸彦，清班直周廬。", "蓬山切星辰，牙籖明綺疏。", "散帙喜所得，懷鉛愧中虛。", "暝歸復奚營，一飽不願餘。", "寧甘四立壁，懶作三獻書。", "高槐障熇煩，清陰落庭除。", "幽卧遂終日，兹謀定非疏。", "娟娟新月流，翳翳歸雲舒。", "懷人發浩歎，屏營以踟躕。", "願言果歸志，春波漲隋渠。"]'),
('90650f85-fa01-4853-bd3f-185bf28c27d9','次韻胡德廣書懷','汪藻','宋','宋诗','song-poetry','','[]','大瓠既成實，無用始欲剖。',144,'全唐诗/poet.song.83000.json','["大瓠既成實，無用始欲剖。", "鮒魚困車轍，求活賴升斗。", "我昔誦斯言，感歎銘座右。", "慎惜千金軀，未欲聊俯就。", "數子磊落人，好事真吾友。", "相期竹西遊，晚歲並耕耦。", "如何窘窮途，狺狺吠羣狗。", "平生笑俗士，反欲較妍醜。", "譬如惡影人，乃與影競走。", "今復念邊陲，未暇從田叟。", "彈冠宜彚征，子先我欲後。", "世間樗與櫟，拳曲自難揉。"]'),
('fa70cf5d-5e2d-436b-9ab5-f2ad03f0daf9','陪諸公遊文雅臺憩法雲寺二首  其一','汪藻','宋','宋诗','song-poetry','','[]','旅泊值秋晚，登臨良亦佳。',156,'全唐诗/poet.song.83000.json','["旅泊值秋晚，登臨良亦佳。", "高臺始基誰，未覺歲月遐。", "維梁漢寵弟，非復莩附葭。", "鳴鞭白雲上，寶髻翻千鴉。", "樽前第詞客，坐使屈宋衙。", "秖今竟何有，蕪没荒烟斜。", "秦墟仆翁仲，楚俗悲章華。", "空餘古招提，老龐伴丹霞。", "花氣侵客袂，松聲滿鄰家。", "凄涼刧灰地，半似篁竹遮。", "坐久鴈橫野，炊烟映簷牙。", "似聞睢陽曲，尚作兒童譁。", "惜無斗酒酧，水厄空嘗茶。"]'),
('8f2d2de0-3ae4-4d36-8064-fbfaa8148f75','陪諸公遊文雅臺憩法雲寺二首  其二','汪藻','宋','宋诗','song-poetry','','[]','向來卜幽期，此樂真雋永。',156,'全唐诗/poet.song.83000.json','["向來卜幽期，此樂真雋永。", "行尋野航渡，俯玩雲水影。", "追隨兩玉人，妙語時灌頂。", "平生訪古意，到此方一騁。", "所欣俱秃翁，王事廢朝請。", "且同陶淵明，蓮社對宗炳。", "晴軒納野色，秋思浩千頃。", "忽驚梨棗村，身墮白鷗境。", "飄零惬勝會，老大惜餘景。", "況當風露辰，病鶴最先警。", "留連凈名室，坐閲篆香冷。", "還尋野田歸，草樹斜復整。", "有酒當再來，悠悠詎能省。"]'),
('c36cad3a-edee-4604-9412-d9e7a4623b88','陪諸公遊惠山','汪藻','宋','宋诗','song-poetry','','[]','兹山定中腴，秀色乃如許。',144,'全唐诗/poet.song.83000.json','["兹山定中腴，秀色乃如許。", "連峰積蒼潤，嵐氣亦如雨。", "珍泉不浪出，世俗那得取。", "羣仙作佛供，灑此玉池股。", "甘寒飲天下，瓶盎走膏乳。", "兒嬉供茗事，雲散入江渚。", "當源起臺殿，下瞰松柏古。", "巍基首梁宋，爽氣接吳楚。", "我來值佳月，濟勝得嵇吕。", "聊分小蒼壁，同振百年羽。", "躋攀興未極，落日在林莽。", "卻立望翠屏，中流駐鳴櫓。"]'),
('dac9c769-028c-41b4-8831-136341fb20d6','題通惠亭','汪藻','宋','宋诗','song-poetry','','[]','吾山皆中腴，初不斷地脉。',72,'全唐诗/poet.song.83000.json','["吾山皆中腴，初不斷地脉。", "淄澠嘗同味，十里何所隔。", "幽居愁遠汲，悵望懸瀑白。", "天公真解事，分我膚寸澤。", "無煩籜龍引，中有玉池色。", "煮茗聊餉君，未須嫌水厄。"]'),
('51664e9a-f27f-406c-8eb5-3c9aa45e6c65','從吳禹功借徐鉉小篆帖以詩還之','汪藻','宋','宋诗','song-poetry','','[]','六書散浮雲，篆籀世不數。',156,'全唐诗/poet.song.83000.json','["六書散浮雲，篆籀世不數。", "陵夷到草隸，差别幾四五。", "人皆逐曾玄，不復知父祖。", "中間尤可笑，雞鶩紛去取。", "孰爲魯漆書，況說周石鼓。", "陽冰雖晚出，妙意得千古。", "後來繼者誰，騎省人最許。", "明窗出小軸，驚嘆手爲拊。", "平生箏笛耳，慣見沐猴舞。", "一登韶濩堂，方信有干羽。", "援毫極摹倣，涴壁類兒女。", "秋蛇已成癖，老腕徒自苦。", "卷書還歸公，祇自愧韓愈。"]'),
('79dc4961-6372-4060-84d6-08bbb71411cb','食十月蕈','汪藻','宋','宋诗','song-poetry','','[]','佳蕈出何許，南山白雲根。',156,'全唐诗/poet.song.83000.json','["佳蕈出何許，南山白雲根。", "畦丁入雲採，徧以脱葉翻。", "戢戢寸玉嫩，纍纍萬釘繁。", "中涵烟霞氣，外絕沙土痕。", "下筯極雋永，加餐亦平溫。", "伊昔貴公子，鮮肥厭羔豚。", "爭啖肉菌美，共品天花尊。", "居然此珍産，以遠莫見論。", "生令五鼎味，但飽三家村。", "伊余少所嗜，頭白歸故園。", "日獲甘脆享，人言老饕存。", "栮脯固已陋，竹枯何足言。", "從今大嚼處，不復思屠門。"]'),
('c8debdc8-6e28-460c-a714-c405f24b6f62','寄余仲誠','汪藻','宋','宋诗','song-poetry','','[]','千巖雪齊消，烟日曖春事。',72,'全唐诗/poet.song.83000.json','["千巖雪齊消，烟日曖春事。", "端憂昧佳節，獨宿松下寺。", "遶屋泉雨鳴，焚香戶深閉。", "殘僧荷耡出，幽鳥下庭戲。", "將期道心復，敢愜棲遁志。", "起望吾家雲，風清鴈成字。"]'),
('7aa64d71-dfdb-4892-93ae-ceeb8e87747f','古鏡行','汪藻','宋','宋诗','song-poetry','','[]','我有辟邪鏡，得之咸陽宫。',168,'全唐诗/poet.song.83000.json','["我有辟邪鏡，得之咸陽宫。", "其陰爲天池，一母將九龍。", "旁書負圖字，土蝕如旋蟲。", "緘以駭雞珍，妙極倕之工。", "請言照遠近，十里秋毫空。", "豈不鑒脂澤，所貴肝膽通。", "問誰爲此器，太古非人功。", "客聞重歎息，意欲窺靈蹤。", "高臺不辭倚，恐客難稱容。", "繩窮匣半啓，四室來悲風。", "日車當晝留，羞澀如頑銅。", "森然髪上指，凜若臨霜鋒。", "我還撫客手，此豈世寶同。", "揮涙兩無言，掩鏡鞶囊中。"]'),
('fd8d4380-5e40-423e-9bb8-7f5cb3da44c0','次高郵軍','汪藻','宋','宋诗','song-poetry','','[]','小雨靜林麓，鵓鴣相應鳴。',84,'全唐诗/poet.song.83000.json','["小雨靜林麓，鵓鴣相應鳴。", "移舟漾清淺，薄晚荷風生。", "歸鳥盡雙去，潛魚時一驚。", "菰蒲若無人，渺渺炊烟横。", "艇子檝迎我，攜魚薦南烹。", "月出殊未高，疏林隱微明。", "依投會有處，斗掛天邊城。"]'),
('e995beec-21ca-4b6a-921f-3c9d88c9703b','避地函亭野步','汪藻','宋','宋诗','song-poetry','','[]','今日幸無雨，天空出遙岑。',144,'全唐诗/poet.song.83000.json','["今日幸無雨，天空出遙岑。", "行行不知疲，遂至春江潯。", "汲路轉籬落，人家在桑陰。", "平疇漲清波，隴麥如人深。", "溝畎戲鳧鶩，新蒲映浮沈。", "我生本樵漁，對此諧初心。", "風物豈不好，悲來自難任。", "胡塵暗中原，四海如驚禽。", "黄屋狩萬里，兩宫隔辰參。", "龍騰鼎湖闊，月晦星河深。", "宇宙有傾覆，兹游豈嶇嶔。", "消憂賴濁醪，太息誰能斟。"]'),
('f5b06e76-f838-4163-bfe8-498eebbd3b7b','庚午歲屏居零陵七月二十日以門揜候蟲秋爲韻賦五首  其一','汪藻','宋','宋诗','song-poetry','','[]','幽人獨夜時，潮落西川根。',48,'全唐诗/poet.song.83000.json','["幽人獨夜時，潮落西川根。", "渡口櫓聲急，一江烟雨昏。", "城頭短長更，不寐聽譙門。", "趺坐數千息，焚香待朝暾。"]'),
('a7a00e37-96f3-40d3-8fba-2422c46133f6','庚午歲屏居零陵七月二十日以門揜候蟲秋爲韻賦五首  其二','汪藻','宋','宋诗','song-poetry','','[]','暑退潦亦收，瀟湘凈如染。',48,'全唐诗/poet.song.83000.json','["暑退潦亦收，瀟湘凈如染。", "時觀自跳魚，衝破青琬琰。", "纖纖初弦月，不受薄雲揜。", "近村應漸寒，已有鴉數點。"]'),
('bc1321b9-5263-4fa3-9c48-674c83a73c0b','庚午歲屏居零陵七月二十日以門揜候蟲秋爲韻賦五首  其三','汪藻','宋','宋诗','song-poetry','','[]','人生幾聰明，日夜隙駒驟。',48,'全唐诗/poet.song.83000.json','["人生幾聰明，日夜隙駒驟。", "纔經花信風，又過麥秋候。", "吾非金石堅，與世相邂逅。", "胡爲聞鐘鳴，更歷路傍堠。"]'),
('30c14f2d-2c98-4587-99a1-4bf79c7965e6','庚午歲屏居零陵七月二十日以門揜候蟲秋爲韻賦五首  其四','汪藻','宋','宋诗','song-poetry','','[]','家山在何許，渺渺彭蠡東。',48,'全唐诗/poet.song.83000.json','["家山在何許，渺渺彭蠡東。", "人來數月程，衣敝補道中。", "昨宵青燈花，似墜釵頭蟲。", "兒饑女沈緜，歲晚書未通。"]'),
('3db8d7db-9cbf-494d-8d80-a306516d96ff','庚午歲屏居零陵七月二十日以門揜候蟲秋爲韻賦五首  其五','汪藻','宋','宋诗','song-poetry','','[]','人言間闊者，一日如三秋。',48,'全唐诗/poet.song.83000.json','["人言間闊者，一日如三秋。", "孤臣昔放逐，七見天星周。", "早污高門地，姓名記前旒。", "如何天雞星，不照湘南州。"]'),
('e69e71b2-a74b-40df-a138-e7f5411e6c26','汴中放船歸陽羨','汪藻','宋','宋诗','song-poetry','','[]','流澌欲作環珮鳴，枯木未肯回春聲。',160,'全唐诗/poet.song.83000.json','["流澌欲作環珮鳴，枯木未肯回春聲。", "舟人坐恐雪爲祟，嬌鴉又舞天邊城。", "天公知我不足厄，乞與十日霜風晴。", "遙遙烟堤護玉鏡，滉滉雲海浮金鉦。", "攬衣坐數踵間息，闚見宇宙無餘情。", "燈花也似調兒女，咄咄笑我長宵征。", "我生底處不堪著，未歸且雜吳兒耕。", "縱無鄰翁飲子美，會有稚子迎淵明。", "仙山況聞連洞壑，餌朮或可求長生。", "閑中日月吾所有，此外付之人重輕。"]'),
('6ea9fa0d-938f-4a08-9c29-e2772ebbe13b','送毘陵太守劉君受代東歸','汪藻','宋','宋诗','song-poetry','','[]','往年我作新安民，人人能說劉使君。',160,'全唐诗/poet.song.83000.json','["往年我作新安民，人人能說劉使君。", "使君本一儒者耳，數十年來嗟未聞。", "我時屈指今州縣，似此賢侯當識面。", "那知漂泊千里餘，畫戟清香日陪宴。", "使君何以人不如，胸中正有萬卷書。", "清真簡淡乃天性，文章政事猶其餘。", "向來天子留君住，重與毘陵三萬戶。", "誰教一曲渭城歌，忽作梨花枝上雨。", "宦遊南北安得同，撫循凋郡還須公。", "人生五馬亦不惡，與民處處爲春風。"]'),
('c7464495-0db8-4c6a-b7aa-1e2f07c02a34','題孫益遠三士堂','汪藻','宋','宋诗','song-poetry','','[]','稚川晚作羅浮遊，淵明暫出還歸休。',64,'全唐诗/poet.song.83000.json','["稚川晚作羅浮遊，淵明暫出還歸休。", "東坡百謫乃欣慕，孫郎更欲參其流。", "四人出處無一似，千載相期風味耳。", "要須共著巖壑中，應只虎頭知此意。"]'),
('adc89fbc-0b41-453e-aa69-8b6ea02596a0','從人乞酒','汪藻','宋','宋诗','song-poetry','','[]','張侯表表霜松立，嗜酒清狂餘故習。',192,'全唐诗/poet.song.83000.json','["張侯表表霜松立，嗜酒清狂餘故習。", "長年種秫學淵明，門外溪流和月汲。", "手調溪上百花乳，十日煉成冰雪汁。", "糟牀夜聽秋雨注，詩腸曉放春風入。", "飽聞誇說未曾見，但笑書生便飲濕。", "爾來消渇卧江海，更似枯魚過河泣。", "傾家餉客古人事，坐看兵廚千斛給。", "那知日飲無骨相，咫尺公榮殊不及。", "西風昨夜到林杪，左手蟹螯行可執。", "新醅早晚定堪斟，凍蟻浮缸應戢戢。", "心知問字寂寥久，會遣鳴鞭馳送急。", "呼兒洗盞酹先酒，爲君快作長鯨吸。"]'),
('ab719b1f-87a2-4ed0-8bff-b1bbbcbd9174','過吳明叟新居','汪藻','宋','宋诗','song-poetry','','[]','誰開大屋沈沈者，門外垂楊拂車馬。',144,'全唐诗/poet.song.83000.json','["誰開大屋沈沈者，門外垂楊拂車馬。", "主人四十持節歸，高卧綠陰啼鳥下。", "冥冥一徑傍花入，忽有清池照深夏。", "魚吹落日知鏡凈，荷受微風看珠瀉。", "夫君少有湖海氣，欲駟長鯨無地跨。", "故將能事驚世人，坐向雲端差萬瓦。", "稍培幽桂出窗底，時放青山來竹罅。", "人言此興極不淺，天遣公忙那肯赦。", "要須更作輞川圖，他日思歸聊對畫。"]'),
('ad411ba2-36eb-4e3f-a354-949243524eed','次韻周聖舉清溪行二首  其一','汪藻','宋','宋诗','song-poetry','','[]','君不見國家有紀狂童干，一溪百繞山千盤。',195,'全唐诗/poet.song.83000.json','["君不見國家有紀狂童干，一溪百繞山千盤。", "竹兵草草兒戲爾，震澤以南心爲寒。", "初如妖禽嘯月曉，忽作聚蚋奔醯酸。", "九重夜半出秦甲，一麾萬里春農安。", "書生那知破賊事，且復雪涕論悲端。", "憶初倉惶挺身走，江湖滿地皆驚湍。", "仲宣何暇守漳浦，子美僅能投錦官。", "朝愁烽連海嶠起，暮恐彗掃星河翻。", "忍饑怖死頭搶地，破釡躍魚苔漬冠。", "爾時身世狹于掌，俯仰宇宙何時寛。", "只今同喜風塵定，慎勿忘憂耽酒聖。", "要須剩作舂陵行，爲洗吳兒百年病。"]'),
('880e8812-df05-4de7-a938-f3bedf587dfe','次韻周聖舉清溪行二首  其二','汪藻','宋','宋诗','song-poetry','','[]','君不見吳儂自昔王江千，歲輸御府金堆盤。',195,'全唐诗/poet.song.83000.json','["君不見吳儂自昔王江千，歲輸御府金堆盤。", "一朝肘掖作奇禍，玉册錦袍盟欲寒。", "驛塵初飛梅未破，匆匆烟雨催梅酸。", "行驅鬼馬載鬼妾，欲偷瞬息如槐安。", "那知氛霧卷清晝，旄頭夜落天南端。", "樓船千萬羽林卒，飛渡海潮江不湍。", "狂童生致獨柳下，請肉仇家來白官。", "千奴一膽更須問，速收兩手春耕翻。", "鹿奔誰云爭走險，雞敗但笑空餘冠。", "政須船粟哺其腹，此令朝行民夕寛。", "功歌九廟今誰定，退之方頌元和聖。", "老人端坐聽清風，習習先秋蘇肺病。"]'),
('345a84c7-3ae3-401f-aaab-bec0b1d83d9f','題周彦約壺齋','汪藻','宋','宋诗','song-poetry','','[]','化人謁帝遊清都，俯視宫室如積蘇。',176,'全唐诗/poet.song.83000.json','["化人謁帝遊清都，俯視宫室如積蘇。", "那知神仙隱朝市，雲窗霧閣在一壺。", "古來志士守環堵，宅彌萬里乾坤俱。", "君今官冷百僚底，世人未識文於菟。", "故營容膝尺度足，卷藏風月吞江湖。", "客卿筆墨共游戲，維摩牀坐同跏趺。", "鈎簾終日屏塵事，卧聽秋雨鳴菰蒲。", "伊余想像未得往，一讀妙語清而腴。", "遙知坐穩肉生髀，滿壁但掛歸來圖。", "功名富貴會相迫，恐此骨相山林無。", "平泉綠野看他日，莫忘築室愚溪愚。"]'),
('4bbaeded-5f5e-4a80-9a1e-196a63d2aceb','觀秋江捕魚圖','汪藻','宋','宋诗','song-poetry','','[]','霜飈落木瀟湘秋，黄蘆颯颯秋江頭。',112,'全唐诗/poet.song.83000.json','["霜飈落木瀟湘秋，黄蘆颯颯秋江頭。", "漁翁短棹搖輕舟，夕陽斜照寒波流。", "篷蓑箬笠興夷猶，得魚沽酒更勸酬。", "生涯一葉水上浮，市朝利病不相謀。", "青山綠水得魚游，此樂未必饒公侯。", "畫圖忽見清兩眸，恍疑身在滄浪洲。", "年來萍梗歎滯留，擬欲與子爲朋儔。"]'),
('eb1f91f3-314b-4528-9f15-95be94c7cc67','何子應少卿作金華書院要老夫賦詩因成長句一首','汪藻','宋','宋诗','song-poetry','','[]','詞林根柢須人品，四海聲名誰藉甚。',192,'全唐诗/poet.song.83000.json','["詞林根柢須人品，四海聲名誰藉甚。", "金華真是第一流，好泛扁舟著宫錦。", "向來奮舌動天意，不怕惠文霜凜凜。", "忽然飄落九疑山，坐對秋風行兩稔。", "手栽巖桂友羣石，收拾清香供燕寢。", "笑隨蠻俗且南冠，忍說鄉關猶左袵。", "人間何事非戲劇，鶴有乘軒蛙給廩。", "功名入手談笑間，誰謂收之如拾瀋。", "況君風骨未渠艾，意氣文章天所稟。", "我今頭白奚所爲，柏樹誰知問從諗。", "雖云百里間何闊，同在邯鄲一羈枕。", "遙知袖手正書空，讀罷離騷還痛飲。"]'),
('c6e2a079-d975-44c5-ba44-32f069db8cc4','蜂兒行','汪藻','宋','宋诗','song-poetry','','[]','蜜蜂以蜜爲生涯，爲人採蜜安于花。',176,'全唐诗/poet.song.83000.json','["蜜蜂以蜜爲生涯，爲人採蜜安于花。", "霜蜂嘗恐奇禍作，深崖大壑懸其家。", "生兒孚乳自毫末，幼成玉蛹肩相差。", "分房戢戢蓮綻子，擁戶娟娟蘭茁芽。", "驚猜肯使樵牧近，千尾負毒爭防遮。", "那知長安貴公子，酒酣咀爾不搖牙。", "登盤未辨翅與股，百金購買囊紅紗。", "琴魚漫傳仙物美，桂蠧空取蠻方賒。", "吾聞厚味古所戒，暴及胎卵寧非奢。", "合圍火攻無脱者，舉族孥戮奚罪耶。", "厥包作貢自誰始，從今可弔不可誇。"]'),
('4d76a466-724b-48da-9f21-a015e8273b92','阻風雨辟邪渡寄王仲成','汪藻','宋','宋诗','song-poetry','','[]','渡頭急雨鳴森木，木杪顛風飛大屋。',128,'全唐诗/poet.song.83000.json','["渡頭急雨鳴森木，木杪顛風飛大屋。", "没腰寒水稻生芽，滿眼青泥車折軸。", "山行值雨舟值風，窮愁日日煩天公。", "不如歸卧澗壑底，世事一掃春花空。", "别君兩年重此别，喜君胸次渾冰雪。", "擬將身作賈胡留，無奈事如空鳥滅。", "挽我不回君怒嗔，交情把玩轉清新。", "相隨百里還相見，只有西山似故人。"]'),
('cd87f619-4b18-476e-a558-593ef96f25a1','贈丹青僧了本','汪藻','宋','宋诗','song-poetry','','[]','虎頭不復傅金粟，魏武之孫聊可續。',131,'全唐诗/poet.song.83000.json','["虎頭不復傅金粟，魏武之孫聊可續。", "如何三昧畫中王，解使天機照人目。", "含毫不動先有情，萬態了了隨經營。", "偶然得意灑春色，日輔月角須臾成。", "精神還仗精神覓，筆下區區徒刻畫。", "故知巧匠盤礴時，萬里丹青減容色。", "君不見齊梁大士天所開，幼僧不許僧繇猜。", "師今幸有印泥手，貌取當年黄面來。"]'),
('08f57b28-a80f-4594-a610-e9b4e129d43c','題楚東吳文學湖隱閣','汪藻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君不見三峽灩澦瞿塘堆，盤渦日夜轟春雷。',230,'全唐诗/poet.song.83000.json','["君不見三峽灩澦瞿塘堆，盤渦日夜轟春雷。", "又不見洞庭周遭六百里，日月出入其灣隈。", "人間偉觀有如此，欲往莫到空低回。", "如何湖光几席上，萬頃鏡凈無纖埃。", "桃花雨餘春漲急，盎盎正作蒲萄醅。", "菰蒲遠映水一碧，五月菱熟芙蕖開。", "冰輪宵向座隅湧，四座林影參差來。", "天寒潮落洲渚出，健步更宜尋野梅。", "吳郎一生短檠下，裹以章服羞自媒。", "家山故有丘壑在，松竹多是兒時栽。", "中年有得雲水趣，深入鷗鳥無驚猜。", "坐令浮念掃除盡，方寸淡泊寒如灰。", "浩歌時從鼓枻去，高卧不怕當關催。", "鑑湖賀老即君是，定與謫仙長舉杯。"]'),
('5832781c-dfbf-4da1-9a39-40f6569cae12','次韻蘇養直寄黄元功','汪藻','宋','宋诗','song-poetry','','[]','男兒當騎生馬駒，不但詞賦凌三都。',160,'全唐诗/poet.song.83000.json','["男兒當騎生馬駒，不但詞賦凌三都。", "願從北地傅介子，西吞青海東元菟。", "一行作吏不稱意，人間險過宫亭湖。", "黄郎里中同隊魚，十年太學隨諸儒。", "春風不作霄漢夢，秋雨漫肥瓜芋區。", "一身長寄白鷗境，千字快掃青松腴。", "風埃空憶大梁别，尺書不到雲泉居。", "似聞騏驥尚伏櫪，饑鷹未飽誰能呼。", "清江上有仙人廬，何時十幅西風蒲。", "與君杖屨日來往，濁醪可解饑寒劬。"]'),
('92f37eb2-0a53-411a-b4c2-69d0f8446419','次韻劉立道二首  其一','汪藻','宋','宋诗','song-poetry','','[]','劉郎有酒君當傾，安用新詩鳴不平。',128,'全唐诗/poet.song.83000.json','["劉郎有酒君當傾，安用新詩鳴不平。", "黄粱未歎轉頭熟，朱絃卻喜知音明。", "古來去國例憔悴，伊余尚得佳山水。", "謝公行處欲千年，擬傍蒼崖尋屐齒。", "揚帆今向古長干，渡口遙知儂戲官。", "此行相伴只明月，到時破璧應團欒。", "羮蓴飯稻江南俗，剩鱠銀絲炊白玉。", "人間墮甑萬事休，卧看雙溪千頃綠。"]'),
('2843fe02-7e16-4296-981d-6fc6b33d38a0','次韻劉立道二首  其二','汪藻','宋','宋诗','song-poetry','','[]','雲花忽作挼雲傾，臘梅便欲迎嘉平。',128,'全唐诗/poet.song.83000.json','["雲花忽作挼雲傾，臘梅便欲迎嘉平。", "青燈已照浪頭宿，夜長更苦風連明。", "榆黄柳綠已衰悴，空餘疏星漾寒水。", "想君懷抱亦凄然，況我飄零誰復齒。", "不須聞此涕闌干，人今得歸仍得官。", "未應百鍊遽磨滅，他年尚識霜鐘欒。", "心知薄領令人俗，賴有烟波雙屬玉。", "長沙縱使賈生歸，只恐樽前凋鬢綠。"]'),
('6c09a26c-0c09-471e-ac4e-50fd016a4301','次韻過顧子美話舊因遊惠山','汪藻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','放船出郭溪渾渾，乘潮夜到吾家門。',288,'全唐诗/poet.song.83000.json','["放船出郭溪渾渾，乘潮夜到吾家門。", "潮頭細卷落花雨，濕櫓不驚春夢魂。", "君家難忘復易識，依然井徑當丘樊。", "向來惡子下闚處，繞屋但見清陰繁。", "飄零懷抱少傾倒，一見故人如故園。", "嗟予何因得之子，舊事請自鍾陵論。", "鍾陵當日盛遊集，往往前輩風流存。", "嘯歌雖容阮籍逸，人物不數王融諼。", "我時三十君始壯，矯矯兩鶴俱乘軒。", "大兒洪徐小兒向，此外餘子何勞吞。", "龍沙買酒醉秋月，倒牀但聽長江奔。", "秖今相去能幾日，世事反復那勝言。", "一官得謫大如屋，五年乞米供朝昏。", "頗疑造物乃知我，欲使晚節窮彌敦。", "君看靜躁不同者，王孫顧肯還爲猿。", "飲酣起步青松根，共瞻佛宇諸峰尊。", "席邊正喜泉潄壑，風外已復烏啼村。", "箇中好著我輩人，寄與石上留窪樽。"]'),
('d8a9e442-665c-4dc9-adbe-63f1efa80d2d','以詩酬答贈小姪','汪藻','宋','宋诗','song-poetry','','[]','老奴攜簡來林泉，蒼然白髪垂枯顛。',80,'全唐诗/poet.song.83000.json','["老奴攜簡來林泉，蒼然白髪垂枯顛。", "自甘老矣填溝壑，那識人間有地仙。", "小牋微意我所喜，扁舟便可來山前。", "輕帆破浪有清思，況是暑月開紅蓮。", "塵緣萬事不足理，且欲一見增欣然。"]'),
('f15856a1-963a-40bf-b6c6-0e443c3c1b4f','石舟歎','汪藻','宋','宋诗','song-poetry','','[]','匆匆負鍤鵝鶩喧，閃閃蹴車雷電翻。',160,'全唐诗/poet.song.83000.json','["匆匆負鍤鵝鶩喧，閃閃蹴車雷電翻。", "一城騷動急星火，官渠底用農時穿。", "海神有意驅巨石，風伯不肯停陰雲。", "坐令榷水甚于酒，盜者以乏軍興論。", "峨峨之山載大艑，所過郡邑千官奔。", "繡衣持斧坐堤上，百瀆倒盡生龜文。", "民間四月種不入，敢惜數斗春泥渾。", "君王神聖古無有，談笑坐可回乾坤。", "何妨謦欬九天上，叱散黄帽還嵌根。", "嗟哉食肉胡不告，勿謂石也安能言。"]'),
('56e9791a-7a4d-433b-b2ca-5109bc93dad9','次韻賈仲遠還浮溪猥藁之什','汪藻','宋','宋诗','song-poetry','','[]','我家浮溪溪水頭，一褐一裘聊玩世。',160,'全唐诗/poet.song.83000.json','["我家浮溪溪水頭，一褐一裘聊玩世。", "誰教去踏曉鼓朝，也學兒童攻偶儷。", "憶身曾是掖垣客，歲晚猶期樂天似。", "兩年漂泊萬里餘，老矣始于魚得計。", "欣逢賈傅古湘口，城郭雖非人物是。", "連臺拗倒時一醉，醉後還爲五禽戲。", "慇懃爲我出新詩，金石因聲泉湧思。", "年來處處飽葵莧，染鼎忽驚嘗異味。", "荷花開已三四紅，有酒無過行樂耳。", "與公同嚼三百杯，莫負便便五經笥。"]'),
('7bef5cae-0bba-4de5-b4a8-2270af2a44d4','即事','汪藻','宋','宋诗','song-poetry','','[]','前瞻西嶺懸日光，回望東崖森兩行。',96,'全唐诗/poet.song.83000.json','["前瞻西嶺懸日光，回望東崖森兩行。", "天公作事銷底力，投壺一笑千家涼。", "初乘青駛度平野，稻花風露隨人香。", "忽驚強弩過林杪，羣山發盡烟復藏。", "宫廚蔗漿若可挹，炎官火傘那復張。", "夜寒更踏松桂影，馬頭新月明于霜。"]'),
('ba75cbfa-fc2e-4e22-952f-6c5694e740a6','次韻董禹川餉墨','汪藻','宋','宋诗','song-poetry','','[]','徂徠老松蔽百牛，輸膏敗乳來中州。',128,'全唐诗/poet.song.83000.json','["徂徠老松蔽百牛，輸膏敗乳來中州。", "何人夜半擣寒碧，用心獨與神明儔。", "範成秋天翔紫鳯，裁作古虛懸蒼球。", "匹夫被褐知者少，江都老相千金收。", "養之懷袖作歎息，平生長物胡爲留。", "分張好事亦及我，摩挲未語心先謀。", "明光起草正須子，一揮坐遣千人休。", "嗟予老矣安用此，誰能細字書蠅頭。"]'),
('5e89ff52-3f11-4459-916b-fbe8d4990b99','汴中書事三首  其一','汪藻','宋','宋诗','song-poetry','','[]','永日鈎簾坐，乘流頗自怡。',48,'全唐诗/poet.song.83000.json','["永日鈎簾坐，乘流頗自怡。", "手邀飛絮住，目送遠花移。", "官牒吾何有，郵籖汝漫知。", "關心淹速事，無復少年時。"]'),
('91df6cc9-76fe-4f7d-abca-ef803b211b65','汴中書事三首  其二','汪藻','宋','宋诗','song-poetry','','[]','既雨堤仍注，無風浪更揚。',48,'全唐诗/poet.song.83000.json','["既雨堤仍注，無風浪更揚。", "麥登孤市沸，榆老半川涼。", "擊汰吳儂勇，傳掫楚戍荒。", "秖應今夜月，兒女話他鄉。"]'),
('426c90b9-3de7-4b8e-94df-3059f363f0fe','汴中書事三首  其三','汪藻','宋','宋诗','song-poetry','','[]','曉日輕橈動，波光滿座隅。',48,'全唐诗/poet.song.83000.json','["曉日輕橈動，波光滿座隅。", "岸遙雙燕去，天齊百禽呼。", "衰白看明鏡，飄零倒濁壺。", "長年作羈旅，三徑有人無。"]'),
('f8f6653e-369c-4432-ad30-860294cccb47','題余氏幽光亭二首  其一','汪藻','宋','宋诗','song-poetry','','[]','縹緲風烟上，誰栽柏滿庭。',48,'全唐诗/poet.song.83000.json','["縹緲風烟上，誰栽柏滿庭。", "諸郎渾玉雪，前哲想丹青。", "舉國思人鑑，重泉揜德星。", "空餘千載事，寒露泣秋螢。"]'),
('6fc42128-30c8-45e2-8f28-abb4c1e29688','題余氏幽光亭二首  其二','汪藻','宋','宋诗','song-poetry','','[]','自奪幽人去，江山勝氣無。',48,'全唐诗/poet.song.83000.json','["自奪幽人去，江山勝氣無。", "秖今埋宿草，誰復奠生芻。", "滿世儒冠寵，他年史筆誅。", "未應丘壑底，遺恨失金朱。"]'),
('de8f594d-c7de-4872-aa54-938fbbce9369','常山道中聞諸將屢捷','汪藻','宋','宋诗','song-poetry','','[]','一雨四十日，羲和安在哉。',48,'全唐诗/poet.song.83000.json','["一雨四十日，羲和安在哉。", "路憂石頭滑，雲怕天心開。", "隔水喚舟渡，逢人騎馬來。", "聞言江北好，一笑爲傳杯。"]'),
('883c95a7-30cf-49e9-95d1-2dc4747613bc','己酉亂後寄常州使君姪四首  其一','汪藻','宋','宋诗','song-poetry','','[]','汾水游仍遠，瑤池宴未歸。',48,'全唐诗/poet.song.83000.json','["汾水游仍遠，瑤池宴未歸。", "航遷羣廟主，矢及近臣衣。", "胡馬窺天塹，邊烽斷日畿。", "百年淮海地，回首復成非。"]'),
('45698bb1-bb24-4b2d-a32d-272e868b0135','己酉亂後寄常州使君姪四首  其二','汪藻','宋','宋诗','song-poetry','','[]','草草官軍渡，悠悠敵騎旋。',48,'全唐诗/poet.song.83000.json','["草草官軍渡，悠悠敵騎旋。", "方嘗勾踐膽，已補女媧天。", "諸將爭陰拱，蒼生忍倒懸。", "乾坤滿羣盜，何日是歸年。"]'),
('d5212fe2-021f-40ec-8426-7698c1593342','己酉亂後寄常州使君姪四首  其三','汪藻','宋','宋诗','song-poetry','','[]','身老今何向，兵拏未肯休。',48,'全唐诗/poet.song.83000.json','["身老今何向，兵拏未肯休。", "經旬甘半菽，盡室委扁舟。", "台拆星猶熭，農饑麥未秋。", "日邊無一使，兒女詎知愁。"]'),
('9b5d06de-105c-4e76-bedd-c8bee84c3457','己酉亂後寄常州使君姪四首  其四','汪藻','宋','宋诗','song-poetry','','[]','春到花仍笑，時危笛自哀。',48,'全唐诗/poet.song.83000.json','["春到花仍笑，時危笛自哀。", "平城隆準去，瓜步佛貍來。", "地下皆冤肉，人間半刦灰。", "只今衰淚眼，那得向君開。"]'),
('c6b63dc2-d8bf-4a3b-ada8-8e87bc22ca4c','次韻桂林經略李尚書投贈之句三首  其一','汪藻','宋','宋诗','song-poetry','','[]','方隅謀帥重，帝豈賈生疏。',48,'全唐诗/poet.song.83000.json','["方隅謀帥重，帝豈賈生疏。", "絕域須高枕，中朝輟引裾。", "邊城雄鼓角，幕府省文書。", "暫作驂鸞去，羣公歎不如。"]'),
('d5d01b13-6fa8-4ff5-8dc2-5b0ef4bb760f','次韻桂林經略李尚書投贈之句三首  其二','汪藻','宋','宋诗','song-poetry','','[]','東越更新組，南陽别舊廬。',48,'全唐诗/poet.song.83000.json','["東越更新組，南陽别舊廬。", "中原猶鐵馬，遠使只銅魚。", "荒俗宜深問，遺蠻勿重鋤。", "歸來正黄閣，將略自公餘。"]'),
('26f60add-6fb0-41c5-8fb7-ccaf4e54845b','次韻桂林經略李尚書投贈之句三首  其三','汪藻','宋','宋诗','song-poetry','','[]','聞道中興帥，今除第一流。',48,'全唐诗/poet.song.83000.json','["聞道中興帥，今除第一流。", "犬牙聊制敵，猿臂即封侯。", "把酒逢元亮，哦詩得子猷。", "何妨留此傑，相與復神州。"]'),
('92d3b52b-7562-47da-820e-da07922e870f','次韻蔡少張遣興四首  其一','汪藻','宋','宋诗','song-poetry','','[]','南紀安耕鑿，平時不受兵。',48,'全唐诗/poet.song.83000.json','["南紀安耕鑿，平時不受兵。", "邊陲忘宇覆，江漢忽塵生。", "潮卷妖星落，春歸玉帳明。", "將軍談笑事，一笴定聊城。"]'),
('d190cc4b-4ea2-4421-9053-86f85b0c6ca7','次韻蔡少張遣興四首  其二','汪藻','宋','宋诗','song-poetry','','[]','聞道官軍入，吳儂盡倒戈。',48,'全唐诗/poet.song.83000.json','["聞道官軍入，吳儂盡倒戈。", "指揮移地軸，湔洗用天河。", "尚作蒼頭起，當如赤子何。", "汝曹宜面縛，環壘即恩波。"]'),
('6edf5aaa-623c-4daf-a90b-f2483f84b988','次韻蔡少張遣興四首  其三','汪藻','宋','宋诗','song-poetry','','[]','欲弔沈冤處，春江只自深。',48,'全唐诗/poet.song.83000.json','["欲弔沈冤處，春江只自深。", "鋤耰元聚守，塢壁要先侵。", "吉語行看報，窮愁有底禁。", "簷花應好在，準擬報同襟。"]'),
('68861fe0-9aca-4482-9ff5-e04cad6bbfb1','次韻蔡少張遣興四首  其四','汪藻','宋','宋诗','song-poetry','','[]','坐奪江山險，都忘带與襟。',48,'全唐诗/poet.song.83000.json','["坐奪江山險，都忘带與襟。", "不應囚膽落，亦費廟謀深。", "賸作懷歸雅，行參解慍琴。", "君王憐赤子，意豈在南金。"]'),
('6b0736da-bd98-4947-84b9-c63a68dedc22','次韻鄭固道侍郎見寄長句二首  其一','汪藻','宋','宋诗','song-poetry','','[]','一作班荆别，秋風幾度涼。',48,'全唐诗/poet.song.83000.json','["一作班荆别，秋風幾度涼。", "論文隔尊俎，得句夢池塘。", "歲晚思傾蓋，情親比陟岡。", "若爲生羽翼，千里到君旁。"]'),
('b7177f81-a159-46b8-a35d-4e7ba572ac80','次韻鄭固道侍郎見寄長句二首  其二','汪藻','宋','宋诗','song-poetry','','[]','憶昨遭戎馬，同浮十里江。',48,'全唐诗/poet.song.83000.json','["憶昨遭戎馬，同浮十里江。", "括囊聊遯世，懷寶豈迷邦。", "眼底雲空過，眉間雪未厖。", "不因參嚼蠟，那得寸心降。"]'),
('3b7d65da-5aeb-4665-a79f-dafe49eb35a5','舟行遣興五首  其一','汪藻','宋','宋诗','song-poetry','','[]','擁衲無餘事，時聞起柁聲。',48,'全唐诗/poet.song.83000.json','["擁衲無餘事，時聞起柁聲。", "水烟猶作暝，霜鵲已嬉晴。", "淼淼人歸路，悠悠歲晚情。", "秖應江海外，隨處著餘生。"]'),
('f6a7a9bb-4b8a-41b9-bd22-81d69369a6a4','舟行遣興五首  其二','汪藻','宋','宋诗','song-poetry','','[]','滔滔千里浪，秖解送人忙。',48,'全唐诗/poet.song.83000.json','["滔滔千里浪，秖解送人忙。", "看即成衰鬢，能堪幾斷腸。", "繫船冰樹動，炊黍水雲香。", "驚怪陶彭澤，功名晚更忘。"]'),
('e29a4c9f-6eb1-4e8f-9ce5-018493a424a3','舟行遣興五首  其三','汪藻','宋','宋诗','song-poetry','','[]','高城吹角罷，别浦載燈歸。',48,'全唐诗/poet.song.83000.json','["高城吹角罷，别浦載燈歸。", "歲晚客猶去，水寒潮亦稀。", "一身將影屢，萬事轉頭非。", "莫倚危檣望，清霜易滿衣。"]'),
('803bc11d-e98b-412b-97b7-01f660782130','舟行遣興五首  其四','汪藻','宋','宋诗','song-poetry','','[]','霜斂初晴夜，江愁獨望人。',48,'全唐诗/poet.song.83000.json','["霜斂初晴夜，江愁獨望人。", "蕭條全浦暝，錯落數星陳。", "老覺癯儒冗，窮遭醉尉嗔。", "梅花行滿眼，莫作後園春。"]'),
('14e968ee-6e12-4ba1-80a1-c18865ed853e','舟行遣興五首  其五','汪藻','宋','宋诗','song-poetry','','[]','渺渺竟何向，滔滔難與論。',48,'全唐诗/poet.song.83000.json','["渺渺竟何向，滔滔難與論。", "鴈書鳴笛野，雪縞過帆村。", "夜寂人誰語，江流月自存。", "莫令漂泊夢，千里到脩門。"]'),
('73fb65f2-df3e-47a4-8a3b-6e7ee9155165','過臨平二首  其一','汪藻','宋','宋诗','song-poetry','','[]','一别九霄路，風烟長滿衣。',48,'全唐诗/poet.song.83000.json','["一别九霄路，風烟長滿衣。", "已成身老大，無復世輕肥。", "天闊鳥雙下，山寒人獨歸。", "曉來何似雨，春水半巖扉。"]'),
('a1157f9b-c29f-4c63-be17-38346ecd74c8','過臨平二首  其二','汪藻','宋','宋诗','song-poetry','','[]','睡起涼生岸，鉤簾坐小窗。',48,'全唐诗/poet.song.83000.json','["睡起涼生岸，鉤簾坐小窗。", "麥風能起柁，梅雨不鳴江。", "往事心長折，歸塗影自雙。", "依然蒲柳地，人老故先降。"]'),
('282497e9-7995-404b-8cfd-eb11c1f4ee46','天長道中三首  其一','汪藻','宋','宋诗','song-poetry','','[]','山行逢淺夏，濃綠屢低巾。',48,'全唐诗/poet.song.83000.json','["山行逢淺夏，濃綠屢低巾。", "地冷猶衣裌，村香已食新。", "菰蒲渾欲老，魚鳥自相親。", "倚杖看孤月，悠悠何處人。"]'),
('7d329d74-720b-4f64-b2a7-332bd5bcaa62','天長道中三首  其二','汪藻','宋','宋诗','song-poetry','','[]','十年遊歷地，客子故難忘。',48,'全唐诗/poet.song.83000.json','["十年遊歷地，客子故難忘。", "下馬尋遺老，開門對夕陽。", "一鳩鳴晻翳，數犢卧蒼茫。", "更欲東南望，疏星近鳥行。"]'),
('196443e4-4426-4c5f-a1d0-389b27e65d37','天長道中三首  其三','汪藻','宋','宋诗','song-poetry','','[]','節物兼暄暑，川原半雨晴。',48,'全唐诗/poet.song.83000.json','["節物兼暄暑，川原半雨晴。", "雉場時一雊，鼃畝忽齊鳴。", "斗粟違高枕，囊衣度古城。", "讀書成底事，投老失春耕。"]'),
('07cb177f-c806-4f6f-b25e-e8aa19f13339','水晶數珠詩','汪藻','宋','宋诗','song-poetry','','[]','猶带他山潤，來依宴坐深。',48,'全唐诗/poet.song.83000.json','["猶带他山潤，來依宴坐深。", "誰云秋露滴，能節海潮音。", "積數塵難盡，微穿蟻可尋。", "但隨君語默，用舍我何心。"]'),
('289b3004-c0f7-4fd1-a22d-f45b852179c6','食蝦','汪藻','宋','宋诗','song-poetry','','[]','久憶南烹好，今朝放筯空。',48,'全唐诗/poet.song.83000.json','["久憶南烹好，今朝放筯空。", "短箱傾碎碧，纖指剝輕紅。", "腰折宜賖死，鬚長不療窮。", "吳兒方獻納，應與䱥魚同。"]'),
('793fbd8c-34ec-4ef2-990a-cee2e5a2ba7c','山奥寺','汪藻','宋','宋诗','song-poetry','','[]','已怯驚潮渡，還憂複嶺登。',48,'全唐诗/poet.song.83000.json','["已怯驚潮渡，還憂複嶺登。", "逢人多問數，投宿只尋僧。", "野飯農夫怪，山行稚子能。", "朝來那得爾，前路好飛騰。"]'),
('48e15bd9-2f9b-4102-aad4-7c6854332fb8','悼往二首  其一','汪藻','宋','宋诗','song-poetry','','[]','宿草縱橫綠，春歸有底忙。',48,'全唐诗/poet.song.83000.json','["宿草縱橫綠，春歸有底忙。", "百年知有盡，萬感要難忘。", "欲語如他日，猶疑在我旁。", "人生今至此，不擬惜流光。"]'),
('e00c8117-00a8-48a7-867d-0560f72e51a3','悼往二首  其二','汪藻','宋','宋诗','song-poetry','','[]','意懶還須步，愁多不更嗔。',48,'全唐诗/poet.song.83000.json','["意懶還須步，愁多不更嗔。", "蕭蕭寒著樹，咄咄老侵人。", "未滿窮愁願，先分夢幻身。", "東風吹節換，送我淚痕新。"]'),
('cf6642fa-0d87-4f45-92bd-b0e60a01bbf0','起居方舍人挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','漢殿臚傳處，回頭四十春。',48,'全唐诗/poet.song.83000.json','["漢殿臚傳處，回頭四十春。", "共嗟香案吏，歸作釣臺人。", "意氣林泉老，名聲日月新。", "賈生方擬召，鵩鳥在承塵。"]'),
('58fb6628-5e7e-447e-9254-ff91c9afc145','起居方舍人挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','經術羣公上，人材二紀間。',48,'全唐诗/poet.song.83000.json','["經術羣公上，人材二紀間。", "屢持邊使節，竟老近臣班。", "賜第叨同擢，趨朝憶共還。", "白頭無力送，能隔幾青山。"]'),
('b934e29b-17ad-440e-bb50-6b2addad3d15','河中使君莫少卿挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','表表今詞伯，邕邕古德人。',48,'全唐诗/poet.song.83000.json','["表表今詞伯，邕邕古德人。", "翺翔初畫省，邂逅老朱輪。", "閲世深涇渭，傳家得鳯麟。", "懸知他日大，時望屬平津。"]'),
('b7f57903-1e3d-4d3a-a1c6-c686b8078e67','河中使君莫少卿挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','藉甚河中守，宜簪近侍冠。',48,'全唐诗/poet.song.83000.json','["藉甚河中守，宜簪近侍冠。", "九霄卿月墮，四海德星寒。", "桂籍新枝大，蘭陂舊馥殘。", "空餘蓴鯽奠，鄉淚滿江干。"]'),
('deefda13-a80a-4cfc-8afe-3addab126bd7','挽毛奉議詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','不信儒冠誤，長年自濯薰。',48,'全唐诗/poet.song.83000.json','["不信儒冠誤，長年自濯薰。", "鄉評推秀孝，墨客誦詩文。", "仕早收朝蹟，材終壅上聞。", "晚全冰壑趣，造物似知君。"]'),
('b0f953fc-24b4-4707-ab37-81540f4e3080','挽毛奉議詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','玉立簪纓底，平生恥自媒。',48,'全唐诗/poet.song.83000.json','["玉立簪纓底，平生恥自媒。", "次山初漫仕，元亮即歸來。", "竟老金閨籍，虛纒蕙帳哀。", "盛名知不朽，妙語寫瓊瑰。"]'),
('58ed2a6b-6503-407c-bf06-1e5b136ecc54','致政魯奉議挽詩二首  其一','汪藻','宋','宋诗','song-poetry','','[]','澤國今耆舊，于君見典刑。',48,'全唐诗/poet.song.83000.json','["澤國今耆舊，于君見典刑。", "居鄉乘款段，生子得寧馨。", "綵服供春酌，銀章慰暮齡。", "誰知雲霧裏，忽失少微星。"]'),
('e92fa879-8e48-434c-8aca-24def0e42ac1','致政魯奉議挽詩二首  其二','汪藻','宋','宋诗','song-poetry','','[]','詔綍從君賜，經龕與佛同。',48,'全唐诗/poet.song.83000.json','["詔綍從君賜，經龕與佛同。", "早霑三釡祿，幾作百年翁。", "閲世松成蓋，傳家桂滿叢。", "素車千兩送，榮絕九原中。"]'),
('3eee9db1-2fab-4352-91e5-0efd5b13eace','魯國太夫人楊氏挽詩三首  其一','汪藻','宋','宋诗','song-poetry','','[]','有子升台衮，承顔況日長。',48,'全唐诗/poet.song.83000.json','["有子升台衮，承顔況日長。", "魚軒開大國，鶴髪老高堂。", "忽報栽萱隕，空餘扇枕涼。", "他年黄閣地，誰舉伯仁觴。"]'),
('bdf6281f-752c-4059-b7f8-31d5146b9585','魯國太夫人楊氏挽詩三首  其二','汪藻','宋','宋诗','song-poetry','','[]','白雲終日望，方喜見庭闈。',48,'全唐诗/poet.song.83000.json','["白雲終日望，方喜見庭闈。", "鼎食三牲養，貂冠五綵衣。", "回班儀未舉，反哭事俄非。", "寂寞苕溪路，安輿去不歸。"]'),
('0a6062f6-fa31-43d8-9971-4e1de31ed447','魯國太夫人楊氏挽詩三首  其三','汪藻','宋','宋诗','song-poetry','','[]','承顔雖一子，扶膝有諸孫。',48,'全唐诗/poet.song.83000.json','["承顔雖一子，扶膝有諸孫。", "壽祉膺難老，哀榮動至尊。", "秖今懷顧復，猶想對平反。", "天與牛眠地，何須返故園。"]'),
('340bd8da-6e56-42ed-91ba-c276d0a435a5','隆祐太后挽詞二首  其一','汪藻','宋','宋诗','song-poetry','','[]','慶源由魏國，奉祀及宣仁。',48,'全唐诗/poet.song.83000.json','["慶源由魏國，奉祀及宣仁。", "盛德儀中壼，私恩絕外親。", "長秋期不老，厚夜忽無晨。", "來歲柔桑綠，誰臨繭館春。"]'),
('1d968590-882c-4b67-aa6e-1430c880200c','隆祐太后挽詞二首  其二','汪藻','宋','宋诗','song-poetry','','[]','朔漠遐征後，南州俶擾時。',48,'全唐诗/poet.song.83000.json','["朔漠遐征後，南州俶擾時。", "人心憂社稷，天意屬簾帷。", "擁佑千齡主，圖回萬世基。", "中興能事畢，倐與帝鄉期。"]'),
('46754446-3bfa-4486-923b-a014c8cd099e','湖州長興縣大雄寺陳霸先故宅天嘉中所植檜柯葉蒼然其中空洞皮脈僅存而已','汪藻','宋','宋诗','song-poetry','','[]','曾經浩劫故依然，老壽方知木有仙。',64,'全唐诗/poet.song.83000.json','["曾經浩劫故依然，老壽方知木有仙。", "直幹凌空裁百尺，虚心閲世已千年。", "深蟠澤國興王地，獨傲天公造物權。", "玉樹庭花非不好，秖今誰占舊山川。"]'),
('023a3423-5444-4385-bed1-31e5e3eea8ec','韋氏獨樂園','汪藻','宋','宋诗','song-poetry','','[]','渺然於世不磷緇，手自栽花作四時。',64,'全唐诗/poet.song.83000.json','["渺然於世不磷緇，手自栽花作四時。", "坐客聽蛙聊復爾，呼卿聞鴈汝爲誰。", "眼中泉石論溪買，行處壺觴逐境移。", "早晚拈書來就讀，别開三徑與君期。"]'),
('6ca19175-2a10-4284-afa3-75909dba8db7','宿東山寺有謝公井存焉','汪藻','宋','宋诗','song-poetry','','[]','謝公當日此徜徉，千載空餘一徑荒。',64,'全唐诗/poet.song.83000.json','["謝公當日此徜徉，千載空餘一徑荒。", "林壑久應無小草，石泉今即是甘棠。", "江山似恨功名誤，花竹猶含笑語香。", "投老西州知不反，可堪垂涕笛筝傍。"]'),
('a394cf57-e4cb-4a82-833e-b985fca20c29','次韻李元亮','汪藻','宋','宋诗','song-poetry','','[]','水宿山行十日歸，李侯應恨尺書遲。',64,'全唐诗/poet.song.83000.json','["水宿山行十日歸，李侯應恨尺書遲。", "遙知雨别風流後，直到秋高木落時。", "負郭生涯千畝竹，長年心事四愁詩。", "與君家世如兄弟，歲晚同爲丘壑期。"]'),
('469c22b9-b333-44be-aef6-e3913d4c818b','次汪相韻','汪藻','宋','宋诗','song-poetry','','[]','幾年東閣歎差池，忽見溪山照紫微。',64,'全唐诗/poet.song.83000.json','["幾年東閣歎差池，忽見溪山照紫微。", "千里讙傳旌節至，一城爭看錦衣歸。", "敢言刺史分符寵，幸遇諸生鼓瑟希。", "早晚九重宣詔急，紫陽山下驛塵飛。"]'),
('a89fcf73-38ce-49ee-8110-11a3c51a7e38','次韻張樂潛','汪藻','宋','宋诗','song-poetry','','[]','從渠兒輩錯書麞，自寫新詩細作行。',64,'全唐诗/poet.song.83000.json','["從渠兒輩錯書麞，自寫新詩細作行。", "門外滿生書带草，林間知有德星堂。", "流匙已厭青精滑，蘸甲須嘗白堕香。", "秖恐笑談須此老，又教天下起馮唐。"]'),
('5d33aad5-2e0f-4c54-a8d8-c7e6b78ce08d','次韻蔡天任二首  其一','汪藻','宋','宋诗','song-poetry','','[]','遠屏郊園誰復過，支筇立到暮鐘時。',64,'全唐诗/poet.song.83000.json','["遠屏郊園誰復過，支筇立到暮鐘時。", "苦無啼鳥坐春去，時見好山緣竹低。", "行逢鄰僧語一則，絕勝飲客呼三遲。", "人間萬事不關我，以殻自遮如凍龜。"]'),
('245b29cc-161f-416a-ad88-b97a8ba7b6d6','次韻蔡天任二首  其二','汪藻','宋','宋诗','song-poetry','','[]','一雨真成解人意，翻盆注野卻晴時。',64,'全唐诗/poet.song.83000.json','["一雨真成解人意，翻盆注野卻晴時。", "五更城上鳥烏樂，十日街頭櫻笋低。", "江聲即隨潮信急，雲氣欲度山椒遲。", "吾徒飽飯眼中見，鍊息不應長學龜。"]'),
('e8bc89b3-1e05-4b32-807c-afdfbd8cdc0c','次韻董禹川二首  其一','汪藻','宋','宋诗','song-poetry','','[]','江山怪我數能來，政坐刀斤赦不才。',64,'全唐诗/poet.song.83000.json','["江山怪我數能來，政坐刀斤赦不才。", "生理喜于魚得計，交情羞似鴆爲媒。", "烟塵回首烽三月，花柳關情酒一杯。", "日夜故園歸夢好，憶衝細雨斸蒿萊。"]'),
('60116393-14df-4715-8b9a-6b5a9acb8961','次韻董禹川二首  其二','汪藻','宋','宋诗','song-poetry','','[]','涉世真成百罅舟，漫教俗子相壺丘。',64,'全唐诗/poet.song.83000.json','["涉世真成百罅舟，漫教俗子相壺丘。", "投林老去三椽在，墮甑年來萬事休。", "只欲攜兒耕甫里，誰能著酒換涼州。", "絕憐揚子津頭雨，管斷江南庾信愁。"]'),
('9ae0f39a-7d06-478e-8f43-1c1261f888e3','次韻洪駒父集東山','汪藻','宋','宋诗','song-poetry','','[]','文書到眼只眵昏，出郭尋山聊解紛。',64,'全唐诗/poet.song.83000.json','["文書到眼只眵昏，出郭尋山聊解紛。", "驅馬去迎三丈日，與僧同卧一窗雲。", "竹間揮麈風相及，松下烹茶手自分。", "回首微官堪底用，他年泉石是知聞。"]'),
('8ff98916-7de7-4a67-bdae-b9f6fab25eb3','晚發吳城山','汪藻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','風埽陽侯雪陣平，雨催摩詰畫圖成。',64,'全唐诗/poet.song.83000.json','["風埽陽侯雪陣平，雨催摩詰畫圖成。", "氣吞浦漵重林盡，秋著江湖去鳥明。", "厚祿故人無一字，長年三老伴餘生。", "會須滿意開懷抱，到眼廬山不世情。"]'),
('c723490f-0074-488c-9b9c-16b7c0c7e5de','題何子應竹君軒','汪藻','宋','宋诗','song-poetry','','[]','苔連深竹楚江干，分與幽人宴坐看。',64,'全唐诗/poet.song.83000.json','["苔連深竹楚江干，分與幽人宴坐看。", "映得圖書終日翠，凄成風雨未秋寒。", "渭川昔漫誇千畝，錦里今須種數竿。", "移取辟疆園畔去，免教童子報平安。"]'),
('02902945-4f57-4f9d-b6bc-53de24c21a58','次韻向君受感秋二首  其一','汪藻','宋','宋诗','song-poetry','','[]','且欲相隨苜蓿盤，不須多問沐猴冠。',64,'全唐诗/poet.song.83000.json','["且欲相隨苜蓿盤，不須多問沐猴冠。", "菊花有意浮杯酒，桐葉無聲下井欄。", "千里江山漁笛晚，十年燈火客氈寒。", "男兒幾許功名事，華髪催人不少寛。"]'),
('c5400c60-fb56-46fe-a991-3e7086a4e1ba','次韻向君受感秋二首  其二','汪藻','宋','宋诗','song-poetry','','[]','向侯拄笏意千里，肯爲俗彈頭上冠。',64,'全唐诗/poet.song.83000.json','["向侯拄笏意千里，肯爲俗彈頭上冠。", "何時盛之青瑣闥，妙語付以烏絲欄。", "日邊人去鴈行斷，江上秋高楓葉寒。", "向來叔度儻公是，一見使我窮愁寛。"]'),
('fd83610e-1cc8-4c93-92f3-deb429f7b4bb','次韻熊使君登樓感秋之作','汪藻','宋','宋诗','song-poetry','','[]','隨儂何物四經秋，只有江南萬斛愁。',64,'全唐诗/poet.song.83000.json','["隨儂何物四經秋，只有江南萬斛愁。", "客枕蛩親聞最早，郷書鴈少到無由。", "菊叢今歲還經眼，茅把何時得蓋頭。", "工部也應兒女隔，羨他相近水中鷗。"]'),
('beab83a4-79bd-4ab8-a4c5-0553a253a57e','小築成漫書','汪藻','宋','宋诗','song-poetry','','[]','旅營茅屋破蒼苔，隔水花多不用栽。',64,'全唐诗/poet.song.83000.json','["旅營茅屋破蒼苔，隔水花多不用栽。", "開卷古今千萬事，杜門清濁兩三杯。", "故人昔尚風相及，客子今并雨不來。", "已辦此身如木石，沙禽那得更驚猜。"]'),
('e93e0e09-b9bc-43e1-8258-2dafc3a665ea','用友人韻寄平江蔣侍郎','汪藻','宋','宋诗','song-poetry','','[]','詞源衮衮患材多，筆力駸駸跨永和。',64,'全唐诗/poet.song.83000.json','["詞源衮衮患材多，筆力駸駸跨永和。", "屢閲州符猶剖竹，盍歸禁槖舊持荷。", "聲華大似城南杜，勲業看如相國何。", "自笑萍蹤久爲客，那能綺麗盡餘波。"]'),
('1ce78f6b-42ec-4662-bcc2-2fb4a456c44d','書寧川驛壁','汪藻','宋','宋诗','song-poetry','','[]','過眼空花一晌休，坐狂猶得佐名州。',64,'全唐诗/poet.song.83000.json','["過眼空花一晌休，坐狂猶得佐名州。", "雖遭瀧吏嗤韓子，却喜溪神識柳侯。", "盡日野田行䆉稏，有時雲嶠聽鉤輈。", "會將新濯滄浪足，踏遍千巖萬壑秋。"]'),
('d1f4390a-fb43-45f8-bc8e-9fd77967e7c5','余去年寄前詩今再過其地而彦征已卒用前韻書驛壁','汪藻','宋','宋诗','song-poetry','','[]','年少豈知身世浮，心期同老故山秋。',64,'全唐诗/poet.song.83000.json','["年少豈知身世浮，心期同老故山秋。", "誰教玉樹埋黄壤，不許鴒原到白頭。", "鼎鼎百年皆夢幻，悠悠萬事判窮愁。", "當時鴻鴈書來處，今日飄然成獨游。"]'),
('dfe5d283-7b2d-431b-8e5a-73711c58b196','惱張子充','汪藻','宋','宋诗','song-poetry','','[]','他州異縣復芳時，彊起尋梅把一枝。',64,'全唐诗/poet.song.83000.json','["他州異縣復芳時，彊起尋梅把一枝。", "濁酒縱能于道近，蒼髯終不與春宜。", "逢人欲作娵隅語，去國長爲僂句欺。", "斟酒旅情誰會得，徑須京兆出蛾眉。"]'),
('8cc9ced1-4d81-4362-981d-2bf9ccdd7323','横山堂二首  其一','汪藻','宋','宋诗','song-poetry','','[]','早冠清朝玉筍班，忽乘歸興拂衣閑。',64,'全唐诗/poet.song.83000.json','["早冠清朝玉筍班，忽乘歸興拂衣閑。", "聊將詩酒關心地，盡占江湖在眼山。", "人坐數州空翠下，月行萬頃水雲間。", "當時范蠡曾知此，那得扁舟去不還。"]'),
('62cd3a9b-3838-40fb-bfdf-7fad1d0e711f','横山堂二首  其二','汪藻','宋','宋诗','song-poetry','','[]','分明圓嶠與方壺，萬壑千巖入坐隅。',64,'全唐诗/poet.song.83000.json','["分明圓嶠與方壺，萬壑千巖入坐隅。", "臨賦競傳今日句，卧遊安用昔人圖。", "丹青霜葉秋明滅，水墨烟林暮有無。", "記取滄浪漁笛曲，他年要捋使君鬚。"]'),
('bf38c227-a71b-464d-8155-e07616dabaf8','靈惠公廟','汪藻','宋','宋诗','song-poetry','','[]','臺殿崇崇冠冢顛，行人跪起白雲邊。',64,'全唐诗/poet.song.83000.json','["臺殿崇崇冠冢顛，行人跪起白雲邊。", "山河霸業三千里，歌舞靈衣五百年。", "鐵馬威神通異域，衮龍書命降中天。", "偃王遺種班班在，好乞韓碑記邈緜。"]'),
('8b725f21-7669-4382-a034-760ccc72c161','醉别劉季高侍郎','汪藻','宋','宋诗','song-poetry','','[]','疇昔追隨翰墨場，功名今日愧劉郎。',64,'全唐诗/poet.song.83000.json','["疇昔追隨翰墨場，功名今日愧劉郎。", "英姿合上凌烟閣，巧譖曾遭偃月堂。", "雙槳又乘清夜去，一尊聊發少年狂。", "歸來卻共燈花語，騎省看成滿鏡霜。"]'),
('d7368b3e-20da-4619-8c07-2552fd154f79','移守臨川曾吉甫以詩見寄次韻答之時吉甫除閩漕未行','汪藻','宋','宋诗','song-poetry','','[]','朝來剝啄叩門誰，昨夜燈花已報知。',64,'全唐诗/poet.song.83000.json','["朝來剝啄叩門誰，昨夜燈花已報知。", "腰下方懸新守印，眼中已見故人詩。", "十年且喜朋簪合，千里休言官牒隨。", "問我抽書何日竟，病來編簡網蛛絲。"]'),
('dff34eb4-a193-4d77-8a95-39e89394c970','送杜文仲微赴山陽倅','汪藻','宋','宋诗','song-poetry','','[]','城外長淮綠渺瀰，此行聊復鴈門踦。',64,'全唐诗/poet.song.83000.json','["城外長淮綠渺瀰，此行聊復鴈門踦。", "邊烽已息何妨醉，民訟全稀尚可詩。", "昭代聲名方此振，中年離别未須悲。", "溧陽老尉還天幸，政自扳援得退之。"]'),
('88799309-74ee-4ad3-908c-35f454131e3d','奉送張彦良司理','汪藻','宋','宋诗','song-poetry','','[]','病來誰復顧湘纍，君獨無忘宿昔時。',64,'全唐诗/poet.song.83000.json','["病來誰復顧湘纍，君獨無忘宿昔時。", "人物喜逢三語掾，風騷遠過四愁詩。", "尊前破涕方成笑，人事多乖又語離。", "莫道天涯無鴈到，好風寧不寄相思。"]'),
('e6bc59fb-0a12-41e5-b04f-dd0d0f8da83a','重送惟皓','汪藻','宋','宋诗','song-poetry','','[]','那知重到舊溪邊，兩月青燈聽雨眠。',64,'全唐诗/poet.song.83000.json','["那知重到舊溪邊，兩月青燈聽雨眠。", "閑引瘦筇行落葉，復尋清磬度疏烟。", "宦遊南北夢千里，人世短長癡百年。", "安得隨君飛鳥去，盤陀相對共安禪。"]'),
('fc0604a8-f621-41d9-b926-5f9c1a71afc4','喜汪發之見訪并簡婺源江明府','汪藻','宋','宋诗','song-poetry','','[]','怪底青燈綴玉蟲，忽傳車馬到溪東。',64,'全唐诗/poet.song.83000.json','["怪底青燈綴玉蟲，忽傳車馬到溪東。", "鳥聲應爲故人好，梨雪欲將春事空。", "老去淵明三逕在，病來彌勒一龕同。", "總持相見問生死，爲報百憂如夢中。"]'),
('010bf732-5bea-42cf-8616-7101b8db0e13','約教授遊東林寺','汪藻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','擾擾塵勞懶曳裾，此生終待老匡廬。',64,'全唐诗/poet.song.83000.json','["擾擾塵勞懶曳裾，此生終待老匡廬。", "兩山分破吟難盡，一水飛來畫不如。", "紅杏成壇今彷彿，白蓮結社漫躊躇。", "泮宫夫子能敦約，共採新聞廣舊書。"]'),
('f14c3b2c-10da-4b16-b6c3-1f5aa8b86f48','熊使君次韻見屬次韻答之','汪藻','宋','宋诗','song-poetry','','[]','蠻縣三年喜及瓜，歸歟春思自無涯。',64,'全唐诗/poet.song.83000.json','["蠻縣三年喜及瓜，歸歟春思自無涯。", "朝陽巖上無殘雪，慶朔堂前已亂花。", "歸到兒曹應借問，爲言顛髪未全華。", "仲宣正得依投處，萬里心安即是家。"]'),
('273b4dc5-ba7c-47fc-8653-31ae39d7163f','寄呈壽基致政左司二首  其一','汪藻','宋','宋诗','song-poetry','','[]','年來何事憶蓴鱸，家近秋風萬頃湖。',64,'全唐诗/poet.song.83000.json','["年來何事憶蓴鱸，家近秋風萬頃湖。", "五馬曾同當日渡，二疏今見古人圖。", "山靈尚勒移文否，田父時遭泥飲無。", "餘論不妨傳四海，君家世世有潛夫。"]'),
('c6721c78-eb2a-457f-8e40-8469e3d1d81f','寄呈壽基致政左司二首  其二','汪藻','宋','宋诗','song-poetry','','[]','拂衣歸憩舊烟蘿，鐘鼎山林竟孰多。',64,'全唐诗/poet.song.83000.json','["拂衣歸憩舊烟蘿，鐘鼎山林竟孰多。", "眼看空花皆是幻，心同古井肯重波。", "清談三尺竹如意，宴坐一枝松養和。", "我亦行抛簪笏去，從君春日曬漁蓑。"]'),
('9c8d02a9-71fe-4d58-a69e-7ade17041117','戲孫仲益暮春自尚書郎予告迎婦淛東留毗陵久之','汪藻','宋','宋诗','song-poetry','','[]','尊酒相逢禊飲初，花飛柳暗忽春餘。',64,'全唐诗/poet.song.83000.json','["尊酒相逢禊飲初，花飛柳暗忽春餘。", "不嗔太史牛馬走，許醉郎官櫻笋廚。", "幸有雪兒歌妙句，何妨雲液載行車。", "只愁人誤刀頭約，新月娟娟已鏡如。"]'),
('7164161f-0969-4164-837d-95a1e43a07e5','次韻張閎道西池小集','汪藻','宋','宋诗','song-poetry','','[]','眼中烟水復雲林，地勝身閑得細尋。',64,'全唐诗/poet.song.83000.json','["眼中烟水復雲林，地勝身閑得細尋。", "沙暖鳧鷗渾得意，日長桃李自成陰。", "風光欲盡今餘幾，杯酒相逢莫厭深。", "報答春江無好語，浪陪諸彦恣窺臨。"]'),
('bbe7f4ab-909f-4691-b8b4-834b83f14cf0','次韻吳子書天寧夜集','汪藻','宋','宋诗','song-poetry','','[]','萬卷長年坐一窗，肯論丘壑與巖廊。',64,'全唐诗/poet.song.83000.json','["萬卷長年坐一窗，肯論丘壑與巖廊。", "江頭同過楝花節，夜半劇談獅子牀。", "異世風流相延祖，他年言語傅君房。", "菰蒲渺渺但烟雨，何意眼中逢此郎。"]'),
('8d4eec81-b892-4e92-9d5b-ab8bdb77233a','同辯良至薦福塔頭','汪藻','宋','宋诗','song-poetry','','[]','曉尋幽處一牛鳴，空霧依迷失化城。',64,'全唐诗/poet.song.83000.json','["曉尋幽處一牛鳴，空霧依迷失化城。", "茗椀薰爐重問訊，竹溪松塢共經行。", "雲昏洲渚雨還作，風入菰蒲潮欲生。", "此地相逢復相别，江天病眼向誰明。"]'),
('724dfb8d-a894-490b-b685-993a7794b907','翁養源因先冢瑞松作亭求詩','汪藻','宋','宋诗','song-poetry','','[]','樛枝偃蓋蔚相扶，絕勝分封五大夫。',64,'全唐诗/poet.song.83000.json','["樛枝偃蓋蔚相扶，絕勝分封五大夫。", "天遣歲寒雙幹合，人言江左百城無。", "聞孫爲表祠叢勝，好事爭傳宰樹圖。", "肯學并柯桃與李，四時佳色照黄壚。"]'),
('733f7dd3-dbb7-4831-ae01-0ada7b907722','過寧國小嶺','汪藻','宋','宋诗','song-poetry','','[]','步歷崔嵬數百尋，垂堂漫許戒千金。',64,'全唐诗/poet.song.83000.json','["步歷崔嵬數百尋，垂堂漫許戒千金。", "年來世事總如夢，老去兒曹長掛心。", "聽雨不眠那夜永，行山未遍忽秋深。", "天寒更度宛陵水，霜月欲生風滿林。"]'),
('dddb55e1-b9e1-46f2-b6e2-243349e1e9f8','東安許明府同里之親任滿回家求詩爲别即席賦此兼簡熊使君','汪藻','宋','宋诗','song-poetry','','[]','三載相依葛與瓜，一尊爲别忽天涯。',64,'全唐诗/poet.song.83000.json','["三載相依葛與瓜，一尊爲别忽天涯。", "君先歸路經回鴈，我正幽棲似浣花。", "好去乘時追俊彦，莫嗔無力薦才華。", "城中若見漁樵客，須問浮溪老圃家。"]'),
('850d9cb2-7bd6-4ef6-80d6-6365e8a96a2b','汴中偶題','汪藻','宋','宋诗','song-poetry','','[]','蜻蜓斜日立簾鉤，燕子新晴語柁樓。',64,'全唐诗/poet.song.83000.json','["蜻蜓斜日立簾鉤，燕子新晴語柁樓。", "熠熠晚花隨意得，茫茫春水此生浮。", "無官可緩三人带，有子能勝十具牛。", "老大拂衣歸去好，蓴鱸何必待清秋。"]'),
('807ab377-9d67-430a-9d13-6d73e9bcc2e2','過金陵','汪藻','宋','宋诗','song-poetry','','[]','六代興亡迹愈陳，迹陳誰遣意如新。',64,'全唐诗/poet.song.83000.json','["六代興亡迹愈陳，迹陳誰遣意如新。", "古今更欲悲何事，天地長留景似人。", "雲壓山低惟妬晚，霧蟠江闊更含春。", "固知到此無窮感，豈獨區區我一身。"]'),
('dcf63308-db9c-4ebf-a94e-a79ad4d9af15','傅沖益久不得書','汪藻','宋','宋诗','song-poetry','','[]','經年坐久一蒲團，幽鳥時呼到曲欄。',64,'全唐诗/poet.song.83000.json','["經年坐久一蒲團，幽鳥時呼到曲欄。", "山色總兼溪色好，松聲長學雨聲寒。", "那將俗物關心事，只擬晴窗想鼻端。", "已作生涯蠶事老，故人誰肯報平安。"]'),
('be58f42e-64ac-4145-b149-5d0b3062183a','次韻孫國器喜予鈔書精密','汪藻','宋','宋诗','song-poetry','','[]','天教江海著潛郎，擬作他年柱下藏。',64,'全唐诗/poet.song.83000.json','["天教江海著潛郎，擬作他年柱下藏。", "未辦壁書摹古漆，聊將閣本寫官黄。", "苦心便擬耽成癖，病眼猶堪細作行。", "秖恐雌霓成誤讀，更須頻訪沈東陽。"]'),
('95e76e75-b30d-4404-9b96-5fbb846d81b7','還吳禹功徐帖','汪藻','宋','宋诗','song-poetry','','[]','誰專小學國朝初，籍籍甘泉數二徐。',64,'全唐诗/poet.song.83000.json','["誰專小學國朝初，籍籍甘泉數二徐。", "輩行雖居騎曹後，典刑全是嶧山餘。", "柳家莫笑薑芽手，鄭老方耽柿葉書。", "待得門前溪水黑，憑看合作定何如。"]'),
('83a84b07-41b5-4cf5-a192-7f45d7403b98','朱新仲自韶州寄靈壽杖并詩次韻答之','汪藻','宋','宋诗','song-poetry','','[]','苔漬嵐侵幾百秋，詩仙寄我海南州。',64,'全唐诗/poet.song.83000.json','["苔漬嵐侵幾百秋，詩仙寄我海南州。", "攜來應自滇池國，得處還因博望侯。", "吹燭會尋延閣老，掛錢肯學飲家流。", "杖兮莫便爲龍去，扶取衰翁老故丘。"]'),
('97840e36-66fa-4028-af86-0231bc7e9464','題四望亭','汪藻','宋','宋诗','song-poetry','','[]','累棟層軒縹緲間，碧虚相照水精寒。',64,'全唐诗/poet.song.83000.json','["累棟層軒縹緲間，碧虚相照水精寒。", "縱横盡得江山勝，俯仰方知宇宙寛。", "千里風烟環廣座，四時星斗轉危欄。", "何須更畫東平障，十萬人家表裏看。"]'),
('9a38dde9-4641-40e9-9054-e0810d6d7ab2','簡蔡天任','汪藻','宋','宋诗','song-poetry','','[]','寂寂閑庭少客過，翛然丈室一維摩。',64,'全唐诗/poet.song.83000.json','["寂寂閑庭少客過，翛然丈室一維摩。", "腦脂遮眼空豪在，藥裹關心奈老何。", "雨後書連修竹翠，夜深牀繞候蟲歌。", "東鄰似最知人意，合有新詩到薜蘿。"]'),
('75aa9263-3d9e-4f59-9e00-033e3367d007','熊使君次韻','汪藻','宋','宋诗','song-poetry','','[]','萬石亭西半是苔，舊時官柳著行栽。',64,'全唐诗/poet.song.83000.json','["萬石亭西半是苔，舊時官柳著行栽。", "使君爲築溪邊屋，野老同傾月下杯。", "好在一廛從此記，休論三徑有誰來。", "會須便作漁梁去，莫遣鸕鷀忽見猜。"]'),
('4914ac2b-5277-4af3-b3af-b9fd56d48b6c','和家叔春日','汪藻','宋','宋诗','song-poetry','','[]','曉看春水滿方塘，靜掩柴扉白日長。',64,'全唐诗/poet.song.83000.json','["曉看春水滿方塘，靜掩柴扉白日長。", "花意風光空爛漫，客愁山色對蒼茫。", "揚州歌吹今何在，陶令田園亦就荒。", "試問南來米貴賤，欲隨春浪過瀟湘。"]'),
('87818477-c37c-4037-83d3-122f9adfd571','挽留二兄','汪藻','宋','宋诗','song-poetry','','[]','聞挈囊衣指故林，上堂長跪涕沾襟。',64,'全唐诗/poet.song.83000.json','["聞挈囊衣指故林，上堂長跪涕沾襟。", "肯將斷鴈相望影，來慰驚波未定心。", "客路山川方積雪，吾廬桃李久成陰。", "歸鞍底用匆匆發，更促杯盤語夜深。"]'),
('a99869c9-8cee-422d-baf2-3f35cd86dc75','嘲人買妾而病二首  其一','汪藻','宋','宋诗','song-poetry','','[]','但知瓊樹鬭清新，不道三彭捷有神。',64,'全唐诗/poet.song.83000.json','["但知瓊樹鬭清新，不道三彭捷有神。", "處仲未聞開閣事，維摩空對問禪人。", "封侯燕頷何妨瘦，伐性蛾眉卻怕顰。", "從此空花掃除盡，定須嚼蠟向横陳。"]'),
('2b533b32-4765-467c-82c1-c5a544f83220','嘲人買妾而病二首  其二','汪藻','宋','宋诗','song-poetry','','[]','何須天氣水邊新，便好尊前賦洛神。',64,'全唐诗/poet.song.83000.json','["何須天氣水邊新，便好尊前賦洛神。", "定自中年多作惡，非關尤物解移人。", "莫愁阿鶩煩君嫁，且學西施爲我顰。", "爭似農家無一事，從來婚嫁只朱陳。"]'),
('b3a85bd1-2f1b-4674-8db4-f22231c90d8e','德劭親迎而歸乃有打包辟穀之興以詩見貽戲用其韻','汪藻','宋','宋诗','song-poetry','','[]','解事無人似樂天，玉簪舊語世相傳。',64,'全唐诗/poet.song.83000.json','["解事無人似樂天，玉簪舊語世相傳。", "打包就使從前話，彈指安能斷後緣。", "寂寂空房惟法喜，茫茫何處問臞仙。", "冬之夜永宜長慮，百計真從若箇邊。"]'),
('8916e836-92ad-4215-9b05-940fc2ee1616','詠菊','汪藻','宋','宋诗','song-poetry','','[]','依倚西風不自持，葳蕤羽葆雜金規。',64,'全唐诗/poet.song.83000.json','["依倚西風不自持，葳蕤羽葆雜金規。", "繁開不負朝陽色，獨步非關昊帝私。", "把酒可能追靖節，掇苗終欲慕天隨。", "春紅過盡聊經眼，賴有芬菲慰所思。"]'),
('4a4600f4-0a41-4e0f-b37c-3139e6bf383e','題止戈堂二首  其一','汪藻','宋','宋诗','song-poetry','','[]','此老胸中百萬軍，暫勞試手犬羊羣。',64,'全唐诗/poet.song.83000.json','["此老胸中百萬軍，暫勞試手犬羊羣。", "山頭不復望廷尉，柱後何須用惠文。", "解带爲城聊戲劇，賣刀買犢便耕耘。", "三山勝處開華屋，千載人傳舊使君。"]'),
('03c80abf-b9a5-4445-8650-82304ea8dd18','題止戈堂二首  其二','汪藻','宋','宋诗','song-poetry','','[]','千里閩山驛騎飛，天書趣解海邊圍。',64,'全唐诗/poet.song.83000.json','["千里閩山驛騎飛，天書趣解海邊圍。", "異軍方逐蒼頭起，元帥徐將白羽揮。", "翻就鐃歌春舉酒，收還烽火夜開扉。", "向來萬事關兵氣，却作風光坐上歸。"]'),
('e52e9388-5445-4857-81b4-5adb5be149b9','郊丘書事','汪藻','宋','宋诗','song-poetry','','[]','琅輿深出未央門，十里圜壇氣象尊。',64,'全唐诗/poet.song.83000.json','["琅輿深出未央門，十里圜壇氣象尊。", "珪璧三千周典備，貔貅百萬漢兵屯。", "青城浮靄連霜動，黄道微風带日温。", "不用靈光符聖武，從來精祲答乾坤。"]'),
('66ac615c-a07c-41a8-8ef4-e350a413f8a8','題至樂堂','汪藻','宋','宋诗','song-poetry','','[]','倚空危榭壓城樓，千里風烟攝寸眸。',64,'全唐诗/poet.song.83000.json','["倚空危榭壓城樓，千里風烟攝寸眸。", "二華忽從天外落，三河直入坐中流。", "何人解得爲邦樂，有客難甘去國愁。", "投老復來江漢外，此生歸計日悠悠。"]'),
('7e6bff3a-73c6-43f5-9dbe-1bb4567b6f76','題僧罄宜枝巢','汪藻','宋','宋诗','song-poetry','','[]','平生到處覓三椽，白首歸來古刹顛。',64,'全唐诗/poet.song.83000.json','["平生到處覓三椽，白首歸來古刹顛。", "飛錫幾逢花雨地，住山今得鳥窠禪。", "九霄鵬翼心雖在，萬壑松風夢自圓。", "莫笑維摩方丈室，會看游戲著人天。"]'),
('2d51299a-0398-43bd-8fad-6fbcba39d800','禪月羅漢','汪藻','宋','宋诗','song-poetry','','[]','扃鎖收傳古聖師，飛揚不類虎頭癡。',64,'全唐诗/poet.song.83000.json','["扃鎖收傳古聖師，飛揚不類虎頭癡。", "槎枒老木垂雲蔓，傴僂胡僧拖雪眉。", "丹墨已隨嵐靄盡，精神猶作電光馳。", "秖應夢乞歸巖寺，要使邦人習氣移。"]'),
('57f16a4b-97f4-468e-9fdd-18be76dec328','送僧還山','汪藻','宋','宋诗','song-poetry','','[]','傳得清凉祖佛衣，來新震澤舊禪扉。',64,'全唐诗/poet.song.83000.json','["傳得清凉祖佛衣，來新震澤舊禪扉。", "幾年香木成林種，一日孤雲带雨歸。", "别路片帆方蕩漾，名山八部已光輝。", "夜窗時得伽陀句，會寄江城秋鴈飛。"]'),
('ed645478-5ee8-40c5-aada-a4af270f15fb','送廷藻兼呈楚州通守杜丈','汪藻','宋','宋诗','song-poetry','','[]','相從常恨十年遲，握手匆匆每自疑。',64,'全唐诗/poet.song.83000.json','["相從常恨十年遲，握手匆匆每自疑。", "風艇烟帆還此日，隙烟籬井定何時。", "試看子學猶難售，須信吾窮未易醫。", "千里同風杜夫子，可能時寄彈丸詩。"]');
